#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The reversed permutation always has the same fingerprint.
    // We need to ensure it's a different permutation.
    // A permutation p is different from its reverse p_rev if p is not a palindrome.
    // The problem guarantees a solution exists.
    // For n >= 2, if p is a palindrome, then p_i = p_{n-i+1}.
    // For example, if n=2, p=[1,2], p_rev=[2,1]. These are different.
    // If n=3, p=[1,2,3], p_rev=[3,2,1]. These are different.
    // If n=4, p=[1,2,3,4], p_rev=[4,3,2,1]. These are different.
    // It's impossible for a permutation of distinct numbers from 1 to n to be a palindrome
    // unless n=1 (which is not allowed, n>=2) or it's a very specific case.
    // For example, if p_1 = p_n, but p_1 and p_n must be distinct if n > 1.
    // Wait, p_i = p_{n-i+1} means p_1 = p_n, p_2 = p_{n-1}, etc.
    // Since all elements in a permutation are distinct, this can only happen if n=1.
    // For n >= 2, p_1 must be different from p_n.
    // Thus, p cannot be equal to its reverse p_rev.
    // So, reversing the permutation always yields a different permutation with the same fingerprint.

    for (int i = n - 1; i >= 0; --i) {
        std::cout << p[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;
}

