int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        long long diff = std::abs(a - b);

        long long ans = 0;

        // Greedy approach for denominations {1, 2, 5}
        // This works because 5 is not too large compared to 1 and 2,
        // and 2 is not too large compared to 1.
        // Specifically, 5 < 2*2 + 1, and 2 < 2*1.
        // For {1, 2, 5}, a greedy approach (take as many 5s, then 2s, then 1s) is optimal.

        ans += diff / 5;
        diff %= 5;

        ans += diff / 2;
        diff %= 2;

        ans += diff; // remaining diff must be 0 or 1

        std::cout << ans << std::endl;
    }
    return 0;
}

