void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) { // Only consider numbers up to 2048
            counts[s_val]++;
        }
    }

    long long current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the total value contributed by this power of two
        // We only care about the sum up to 2048.
        // If we have 2^k, and we have 'count' of them, they contribute count * 2^k to the total sum.
        // This sum can then be combined to form larger powers of two.
        // For example, if we have two 512s, they form one 1024.
        // If we have four 512s, they form two 1024s, which form one 2048.
        // The total value is what matters.
        current_sum += (long long)val * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

