void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << std::endl;
    } else {
        // For n >= 2, we can construct a number.
        // A number starting with '2' and followed by '3's for n-1 digits
        // will not be divisible by 2 (since it's odd if n-1 is odd, or ends in 3).
        // It will not be divisible by 3 (sum of digits is 2 + 3*(n-1) = 3n-1, not divisible by 3).
        // This strategy works for n >= 2.
        // Example: n=2 -> 23. 23%2=1, 23%3=2.
        // Example: n=3 -> 233. 233%2=1, 233%3=2.
        // Example: n=4 -> 2333. 2333%2=1, 2333%3=2.
        // The problem statement's example for n=2 is 57, for n=3 is 239, for n=4 is 6789.
        // My construction is simpler and also valid.
        // Let's use '2' followed by '3's.
        // The only edge case is if n=1, which is handled.
        // For n=2, 23.
        // For n=3, 233.
        // For n=4, 2333.
        // This construction is always valid for n >= 2.
        // The first digit is '2'.
        // The remaining n-1 digits are '3'.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << std::endl;
    }
}

