#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long l, r;
    std::cin >> l >> r;

    if (l == r) {
        std::cout << l << std::endl;
    } else {
        // The number 2 is a divisor of all even numbers.
        // In any range [l, r] where r > l, there will be at least one even number
        // if r - l + 1 >= 2.
        // If r - l + 1 = 1, then l = r, which is handled above.
        // So, if r > l, there are at least two numbers.
        // If l is even, then l, l+2, ... are even.
        // If l is odd, then l+1, l+3, ... are even.
        // In any range of length 2 or more, there is at least one even number.
        // The count of multiples of 2 is floor(r/2) - floor((l-1)/2).
        // The count of multiples of any k > 2 is floor(r/k) - floor((l-1)/k).
        // For k > 2, floor(r/k) <= floor(r/2) and floor((l-1)/k) >= floor((l-1)/2)
        // (or at least, the difference for k will be less than or equal to the difference for 2).
        // Specifically, for k >= 3, the count of multiples of k will be less than or equal to
        // the count of multiples of 2.
        // Example: [3, 6]
        // Multiples of 2: {4, 6} -> count = 2
        // Multiples of 3: {3, 6} -> count = 2
        // Multiples of 4: {4} -> count = 1
        // Multiples of 5: {5} -> count = 1
        // Multiples of 6: {6} -> count = 1
        // In this case, 2 and 3 both appear 2 times. Any is fine.
        // The problem asks for *any* integer that appears the maximum number of times.
        // Since 2 is the smallest prime and thus has the highest density of multiples,
        // it's a very strong candidate.
        // If l and r are both odd, and r = l + 1, e.g., [3, 4].
        // Divisors (excluding 1):
        // 3: {3}
        // 4: {2, 4}
        // Count for 2: 1 (from 4)
        // Count for 3: 1 (from 3)
        // Count for 4: 1 (from 4)
        // Here, 2, 3, 4 all appear once. Any is fine.
        //
        // The only case where 2 might not be the answer is if the range is very small
        // and contains only odd numbers, but this is covered by l=r.
        // If l=3, r=3, output 3.
        // If l=5, r=5, output 5.
        // If l=7, r=7, output 7.
        //
        // If l=3, r=4:
        // 3: {3}
        // 4: {2, 4}
        // Max count is 1. 2, 3, 4 are all valid answers.
        //
        // If l=19, r=29:
        // Multiples of 2: {20, 22, 24, 26, 28} -> count = 5
        // Multiples of 3: {21, 24, 27} -> count = 3
        // Multiples of 4: {20, 24, 28} -> count = 3
        // Multiples of 5: {20, 25} -> count = 2
        // ...
        // 2 is clearly the winner here.
        //
        // The number 2 will always be a valid answer if r > l.
        // This is because for any k > 2, the number of multiples of k in [l, r]
        // will be less than or equal to the number of multiples of 2.
        // The count of multiples of k is floor(r/k) - floor((l-1)/k).
        // For k=2, count = floor(r/2) - floor((l-1)/2).
        // For k=3, count = floor(r/3) - floor((l-1)/3).
        // Since floor(x/k) <= floor(x/2) for k >= 2, and floor((x-1)/k) <= floor((x-1)/2),
        // the difference for k will be less than or equal to the difference for 2.
        // The only exception is if l=r, where the only divisor is l itself.
        // But if l != r, then 2 is always a valid answer.
        std::cout << 2 << std::endl;
    }

    return 0;
}

