            color_for_half = 1 - color_for_half; // Alternate color for elements equal to T/2
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

