#include <iostream>
#include <vector>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 0) {
        std::cout << 0 << std::endl;
        return;
    }

    int bad_prices_count = 0;
    int min_suffix_price = a[n - 1]; // Initialize with the last price

    // Iterate from right to left (from n-2 down to 0)
    // The last price a[n-1] can never be bad because there are no prices after it.
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix_price) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix_price,
            // it means a[i] is less than or equal to the minimum price found so far
            // in the suffix a[i+1...n-1].
            // So, a[i] becomes the new minimum for the suffix a[i...n-1].
            min_suffix_price = a[i];
        }
    }
    std::cout << bad_prices_count << std::endl;
}

