int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_R_pos = -1; // Represents cell 0

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // Current cell is i+1 (1-indexed)
                // The previous 'R' was at last_R_pos (0-indexed)
                // The gap is between last_R_pos and i+1
                // If last_R_pos is -1, it means the gap is from cell 0 to cell i+1
                max_gap = std::max(max_gap, (i + 1) - (last_R_pos + 1) + 1);
                last_R_pos = i;
            }
        }

        // After iterating through the string, consider the gap from the last 'R' to n+1
        // If last_R_pos is -1, it means there were no 'R's in the string.
        // In this case, the frog must jump from 0 to n+1 directly.
        // The gap is from cell 0 to cell n+1.
        // (n+1) - (0) + 1 = n+2
        max_gap = std::max(max_gap, (n + 1) - (last_R_pos + 1) + 1);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_for_i = 0;
        for (int j = 0; j < n; ++j) {
            int a_ij;
            std::cin >> a_ij;
            if (i != j) {
                max_val_for_i = std::max(max_val_for_i, a_ij);
            }
        }
        p[i] = max_val_for_i;
    }

    // Check if any p[i] is 0. If so, it means all a[i][j] for j!=i were 0.
    // This implies p[i] must be 1 (the smallest possible value in a permutation).
    // This happens if n=1, but problem constraints say n >= 2.
    // If n >= 2, and p[i] is 0, it means all other p[j] are 0, which is impossible
    // as p is a permutation of 1 to n.
    // The only case where max_val_for_i could be 0 is if n=1, but n>=2.
    // For n>=2, if max_val_for_i is 0, it means p[i] must be 1.
    // This logic is slightly off. If max_val_for_i is 0, it means for all j!=i, min(p[i], p[j]) = 0.
    // This is impossible for a permutation of 1 to n.
    // The problem statement guarantees a solution exists.
    // The only way max_val_for_i could be 0 is if n=1, but n>=2.
    // For n>=2, the smallest possible value for max_val_for_i is 1.
    // If max_val_for_i is 0, it means p[i] must be 1.
    // This is a special case for when p[i] is the smallest element (1).
    // If p[i] = 1, then for any j != i, a[i][j] = min(1, p[j]) = 1.
    // So, max_{j!=i} a[i][j] would be 1.
    // The only way max_val_for_i could be 0 is if n=1, which is not allowed.
    // So, max_val_for_i will always be at least 1.

    // The logic for p[i] = max_val_for_i is correct for all p[i] > 1.
    // If p[i] = 1, then max_val_for_i will be 1.
    // So, p[i] = max_val_for_i works for all p[i] >= 1.

    // However, there's a special case: if all p[i] are distinct and cover 1 to n,
    // then one of them must be n.
    // The element p_k that corresponds to n will have max_{j!=k} a_{k,j} = n-1.
    // This is because for all j!=k, a_{k,j} = min(n, p_j) = p_j.
    // So max_{j!=k} a_{k,j} = max_{j!=k} p_j = n-1.
    // So, if we simply set p[i] = max_val_for_i, the element that should be n will be n-1.
    // All other elements will be correctly identified.
    // This means one element will be n-1, and all other elements will be correct.
    // The set of values {p[0], ..., p[n-1]} will be {1, 2, ..., n-1, n-1}.
    // To fix this, we find the maximum value in our reconstructed p.
    // If this maximum value is n-1, it means the true maximum value n was mapped to n-1.
    // We need to change this n-1 to n.

    int max_in_p = 0;
    for (int val : p) {
        max_in_p = std::max(max_in_p, val);
    }

    if (max_in_p < n) { // This means the true 'n' was mapped to 'n-1'
        for (int i = 0; i < n; ++i) {
            if (p[i] == max_in_p) {
                p[i] = n;
                break; // Only one such element needs to be changed
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

