#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i] < a[i+1]
    // This `i` is the end of the non-increasing suffix.
    // Example: [4, 3, 3, 8, 4, 5, 2]
    // n-1 = 6, a[6]=2
    // n-2 = 5, a[5]=5. a[5] > a[6] (5 > 2). i=5.
    // n-3 = 4, a[4]=4. a[4] < a[5] (4 < 5). This is the first break.
    // So the suffix [4, 5, 2] starts at index 4.
    // The non-increasing suffix is [5, 2] starting at index 5.
    // The first element of the non-increasing suffix is a[i+1].
    // The index of the first element of the non-increasing suffix is `i_suffix_start`.
    // `i_suffix_start` is `i+1` from the loop below.
    int i_suffix_start = n - 1;
    while (i_suffix_start > 0 && a[i_suffix_start - 1] >= a[i_suffix_start]) {
        i_suffix_start--;
    }
    // After this loop, a[i_suffix_start ... n-1] is non-increasing.
    // If i_suffix_start is 0, the whole array is non-increasing.

    // Now, find the rightmost index `j` such that a[j] > a[j+1]
    // This `j` is the end of the non-decreasing suffix.
    // Example: [4, 3, 3, 8, 4, 5, 2]
    // i_suffix_start = 5. Suffix is [5, 2].
    // Now we look for the non-decreasing part before this.
    // j = i_suffix_start - 1 = 4. a[4]=4.
    // j-1 = 3. a[3]=8. a[3] > a[4] (8 > 4). This is the first break.
    // So the non-decreasing suffix starts at index 4.
    // The index of the first element of the non-decreasing suffix is `j_suffix_start`.
    // `j_suffix_start` is `j+1` from the loop below.
    int j_suffix_start = i_suffix_start;
    while (j_suffix_start > 0 && a[j_suffix_start - 1] <= a[j_suffix_start]) {
        j_suffix_start--;
    }
    // After this loop, a[j_suffix_start ... n-1] is non-decreasing.
    // If j_suffix_start is 0, the whole array is non-decreasing.

    std::cout << j_suffix_start << std::endl;
}

