// Function to check if Box 1 can be the special box
// Box 1: (-inf, -1] (Negative, magnitude >= 1)
bool can_be_box1(long long A, long long B, long long C, long long D) {
    // To end up in Box 1, the final toy must be negative and have magnitude >= 1.
    // This means the total number of negative factors must be odd.
    // And the product of magnitudes must be >= 1.

    // Case 1: Final product is negative.
    // This requires an odd number of negative factors.
    // The initial negative factors come from A and B.
    // (A + B) % 2 == 1

    // If (A+B) is odd:
    // We need to ensure we can achieve magnitude >= 1.
    // If A > 0, we have at least one toy with magnitude >= 1.
    // If D > 0, we have at least one toy with magnitude >= 1.
    // If A > 0 or D > 0, we can potentially keep the magnitude >= 1.
    // If A=0 and D=0, all initial toys have magnitude < 1.
    // In this case, the product of any number of toys with magnitude < 1 will always be < 1.
    // So, if A=0 and D=0, we cannot end up in Box 1 or Box 4.
    // Thus, if (A+B) is odd and (A > 0 or D > 0), Box 1 is possible.

    // If (A+B) is even:
    // The final product will be positive. So Box 1 is not possible.

    // Special case: If A+B+C+D == 1, the single toy is the super toy.
    // If A=1, B=C=D=0, then Box 1 is possible.
    if (A == 1 && B == 0 && C == 0 && D == 0) return true;

    // If total toys > 1:
    // If (A+B) is odd:
    //   If A > 0 or D > 0: We have at least one toy with magnitude >= 1.
    //     We can always ensure the final product has magnitude >= 1.
    //     Example: If we have a toy with value -2 (from A) and many toys with magnitude < 1.
    //     We can multiply all magnitude < 1 toys together to get a product P with |P| < 1.
    //     Then multiply -2 * P. The result is negative, and |-2*P| < 2.
    //     If we have a toy with value 2 (from D) and many toys with magnitude < 1.
    //     We can multiply all magnitude < 1 toys together to get a product P with |P| < 1.
    //     Then multiply 2 * P. The result is positive, and |2*P| < 2.
    //     This doesn't guarantee magnitude >= 1.

    // Let's re-evaluate the magnitude condition.
    // To get magnitude >= 1, we need at least one toy from Box 1 or Box 4.
    // If A + D == 0, all initial toys have magnitude < 1.
    // Any product of such toys will have magnitude < 1.
    // So if A + D == 0, Box 1 is impossible.
    if (A + D == 0) return false;

    // Now we know A + D > 0, so there's at least one toy with magnitude >= 1.
    // We need the final product to be negative. This means (A + B) must be odd.
    if ((A + B) % 2 == 1) {
        return true;
    } else {
        // If (A+B) is even, the final product is positive.
        // Can we make it negative?
        // This requires changing the parity of negative factors.
        // This can only happen if we can "create" a negative factor from positive ones, which is impossible.
        // Or if we can "remove" a negative factor, which means pairing it with another negative factor.
        // If (A+B) is even, the final product will always be positive.
        return false;
    }
}

// Function to check if Box 2 can be the special box
// Box 2: (-1, 0) (Negative, magnitude < 1)
bool can_be_box2(long long A, long long B, long long C, long long D) {
    // To end up in Box 2, the final toy must be negative and have magnitude < 1.
    // This means the total number of negative factors must be odd.
    // And the product of magnitudes must be < 1.

    // Case 1: Final product is negative. (A + B) % 2 == 1.
    // Case 2: Final product has magnitude < 1.
    // This is always possible if B+C > 0.
    // If B+C > 0, we can pick a toy from B or C (e.g., 0.5 or -0.5).
    // Multiply all other toys together to get a product P.
    // Then multiply P by 0.5 (or -0.5). The magnitude will be |P| * 0.5, which is smaller.
    // We can always make the magnitude arbitrarily small by multiplying with toys from B or C.
    // So, if B+C > 0, we can always achieve magnitude < 1.

    // If A+B+C+D == 1:
    if (B == 1 && A == 0 && C == 0 && D == 0) return true;

    // If total toys > 1:
    // We need (A+B) to be odd for a negative result.
    // We need to be able to achieve magnitude < 1.
    // If B+C > 0, we can always achieve magnitude < 1.
    // So if (A+B) is odd AND (B+C > 0), Box 2 is possible.
    if ((A + B) % 2 == 1 && (B + C > 0)) {
        return true;
    }

    // What if (A+B) is even?
    // The product is positive. Can we make it negative? No.
    // So (A+B) must be odd.

    // What if B+C == 0?
    // This means all toys are from A or D.
    // If A+D > 0, all toys have magnitude >= 1.
    // The product of such toys will always have magnitude >= 1.
    // So if B+C == 0, Box 2 is impossible.
    return false;
}

// Function to check if Box 3 can be the special box
// Box 3: (0, 1) (Positive, magnitude < 1)
bool can_be_box3(long long A, long long B, long long C, long long D) {
    // To end up in Box 3, the final toy must be positive and have magnitude < 1.
    // This means the total number of negative factors must be even.
    // And the product of magnitudes must be < 1.

    // If A+B+C+D == 1:
    if (C == 1 && A == 0 && B == 0 && D == 0) return true;

    // If total toys > 1:
    // We need (A+B) to be even for a positive result.
    // We need to be able to achieve magnitude < 1.
    // If B+C > 0, we can always achieve magnitude < 1.
    // So if (A+B) is even AND (B+C > 0), Box 3 is possible.
    if ((A + B) % 2 == 0 && (B + C > 0)) {
        return true;
    }

    // What if (A+B) is odd?
    // The product is negative. Can we make it positive? No.
    // So (A+B) must be even.

    // What if B+C == 0?
    // This means all toys are from A or D.
    // If A+D > 0, all toys have magnitude >= 1.
    // The product of such toys will always have magnitude >= 1.
    // So if B+C == 0, Box 3 is impossible.
    return false;
}

// Function to check if Box 4 can be the special box
// Box 4: [1, inf) (Positive, magnitude >= 1)
bool can_be_box4(long long A, long long B, long long C, long long D) {
    // To end up in Box 4, the final toy must be positive and have magnitude >= 1.
    // This means the total number of negative factors must be even.
    // And the product of magnitudes must be >= 1.

    // If A+B+C+D == 1:
    if (D == 1 && A == 0 && B == 0 && C == 0) return true;

    // If total toys > 1:
    // We need (A+B) to be even for a positive result.
    // We need to be able to achieve magnitude >= 1.
    // If A+D > 0, we have at least one toy with magnitude >= 1.
    // We can always ensure the final product has magnitude >= 1.
    // Example: If we have a toy with value 2 (from D) and many toys with magnitude < 1.
    // We can multiply all magnitude < 1 toys together to get a product P with |P| < 1.
    // Then multiply 2 * P. The result is positive, and |2*P| < 2. This doesn't guarantee >= 1.

    // Let's re-evaluate the magnitude condition.
    // To get magnitude >= 1, we need at least one toy from Box 1 or Box 4.
    // If A + D == 0, all initial toys have magnitude < 1.
    // Any product of such toys will have magnitude < 1.
    // So if A + D == 0, Box 4 is impossible.
    if (A + D == 0) return false;

    // Now we know A + D > 0, so there's at least one toy with magnitude >= 1.
    // We need the final product to be positive. This means (A + B) must be even.
    if ((A + B) % 2 == 0) {
        return true;
    } else {
        // If (A+B) is odd, the final product is negative.
        return false;
    }
}

