        long long ans = 0;
        while (low <= high) {
            long long mid = low + (high - low) / 2;
            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians as minimums.
            // Remaining students: (c - mid) coders, (m - mid) mathematicians, x non-specialized.
