int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        long long current_cost = 0;
        long long count = 0;
        long long k = 1; // Represents 2^k - 1 stairs, starting with k=1 for 1 stair.
                         // The number of stairs is 2^k - 1.
                         // The cost for 2^k - 1 stairs is (2^k - 1) * 2^k / 2.
                         // This is equivalent to (2^k - 1) * (2^(k-1)).
                         // Let's use the formula for cost directly.
                         // Cost for n stairs is n*(n+1)/2.
                         // For n = 2^k - 1, cost is (2^k - 1) * (2^k) / 2.
                         // This can be written as (2^k - 1) * 2^(k-1).
                         // Let's precompute costs for n = 1, 3, 7, 15, ...

        // The number of stairs for a nice staircase is of the form 2^k - 1.
        // Let's generate these costs.
        // n=1 (k=1): cost = 1 * 2 / 2 = 1
        // n=3 (k=2): cost = 3 * 4 / 2 = 6
        // n=7 (k=3): cost = 7 * 8 / 2 = 28
        // n=15 (k=4): cost = 15 * 16 / 2 = 120
        // n=31 (k=5): cost = 31 * 32 / 2 = 496
        // ...
        // The cost for n = 2^k - 1 stairs is (2^k - 1) * 2^(k-1).
        // Let's denote n_k = 2^k - 1.
        // Cost_k = n_k * (n_k + 1) / 2 = (2^k - 1) * 2^k / 2 = (2^k - 1) * 2^(k-1).
        // The next cost (for k+1) is Cost_{k+1} = (2^(k+1) - 1) * 2^k.
        // Notice that Cost_{k+1} = (2 * (2^k - 1) + 1) * 2^k = (2 * n_k + 1) * 2^k.
        // This is not a simple recurrence.
        // Let's use the observation from the problem statement:
        // A staircase with n stairs is nice if n = 2^k - 1.
        // The cost of such a staircase is (2^k - 1) * 2^(k-1).
        // Let's denote the number of stairs as `num_stairs`.
        // Let's denote the cost as `current_staircase_cost`.

        long long num_stairs = 1; // n = 2^1 - 1
        long long current_staircase_cost = 1; // cost for 1 stair

        while (true) {
            if (x >= current_staircase_cost) {
                x -= current_staircase_cost;
                count++;

                // Calculate the next nice staircase's properties
                // The next number of stairs is 2 * num_stairs + 1
                // The next cost is (2 * num_stairs + 1) * (num_stairs + 1)
                // This is because if current num_stairs is 2^k - 1, then num_stairs + 1 = 2^k.
                // The next num_stairs is 2^(k+1) - 1 = 2 * (2^k - 1) + 1 = 2 * num_stairs + 1.
                // The next cost is (2^(k+1) - 1) * 2^k = (2 * num_stairs + 1) * (num_stairs + 1).

                num_stairs = 2 * num_stairs + 1;
                current_staircase_cost = num_stairs * (num_stairs + 1) / 2;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

