#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the maximum possible length of the strictly increasing prefix
    // ending at index i, if we set a[0] to 0, a[1] to 1, etc.
    // This means a[i] must be at least i.
    // More precisely, a[i] must be at least i-0 for a[0] to be 0, a[i] to be i.
    // So, a[i] must be at least i.
    // Let's call this `left_reach[i]`.
    // `left_reach[i]` is the maximum `j` such that `a[i]` can be `j` and `a[0]...a[i]` can be `0...j`.
    // This is equivalent to `a[i] >= i`.
    // The actual value we care about is `i` itself.
    // `left_possible[i]` is true if `a[0] < a[1] < ... < a[i]` can be formed with `a[0]=0, a[1]=1, ..., a[i]=i`.
    // This requires `a[j] >= j` for all `0 <= j <= i`.
    // We can find the first index `i` from the left where `a[i] < i`.
    // All indices before this `i` (inclusive) can potentially be part of the increasing sequence `0, 1, ..., i-1`.
    // Let `max_inc_len` be the maximum `k` such that `a_0, ..., a_{k-1}` can be `0, ..., k-1`.
    // This means `a_i >= i` for `0 <= i < k`.
    // We find the first `i` where `a[i] < i`. If no such `i` exists, `max_inc_len = n`.
    int max_inc_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            break;
        }
        max_inc_len = i + 1;
    }

    // Similarly, for the strictly decreasing suffix.
    // `a_k > a_{k+1} > ... > a_n`.
    // If we set `a_n` to 0, `a_{n-1}` to 1, etc.
    // `a_{n-j}` must be at least `j-1`.
    // `a[n-1]` must be at least 0.
    // `a[n-2]` must be at least 1.
    // `a[n-1-i]` must be at least `i`.
    // We find the first index `i` from the right where `a[n-1-i] < i`.
    // All indices after this `n-1-i` (inclusive) can potentially be part of the decreasing sequence `..., 1, 0`.
    // Let `max_dec_len` be the maximum `k` such that `a_{n-k}, ..., a_{n-1}` can be `k-1, ..., 0`.
    // This means `a[n-1-i] >= i` for `0 <= i < k`.
    // We find the first `i` where `a[n-1-i] < i`. If no such `i` exists, `max_dec_len = n`.
    int max_dec_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[n - 1 - i] < i) {
            break;
        }
        max_dec_len = i + 1;
    }

    // An array is sharpened if there exists a peak `k` (1-indexed) such that:
    // `a_1 < ... < a_k` and `a_k > ... > a_n`.
    // In 0-indexed terms, `a_0 < ... < a_{k-1}` and `a_{k-1} > ... > a_{n-1}`.
    // The peak index is `k-1`.
    // The length of the increasing part up to `a_{k-1}` is `k`.
    // The length of the decreasing part from `a_{k-1}` is `n - (k-1)`.
    //
    // We need to find if there's an index `p` (0-indexed peak) such that:
    // 1. `a_0, ..., a_p` can be `0, ..., p` (increasing part)
    // 2. `a_p, ..., a_{n-1}` can be `p, p-1, ..., p-(n-1-p)` (decreasing part)
    //
    // Condition 1 is satisfied if `p < max_inc_len`.
    // Condition 2 is satisfied if `(n-1-p) < max_dec_len`.
    //
    // So we need to check if there exists a `p` (0-indexed) such that:
    // `p < max_inc_len` AND `(n-1-p) < max_dec_len`.
    //
    // This is equivalent to checking if `max_inc_len + max_dec_len > n`.
    // Why?
    // `p < max_inc_len` means `p` can be `0, 1, ..., max_inc_len - 1`.
    // `n-1-p < max_dec_len` means `p > n-1-max_dec_len`.
    // So we need to find if there is an integer `p` such that:
    // `n - 1 - max_dec_len < p < max_inc_len`.
    // Such a `p` exists if and only if `(n - 1 - max_dec_len) + 1 < max_inc_len`.
    // Which simplifies to `n - max_dec_len < max_inc_len`.
    // Or `max_inc_len + max_dec_len > n`.

    if (max_inc_len + max_dec_len > n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Cost to make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // Elements to the left of the median must be <= s
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Elements to the right of the median must be >= s
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());

        // The problem asks for the minimum absolute difference between medians.
        // With 2n students, if we sort all students' skill levels,
        // the optimal strategy is to assign the first n students to one class
        // and the next n students to the other class.
        // However, the classes must have an odd number of students.
        // The total number of students is 2n.
        // If we split the sorted array into two halves:
        // [a_0, ..., a_{n-1}] and [a_n, ..., a_{2n-1}]
        // The median of the first half (if it were a class) would be a_{(n-1)/2}
        // The median of the second half (if it were a class) would be a_{n + (n-1)/2}
        // This split is only valid if n is odd.
        // If n is odd, then n students is an odd number.
        // So, we can form two classes of size n.
        // The median of the first class (a_0, ..., a_{n-1}) would be a_{(n-1)/2}.
        // The median of the second class (a_n, ..., a_{2n-1}) would be a_{n + (n-1)/2}.
        // The difference would be a_{n + (n-1)/2} - a_{(n-1)/2}.
        //
        // However, the problem statement implies a simpler structure.
        // The median of an array of 2k+1 elements is the (k+1)-th element.
        // This means there are k elements smaller or equal, and k elements larger or equal.
        //
        // Consider the sorted array a_0, a_1, ..., a_{2n-1}.
        // We need to pick two medians, say m1 and m2.
        // Let class 1 have size 2k1+1 and class 2 have size 2k2+1.
        // (2k1+1) + (2k2+1) = 2n => 2k1 + 2k2 + 2 = 2n => k1 + k2 + 1 = n.
        //
        // To minimize the difference between medians, we want the medians to be as close as possible.
        // The smallest possible median for any class will be a_0 (if class size is 1).
        // The largest possible median for any class will be a_{2n-1} (if class size is 1).
        //
        // Consider the two elements a_{n-1} and a_n from the sorted array.
        // Can we make a_{n-1} the median of one class and a_n the median of another?
        // If a_{n-1} is the median of a class of size 2k1+1, it means there are k1 elements <= a_{n-1}
        // and k1 elements >= a_{n-1} in that class.
        // If a_n is the median of a class of size 2k2+1, it means there are k2 elements <= a_n
        // and k2 elements >= a_n in that class.
        //
        // The most balanced way to split the students to get two medians close to the overall middle
        // is to take the n smallest students for one group and the n largest students for the other.
        // This is not quite right because class sizes must be odd.
        //
        // The key insight for this type of problem is often that the optimal medians will be adjacent
        // elements in the globally sorted array, or at least very close.
        //
        // If we form two classes, say Class A and Class B, with sizes |A| and |B| respectively.
        // Let |A| = 2k_A + 1 and |B| = 2k_B + 1.
        // Then (2k_A + 1) + (2k_B + 1) = 2n, which implies k_A + k_B + 1 = n.
        //
        // Consider the elements a_{n-1} and a_n in the sorted array.
        // Can we make a_{n-1} the median of one class and a_n the median of the other?
        // To make a_{n-1} the median of a class, we need to pick k_A elements smaller than or equal to a_{n-1}
        // and k_A elements larger than or equal to a_{n-1}.
        // To make a_n the median of a class, we need to pick k_B elements smaller than or equal to a_n
        // and k_B elements larger than or equal to a_n.
        //
        // The simplest partition that satisfies the odd size constraint and minimizes the difference
        // is to take the first n elements for one "half" and the next n elements for the other "half".
        // The median of the first "half" (a_0, ..., a_{n-1}) would be a_{(n-1)/2} if n is odd.
        // The median of the second "half" (a_n, ..., a_{2n-1}) would be a_{n + (n-1)/2} if n is odd.
        //
        // The problem is simpler: the two medians will be a_{n-1} and a_n.
        // We can always construct two classes such that a_{n-1} is the median of one and a_n is the median of the other.
        //
        // Class 1: Take a_{n-1} as its median.
        // We need k_1 elements smaller than or equal to a_{n-1} and k_1 elements larger than or equal to a_{n-1}.
        // We can take a_0, ..., a_{n-2} (n-1 elements) and assign them to Class 1 or Class 2.
        // We can take a_n, ..., a_{2n-1} (n elements) and assign them to Class 1 or Class 2.
        //
        // Consider the partition where Class 1 consists of students with skill levels
        // a_0, a_1, ..., a_{n-1}. This class has n students.
        // Class 2 consists of students with skill levels
        // a_n, a_{n+1}, ..., a_{2n-1}. This class also has n students.
        //
        // If n is odd, then both classes have an odd number of students.
        // The median of Class 1 is a_{(n-1)/2}.
        // The median of Class 2 is a_{n + (n-1)/2}.
        // The difference is a_{n + (n-1)/2} - a_{(n-1)/2}.
        //
        // If n is even, then both classes have an even number of students, which is not allowed.
        //
        // The problem statement is a bit tricky. It asks for *any* partition where each class has an odd number of students.
        // The simplest way to achieve this is to make one class of size 1 and the other of size 2n-1.
        // For example, Class A = {a_0}, median = a_0. Class B = {a_1, ..., a_{2n-1}}, median = a_{1 + (2n-1-1)/2} = a_{1+n-1} = a_n.
        // Difference = |a_n - a_0|. This is usually not minimal.
        //
        // The crucial observation is that to minimize the difference between two medians,
        // these medians should be chosen from the "middle" of the sorted array.
        // Specifically, the two medians will be a_{n-1} and a_n.
        //
        // Let's prove this. Suppose we have two classes, C1 and C2, with medians M1 and M2.
        // Assume M1 < M2.
        // For C1, there are k1 elements <= M1 and k1 elements >= M1.
        // For C2, there are k2 elements <= M2 and k2 elements >= M2.
        // Total elements: 2n.
        // Total elements <= M1: at least k1+1 (M1 itself and k1 smaller ones).
        // Total elements >= M2: at least k2+1 (M2 itself and k2 larger ones).
        //
        // The elements a_0, ..., a_{n-1} are the first n elements.
        // The elements a_n, ..., a_{2n-1} are the last n elements.
        //
        // If we pick a_{n-1} as the median of one class and a_n as the median of the other,
        // we can always construct such classes.
        //
        // Class 1: {a_0, a_1, ..., a_{n-1}}. This class has n elements.
        // Class 2: {a_n, a_{n+1}, ..., a_{2n-1}}. This class has n elements.
        //
        // If n is odd, then both classes have odd sizes.
        // Median of Class 1 is a_{(n-1)/2}.
        // Median of Class 2 is a_{n + (n-1)/2}.
        // The difference is a_{n + (n-1)/2} - a_{(n-1)/2}.
        //
        // This is not what the example implies.
        // Example 2: n=3, 2n=6. Skills: 1 2 3 4 5 6. Sorted: 1 2 3 4 5 6.
        // Here n=3 is odd.
        // Class 1: {1, 2, 3}. Median = 2. (a_{(3-1)/2} = a_1)
        // Class 2: {4, 5, 6}. Median = 5. (a_{3+(3-1)/2} = a_4)
        // Difference = |5-2| = 3.
        // The example output is 1.
        // The example partition is [6, 4, 2] (median 4) and [5, 1, 3] (median 3). Difference |4-3|=1.
        // This means the simple split into two halves of size n is not necessarily optimal.
        //
        // The example partition uses elements from both "halves" of the sorted array.
        // Class 1: {2, 4, 6}. Median is 4.
        // Class 2: {1, 3, 5}. Median is 3.
        //
        // The key is that the problem asks for the minimum possible absolute difference.
        // The two medians must be chosen from the sorted array.
        // Let the sorted array be $a_0, a_1, \dots, a_{2n-1}$.
        //
        // Consider the elements $a_{n-1}$ and $a_n$.
        // These are the two "middle" elements of the entire sorted array.
        // It is always possible to construct two classes such that $a_{n-1}$ is the median of one class
        // and $a_n$ is the median of the other class.
        //
        // Let's try to make $a_{n-1}$ the median of Class A and $a_n$ the median of Class B.
        // Class A needs $k_A$ elements smaller than or equal to $a_{n-1}$ and $k_A$ elements larger than or equal to $a_{n-1}$.
        // Class B needs $k_B$ elements smaller than or equal to $a_n$ and $k_B$ elements larger than or equal to $a_n$.
        // And $k_A + k_B + 1 = n$.
        //
        // We can form Class A with $a_{n-1}$ as its median by taking $k_A$ elements from $a_0, \dots, a_{n-2}$
        // and $k_A$ elements from $a_n, \dots, a_{2n-1}$.
        // We can form Class B with $a_n$ as its median by taking $k_B$ elements from $a_0, \dots, a_{n-1}$
        // and $k_B$ elements from $a_{n+1}, \dots, a_{2n-1}$.
        //
        // The simplest construction:
        // Class A: {a_0, a_1, ..., a_{n-1}}
        // Class B: {a_n, a_{n+1}, ..., a_{2n-1}}
        // This is a partition into two groups of size n.
        // If n is odd, this is a valid partition.
        // Median of A is a_{(n-1)/2}. Median of B is a_{n + (n-1)/2}.
        // The difference is a_{n + (n-1)/2} - a_{(n-1)/2}.
        //
        // The example output for n=3 (2n=6) is 1.
        // Sorted array: 1 2 3 4 5 6.
        // a_0=1, a_1=2, a_2=3, a_3=4, a_4=5, a_5=6.
        // n=3. (n-1)/2 = 1.
        // a_{(n-1)/2} = a_1 = 2.
        // a_{n+(n-1)/2} = a_{3+1} = a_4 = 5.
        // Difference = 5-2 = 3. This is not 1.
        //
        // This means my interpretation of the "simple split" is wrong for the general case.
        //
        // The problem is much simpler than trying to construct classes.
        // The minimum difference between medians will always be $a_n - a_{n-1}$.
        //
        // Why?
        // Let $M_1$ and $M_2$ be the medians of the two classes, with $M_1 \le M_2$.
        // Each class has an odd number of students. Let class 1 have $2k_1+1$ students and class 2 have $2k_2+1$ students.
        // $k_1+k_2+1 = n$.
        //
        // For class 1, there are $k_1$ students with skill $\le M_1$ and $k_1$ students with skill $\ge M_1$.
        // For class 2, there are $k_2$ students with skill $\le M_2$ and $k_2$ students with skill $\ge M_2$.
        //
        // Consider the $n$ smallest students in the overall sorted list: $a_0, \dots, a_{n-1}$.
        // At most $k_1$ of these can be greater than or equal to $M_1$ (if $M_1$ is one of $a_0, \dots, a_{n-1}$).
        // At most $k_2$ of these can be greater than or equal to $M_2$.
        //
        // The total number of students with skill $\le M_1$ is at least $k_1+1$.
        // The total number of students with skill $\ge M_2$ is at least $k_2+1$.
        //
        // Summing these, we have at least $(k_1+1) + (k_2+1)$ distinct students.
        // These are $k_1+k_2+2 = n+1$ students.
        //
        // This means that there must be at least $n+1$ students in the range $[a_0, \dots, a_{2n-1}]$
        // such that $a_i \le M_1$ or $a_i \ge M_2$.
        //
        // If $M_1$ is $a_x$ and $M_2$ is $a_y$ in the sorted list.
        // We know that $x \le n-1$ and $y \ge n$.
        //
        // The $n$ smallest elements are $a_0, \dots, a_{n-1}$.
        // The $n$ largest elements are $a_n, \dots, a_{2n-1}$.
        //
        // If $M_1$ is the median of Class A, then at least $k_A+1$ elements in Class A are $\le M_1$.
        // If $M_2$ is the median of Class B, then at least $k_B+1$ elements in Class B are $\ge M_2$.
        //
        // The total number of elements $\le M_1$ in the entire $2n$ students must be at least $k_A+1$.
        // The total number of elements $\ge M_2$ in the entire $2n$ students must be at least $k_B+1$.
        //
        // Since $k_A+k_B+1 = n$, we have $k_A+1 + k_B+1 = n+1$.
        // This means there are at least $n+1$ students whose skill levels are either $\le M_1$ or $\ge M_2$.
        //
        // In the sorted array $a_0, \dots, a_{2n-1}$:
        // The elements $a_0, \dots, a_{n-1}$ are $n$ elements.
        // The elements $a_n, \dots, a_{2n-1}$ are $n$ elements.
        //
        // If $M_1 < a_{n-1}$, then there are at most $n-1$ elements $\le M_1$.
        // This would mean $k_A+1 \le n-1$, so $k_A \le n-2$.
        // If $M_2 > a_n$, then there are at most $n-1$ elements $\ge M_2$.
        // This would mean $k_B+1 \le n-1$, so $k_B \le n-2$.
        //
        // This line of reasoning is getting complicated.
        //
        // Let's use the property of medians:
        // For any set of $2k+1$ numbers, its median is $b_{k+1}$ in sorted order.
        // This means there are $k$ numbers $\le b_{k+1}$ and $k$ numbers $\ge b_{k+1}$.
        //
        // Let $M_1$ and $M_2$ be the medians of the two classes.
        // Without loss of generality, assume $M_1 \le M_2$.
        //
        // Class 1 has $2k_1+1$ students, median $M_1$.
        // Class 2 has $2k_2+1$ students, median $M_2$.
        // $k_1+k_2+1 = n$.
        //
        // There are at least $k_1+1$ students in Class 1 with skill $\le M_1$.
        // There are at least $k_2+1$ students in Class 2 with skill $\ge M_2$.
        //
        // These two sets of students are disjoint.
        // So, in the entire set of $2n$ students, there are at least $(k_1+1) + (k_2+1) = n+1$ students
        // whose skill is either $\le M_1$ or $\ge M_2$.
        //
        // In the sorted array $a_0, \dots, a_{2n-1}$:
        // The first $n$ elements are $a_0, \dots, a_{n-1}$.
        // The last $n$ elements are $a_n, \dots, a_{2n-1}$.
        //
        // If $M_1$ were greater than $a_{n-1}$, then all $n$ elements $a_0, \dots, a_{n-1}$ would be $\le M_1$.
        // If $M_2$ were less than $a_n$, then all $n$ elements $a_n, \dots, a_{2n-1}$ would be $\ge M_2$.
        //
        // Consider the $n$ elements $a_0, \dots, a_{n-1}$.
        // At most $k_1$ of these can be part of Class 1 and be $\ge M_1$.
        // At most $k_2$ of these can be part of Class 2 and be $\ge M_2$.
        //
        // The crucial observation is that $a_{n-1}$ is the largest of the first $n$ elements,
        // and $a_n$ is the smallest of the last $n$ elements.
        //
        // It is always possible to construct two classes such that $a_{n-1}$ is the median of one class
        // and $a_n$ is the median of the other class.
        //
        // Let's try to make $a_{n-1}$ the median of Class A and $a_n$ the median of Class B.
        // We need to pick $k_A$ elements for Class A that are $\le a_{n-1}$ and $k_A$ elements that are $\ge a_{n-1}$.
        // We need to pick $k_B$ elements for Class B that are $\le a_n$ and $k_B$ elements that are $\ge a_n$.
        // And $k_A+k_B+1 = n$.
        //
        // We can choose $k_A = 0$ and $k_B = n-1$.
        // Class A: $\{a_{n-1}\}$. Median is $a_{n-1}$. Size is 1 (odd).
        // Class B: $\{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$.
        // This class has $(n-1) + n = 2n-1$ students. Size is odd.
        // Its median would be $a_n$.
        // To verify: Class B has $2n-1$ students. $k_B = (2n-1-1)/2 = n-1$.
        // We need $n-1$ students $\le a_n$ and $n-1$ students $\ge a_n$.
        // The students $a_0, \dots, a_{n-2}$ are $n-1$ students, all $\le a_n$.
        // The students $a_{n+1}, \dots, a_{2n-1}$ are $n-1$ students, all $\ge a_n$.
        // So, this construction works!
        //
        // Class A = $\{a_{n-1}\}$ (median $a_{n-1}$)
        // Class B = $\{a_0, \dots, a_{n-2}\} \cup \{a_n, \dots, a_{2n-1}\}$ (median $a_n$)
        // The difference is $|a_n - a_{n-1}|$.
        //
        // This construction is always possible and satisfies all conditions:
        // 1. Each student is assigned to exactly one class.
        //    $a_{n-1}$ goes to Class A.
        //    All other $2n-1$ students go to Class B.
        // 2. Each class has an odd number of students.
        //    Class A has 1 student (odd).
        //    Class B has $2n-1$ students (odd, since $2n-1$ is always odd for any $n \ge 1$).
        // 3. Skill level of a class is the median.
        //    Median of Class A is $a_{n-1}$.
        //    Median of Class B is $a_n$. (This is because $a_n$ is the $(n-1+1)$-th element in the sorted list of Class B elements, which is $a_0, \dots, a_{n-2}, a_n, a_{n+1}, \dots, a_{2n-1}$. There are $n-1$ elements before $a_n$ and $n-1$ elements after $a_n$.)
        //
        // Since $a_n - a_{n-1}$ is the smallest possible difference between any two adjacent elements in the sorted array,
        // and we have shown that we can achieve this difference, it must be the minimum.
        //
        // Example 1: n=1, 2n=2. Skills: 1 1. Sorted: 1 1.
        // a_0=1, a_1=1.
        // n-1 = 0, n = 1.
        // Difference = a_1 - a_0 = 1 - 1 = 0. Correct.
        //
        // Example 2: n=3, 2n=6. Skills: 6 5 4 1 2 3. Sorted: 1 2 3 4 5 6.
        // a_0=1, a_1=2, a_2=3, a_3=4, a_4=5, a_5=6.
        // n-1 = 2, n = 3.
        // Difference = a_3 - a_2 = 4 - 3 = 1. Correct.
        //
        // Example 3: n=5, 2n=10. Skills: 13 4 20 13 2 5 8 3 17 16.
        // Sorted: 2 3 4 5 8 13 13 16 17 20.
        // a_0=2, a_1=3, a_2=4, a_3=5, a_4=8, a_5=13, a_6=13, a_7=16, a_8=17, a_9=20.
        // n-1 = 4, n = 5.
        // Difference = a_5 - a_4 = 13 - 8 = 5. Correct.
        //
        // The logic holds for all examples.
        // The minimum difference is simply the difference between the (n-1)-th and n-th elements (0-indexed)
        // of the globally sorted array.

        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

