        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    int count = 0;
    int left_ptr = 0; // Pointer for elements to be placed (smaller elements)
    int right_ptr = 0; // Pointer for elements to be used as original (larger elements)

    // We want to find a permutation b such that b[i] > a[i] for as many i as possible.
    // Sort the original array 'a'.
    // Now, we iterate through the sorted 'a' using 'left_ptr' for the elements we want to place (b[i])
    // and 'right_ptr' for the elements that were originally at that position (a[i]).
    // To maximize the count, we try to match the smallest available element from 'a' (at left_ptr)
    // with the smallest available element from 'a' that is strictly greater than it (at right_ptr).
    // This is a greedy approach.
    // 'left_ptr' represents the index of the element from the sorted array 'a' that we are trying to place
    // into a position where an element 'a[right_ptr]' used to stand.
    // We want to find a 'b[i]' (which is a[left_ptr]) such that 'b[i] > a[i]' (which is a[right_ptr]).
    // So, we are essentially trying to match a[left_ptr] with a[right_ptr] such that a[left_ptr] > a[right_ptr].
    // To maximize matches, we should use the smallest possible a[left_ptr] that satisfies the condition
    // for the current a[right_ptr].
    // This means we advance 'left_ptr' only when we find a match.
    // 'right_ptr' always advances, effectively considering the next element from the sorted original array
    // as the 'a[i]' we are trying to beat.

    while (right_ptr < n) {
        // If the element at left_ptr can be placed at a position where element at right_ptr used to stand
        // and satisfy the condition (a[left_ptr] > a[right_ptr]), then we make this match.
        // We increment count and move to the next element for both 'b' (left_ptr) and 'a' (right_ptr).
        if (a[left_ptr] > a[right_ptr]) {
            count++;
            left_ptr++;
            right_ptr++;
        } else {
            // If a[left_ptr] is not greater than a[right_ptr], it means a[left_ptr] is too small
            // to beat a[right_ptr]. We cannot use a[left_ptr] for this a[right_ptr].
            // Since we want to maximize matches, we should try to beat a[right_ptr] with a larger element.
            // However, we are iterating through sorted 'a' with 'left_ptr', so we can't just pick a larger 'a[left_ptr]'.
            // Instead, we must move on to try to beat the *next* original element a[right_ptr+1]
            // with the *same* a[left_ptr] (or a[left_ptr+1] if we already used a[left_ptr]).
            // The key insight is that if a[left_ptr] cannot beat a[right_ptr], it also cannot beat any a[k] where k > right_ptr
            // if a[left_ptr] is still smaller than or equal to a[right_ptr].
            // The correct greedy strategy is:
            // We have two pointers, `left_ptr` and `right_ptr`, both starting at 0.
            // `left_ptr` points to the element we are trying to place in the permuted array `b`.
            // `right_ptr` points to the element in the original array `a` that we are trying to beat.
            // If `a[left_ptr] > a[right_ptr]`, we found a successful match. Increment `count`, and advance both pointers.
            // If `a[left_ptr] <= a[right_ptr]`, `a[left_ptr]` is too small to beat `a[right_ptr]`.
            // We cannot use `a[left_ptr]` to beat `a[right_ptr]`.
            // To maximize matches, we should try to use `a[left_ptr]` to beat some *other* `a[k]` where `k > right_ptr`.
            // But this is not how it works. We are trying to match elements from the sorted array `a` to positions in the sorted array `a`.
            // The `right_ptr` effectively represents the "original" element `a[i]` that we are trying to beat.
            // The `left_ptr` represents the "permuted" element `b[i]` that we are using.
            // If `a[left_ptr] <= a[right_ptr]`, it means the current smallest available element for `b` (a[left_ptr])
            // is not large enough to beat the current smallest available element for `a` (a[right_ptr]).
            // In this case, `a[left_ptr]` cannot be used to beat `a[right_ptr]`.
            // We must try to use a larger element for `b`. So, we advance `left_ptr`.
            // The `right_ptr` stays, waiting for a larger `a[left_ptr]` to come along.
            // This is incorrect. The problem is about positions.
            // Let's re-evaluate the greedy strategy.
            // We have sorted `a`. We want to form `b` (a permutation of `a`).
            // We want to maximize `b[i] > a[i]`.
            // Consider `a_sorted = [a_0, a_1, ..., a_{n-1}]`.
            // We want to pair `a_j` with `a_k` such that `a_j > a_k`.
            // To maximize such pairs, we should try to use the smallest possible `a_j` to beat the smallest possible `a_k`.
            // Let `i` be the pointer for elements we are trying to beat (from `a_sorted`).
            // Let `j` be the pointer for elements we are using to beat (from `a_sorted`).
            // Initialize `i = 0`, `j = 0`.
            // While `j < n`:
            //   If `a_sorted[j] > a_sorted[i]`:
            //     We can use `a_sorted[j]` to beat `a_sorted[i]`. This is a successful match.
            //     Increment `count`.
            //     Advance both `i` and `j`.
            //   Else (`a_sorted[j] <= a_sorted[i]`):
            //     `a_sorted[j]` is not large enough to beat `a_sorted[i]`.
            //     We must try a larger element for `b`. So, advance `j`.
            //     `i` stays, waiting for a larger `a_sorted[j]` to beat it.
            // This is the correct greedy strategy.

            left_ptr++; // This is the 'j' pointer in the re-evaluation.
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long turn = 0; // 0 for Chanek, 1 for Opponent

    while (n > 0) {
        if (turn == 0) { // Chanek's turn
            if (n % 2 == 1) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                // Option 1: Take N/2
                // Option 2: Take 1

                // If N is a power of 2 (and N > 2), taking N/2 leaves N/2, which is also a power of 2.
                // The opponent will then take N/4, and so on.
                // This leads to a sequence of N/2, N/4, N/8, ... 1.
                // If N is not a power of 2, N/2 might be odd or even.

                // Check if N is a power of 2
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    // If N is a power of 2, taking N/2 is always optimal for the current player
                    // because it forces the opponent to take N/4, etc., maximizing the current player's share.
                    // Example: N=8. Chanek takes 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                    // Chanek: 4+1=5. Opponent: 2+1=3.
                    // If Chanek takes 1: N=7. Opponent takes 1. N=6. Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                    // Chanek: 1+3+1=5. Opponent: 1+1+1=3.
                    // It seems taking N/2 is always better or equal for powers of 2.
                    // For N=2, Chanek takes 1. N=1. Opponent takes 1. Chanek: 1. Opponent: 1.
                    // If Chanek takes N/2 (1): N=1. Opponent takes 1. Chanek: 1. Opponent: 1.
                    // So for N=2, both options yield the same result.
                    // For N > 2 and N is a power of 2, taking N/2 is optimal.
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N is even but not a power of 2
                    // If N is even and not a power of 2, N/2 will not be a power of 2 (unless N/2 is 1, i.e., N=2).
                    // If N/2 is odd, the opponent will be forced to take 1.
                    // If N/2 is even but not a power of 2, the opponent will also face a similar choice.
                    // Taking N/2 is generally better if it leaves the opponent with an odd number or a number that is not a power of 2.
                    // Taking 1 leaves the opponent with an odd number.
                    // The strategy is to take N/2 if N/2 is odd, or if N/2 is even and not a power of 2.
                    // The only case where taking 1 might be better is if N/2 is a power of 2.
                    // If N/2 is a power of 2, then N must be 2 * (power of 2).
                    // Example: N=6. N/2=3 (odd). Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                    // Chanek: 3+1=4. Opponent: 1+1=2.
                    // If Chanek takes 1: N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                    // Chanek: 1+2+1=4. Opponent: 1+1=2.
                    // In this case, both options yield the same result for Chanek.
                    // It seems taking N/2 is always optimal for Chanek when N is even and not a power of 2.
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n % 2 == 1) { // N is odd
                n -= 1;
            } else { // N is even
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    n /= 2;
                } else { // N is even but not a power of 2
                    n /= 2;
                }
            }
        }
        turn = 1 - turn; // Switch turn
    }
    return chanek_coins;
}

