    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl << std::endl;
    } else {
        // We need to append at most 3 elements.
        // Let's try to append two elements: X and S+X.
        // New XOR sum: current_xor_sum ^ X ^ (S+X)
        // New sum: current_sum + X + (S+X)
        // We want: current_sum + X + (S+X) = 2 * (current_xor_sum ^ X ^ (S+X))
        // Let b1 = current_xor_sum.
        // Let b2 = current_sum + current_xor_sum.
        // New XOR sum: current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
        //            = 0 ^ (current_sum + current_xor_sum)
        //            = current_sum + current_xor_sum
        // New sum: current_sum + current_xor_sum + (current_sum + current_xor_sum)
        //        = 2 * (current_sum + current_xor_sum)
        //
        // So, if we append b1 = current_xor_sum and b2 = current_sum + current_xor_sum,
        // the new sum will be 2 * (current_sum + current_xor_sum)
        // and the new XOR sum will be current_sum + current_xor_sum.
        // This satisfies the condition: new_sum = 2 * new_xor_sum.

        long long b1 = current_xor_sum;
        long long b2 = current_sum + current_xor_sum;

        std::cout << 2 << std::endl;
        std::cout << b1 << " " << b2 << std::endl;
    }
}

