#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // current_min_idx and current_max_idx are already set to pos[1].
        // The length is 1. Max value is 1. Min value is 1.
        // So m=1 is always beautiful.

        // For m > 1, we need to expand the segment to include m.
        // The segment must contain 1, 2, ..., m.
        // The current segment [current_min_idx, current_max_idx] already contains 1, ..., m-1.
        // To include m, we must extend the segment to include pos[m].
        // Update current_min_idx and current_max_idx to cover the range [1, ..., m].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number m is beautiful if the segment p[current_min_idx ... current_max_idx]
        // is a permutation of 1, ..., m.
        // This means its length must be exactly m.
        // The length of the segment is (current_max_idx - current_min_idx + 1).
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

