int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let i be the number of items taken from the left (0 <= i <= n)
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += (prefix_sum[i] - prefix_sum[0]) * l;

        // Energy for items taken from the right
        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Add penalties
        if (i > j) { // More items from left than right
            int diff = i - j;
            // If all items are taken, and i > j, then the last item must have been from the left.
            // The number of "extra" left items is diff.
            // The number of times we took left consecutively after right items ran out is diff - 1.
            // This applies if j < n. If j == n, then i == 0, so i > j is false.
            // If j < n, then the last j items were taken from the right.
            // The remaining diff items were taken from the left.
            // The last diff-1 items taken from the left would incur Ql penalty.
            // This is equivalent to (i - j - 1) * Ql if i > j.
            // The problem statement says "If the previous action was the same (left-hand), then the robot spends extra Ql energy units".
            // This means if we take L, L, L, the second L costs Ql, the third L costs Ql.
            // If we take i items from left and j items from right, and i > j,
            // it means we took i items from left and j items from right.
            // The "excess" items from the left are i - j.
            // If i - j > 0, it means we took more items from the left.
            // The minimum number of times we could have switched hands is 1 (L...L R...R) or 0 (all L or all R).
            // The penalty applies when the *number* of items from one side exceeds the other by more than 1.
            // If i > j, it means we took i items from left and j items from right.
            // The "excess" items from the left are i - j.
            // If i = j + 1, no penalty.
            // If i = j + 2, one Ql penalty.
            // If i = j + k, k-1 Ql penalties.
            // So, if i > j, penalty is (i - j - 1) * Ql.
            current_energy += (i - j - 1) * Ql;
        } else if (j > i) { // More items from right than left
            int diff = j - i;
            // Similar logic: if j > i, penalty is (j - i - 1) * Qr.
            current_energy += (j - i - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

