void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    for (int split_digit = 0; split_digit <= 9; ++split_digit) {
        std::string coloring(n, ' ');
        char last1 = '0'; // Last digit colored 1
        char last2 = (char)(split_digit + '0'); // Last digit colored 2 (initially split_digit)
        bool possible_split = true;

        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];

            // Option 1: Color current_digit with 1
            // This is possible if current_digit >= last1 AND current_digit <= split_digit
            bool can_color_1 = (current_digit >= last1) && (current_digit <= (char)(split_digit + '0'));

            // Option 2: Color current_digit with 2
            // This is possible if current_digit >= last2
            bool can_color_2 = (current_digit >= last2);

            if (can_color_1 && can_color_2) {
                // If both are possible, greedily choose 1 if current_digit == split_digit
                // This helps to "fill up" S1 with split_digit as much as possible
                // before moving to S2, which starts with split_digit.
                // This is crucial for correctness.
                if (current_digit == (char)(split_digit + '0')) {
                    coloring[i] = '1';
                    last1 = current_digit;
                } else { // current_digit < split_digit (since it's <= split_digit)
                    coloring[i] = '1';
                    last1 = current_digit;
                }
            } else if (can_color_1) {
                coloring[i] = '1';
                last1 = current_digit;
            } else if (can_color_2) {
                coloring[i] = '2';
                last2 = current_digit;
            } else {
                possible_split = false;
                break;
            }
        }

        if (possible_split) {
            std::cout << coloring << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

