// Function to get prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // This means we need to remove some prime factors from p such that the resulting number
        // is no longer divisible by q, but is as large as possible.

        // Get prime factors of q.
        // For each prime factor f of q, we need to reduce the count of f in p
        // until p is no longer divisible by q.
        // To maximize x, we should remove the minimum necessary factors.
        // If q = f1^a1 * f2^a2 * ... * fk^ak
        // and p = f1^b1 * f2^b2 * ... * fk^bk * ...
        // For p to be divisible by q, we must have bi >= ai for all i.
        // To make p not divisible by q, we need to find some fi such that
        // if we divide p by fi enough times, the new exponent b'i < ai.
        // We want to find the largest x. This means we want to divide p by the smallest possible factor.
        // For each prime factor f of q, we can form a candidate x by dividing p by f until
        // the resulting number is no longer divisible by q.
        // Specifically, if p = P * f^k and q = Q * f^m, where P, Q are not divisible by f.
        // If k >= m, then p is divisible by f^m.
        // We need to find x such that x is not divisible by f^m.
        // The largest such x would be p / f^(k - m + 1).
        // We do this for each prime factor of q and take the maximum.

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 1;

        for (long long f : q_prime_factors) {
            long long current_p = p;
            // Divide current_p by f until it's no longer divisible by q.
            // This means we need to find the smallest power of f, say f^k, such that
            // (p / f^k) % q != 0.
            // We want to maximize p / f^k, so we want to minimize f^k.
            // The smallest k such that (p / f^k) % q != 0.
            // Let's count the power of f in q.
            long long q_f_power = 0;
            long long temp_q = q;
            while (temp_q > 0 && temp_q % f == 0) {
                q_f_power++;
                temp_q /= f;
            }

            // Now, we need to find the largest x that is a divisor of p,
            // and x is not divisible by q.
            // We iterate through divisors of p that are formed by removing factors of f.
            // We want to remove just enough factors of f from p such that the resulting number
            // is no longer divisible by q.
            // The number of factors of f in p must be reduced below q_f_power.
            // So, if p has p_f_power factors of f, we need to remove p_f_power - q_f_power + 1 factors of f.
            long long p_f_power = 0;
            long long temp_p = p;
            while (temp_p > 0 && temp_p % f == 0) {
                p_f_power++;
                temp_p /= f;
            }

            // The number of factors of f to remove from p is p_f_power - q_f_power + 1.
            // This ensures that the remaining number of factors of f is q_f_power - 1,
            // which is less than q_f_power, so it won't be divisible by f^q_f_power.
            // And since q is divisible by f^q_f_power, the new number won't be divisible by q.
            long long current_x = p;
            for (int i = 0; i < p_f_power - q_f_power + 1; ++i) {
                current_x /= f;
            }
            max_x = std::max(max_x, current_x);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

