int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    // Since b can be up to 10^7, (b-1)*b can be up to 10^14, which fits in long long.
    // We need to perform division by 2.
    // If b is even, b/2 is integer.
    // If b-1 is even, (b-1)/2 is integer.
    // One of b or b-1 must be even.
    long long sum_r;
    if (b % 2 == 0) {
        sum_r = ((b - 1) % MOD * (b / 2 % MOD)) % MOD;
    } else {
        sum_r = (((b - 1) / 2) % MOD * (b % MOD)) % MOD;
    }

    // Calculate sum_k_b_plus_1 = sum_{k=1 to a} (k * b + 1)
    // sum_k_b_plus_1 = sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // sum_{k=1 to a} k = a * (a + 1) / 2
    long long sum_k;
    if (a % 2 == 0) {
        sum_k = (a / 2 % MOD * ((a + 1) % MOD)) % MOD;
    } else {
        sum_k = (((a + 1) / 2) % MOD * (a % MOD)) % MOD;
    }

    long long sum_k_b_plus_1 = (b % MOD * sum_k) % MOD;
    sum_k_b_plus_1 = (sum_k_b_plus_1 + (a % MOD)) % MOD;

    // Total sum S = sum_r * sum_k_b_plus_1
    long long total_sum = (sum_r * sum_k_b_plus_1) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

