int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_prob = 0.0;

    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char first_char_t = s[k_actual];
        int char_code = first_char_t - 'a';

        const std::vector<int>& possible_k_values = char_indices[char_code];

        if (possible_k_values.size() == 1) {
            total_prob += 1.0; // Vasya wins for sure if only one k matches t[0]
            continue;
        }

        // Vasya needs to choose an optimal position p to reveal t[p]
        // to maximize the probability of winning for this specific t[0].
        // This is equivalent to maximizing the number of k_i for which
        // t[p] uniquely determines k_i among possible_k_values.

        int max_wins_for_this_t0 = 0;

        // Iterate over all possible positions p (1 to L-1)
        for (int p = 1; p < L; ++p) {
            std::vector<std::vector<int>> groups_by_tp_char(26);
            for (int k_cand : possible_k_values) {
                // t_k_cand[p] = s[(k_cand + p) % L]
                char char_at_p = s[(k_cand + p) % L];
                groups_by_tp_char[char_at_p - 'a'].push_back(k_cand);
            }

            int current_p_wins = 0;
            for (int c = 0; c < 26; ++c) {
                if (groups_by_tp_char[c].size() == 1) {
                    current_p_wins++;
                }
            }
            max_wins_for_this_t0 = std::max(max_wins_for_this_t0, current_p_wins);
        }

        total_prob += static_cast<double>(max_wins_for_this_t0) / possible_k_values.size();
    }

    std::cout << std::fixed << std::setprecision(15) << total_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    std::vector<int> degree(26, 0);
    std::vector<bool> in_s(26, false);

    for (char c : s) {
        in_s[c - 'a'] = true;
    }

    for (size_t i = 0; i < s.length() - 1; ++i) {
        char u = s[i];
        char v = s[i+1];

        if (adj[u - 'a'].find(v) == adj[u - 'a'].end()) {
            adj[u - 'a'].insert(v);
            adj[v - 'a'].insert(u);
            degree[u - 'a']++;
            degree[v - 'a']++;
        }
    }

    for (int i = 0; i < 26; ++i) {
        if (degree[i] > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::vector<bool> visited(26, false);

    // Find a starting point for a chain
    int start_node = -1;
    for (int i = 0; i < 26; ++i) {
        if (in_s[i] && degree[i] == 1) {
            start_node = i;
            break;
        }
    }

    // If no node with degree 1 is found, it means all nodes in 's' have degree 0 or 2.
    // If all nodes have degree 0, s must be empty or length 1.
    // If all nodes have degree 2, it means there's a cycle.
    // The problem guarantees s is not empty.
    // If s has length 1, start_node will be -1, but in_s[s[0]-'a'] will be true.
    // If s has length > 1 and all nodes have degree 2, it's a cycle.
    // A cycle cannot be represented on a linear keyboard.
    // Example: abcda -> a-b-c-d-a. a needs 2 neighbors (b,d). b needs 2 (a,c). c needs 2 (b,d). d needs 2 (c,a).
    // This forms a cycle. A linear keyboard cannot represent a cycle.
    // So, if all in_s nodes have degree 2, it's impossible.
    // Exception: if s has length 1, say "a", then degree[a] is 0. This is a valid start.
    // The logic below handles this: if start_node is -1, it tries to pick any in_s node.
    // If it picks an in_s node with degree 2, it will try to build a chain.
    // If it successfully builds a chain that includes all in_s nodes, it's fine.
    // But if it's a cycle, it will eventually return to the start node and try to add a third neighbor, which is caught by degree check.
    // Or, it will try to add a node already visited, which is also handled.

    if (start_node == -1) { // No degree 1 node found among characters in s
        // This can happen if s has length 1 (e.g., "a"), or if all characters in s form a cycle (e.g., "abcda").
        // For "a", degree[0] is 0.
        // For "abcda", degree[a,b,c,d] are all 2.
        for (int i = 0; i < 26; ++i) {
            if (in_s[i]) { // Pick any character from s
                start_node = i;
                break;
            }
        }
    }

    if (start_node != -1) {
        int current = start_node;
        while (current != -1 && !visited[current]) {
            layout += (char)('a' + current);
            visited[current] = true;

            int next_node = -1;
            for (char neighbor_char : adj[current]) {
                int neighbor_idx = neighbor_char - 'a';
                if (!visited[neighbor_idx]) {
                    next_node = neighbor_idx;
                    break;
                }
            }
            current = next_node;
        }
    }

    // Check if all characters from s are included in the layout
    for (int i = 0; i < 26; ++i) {
        if (in_s[i] && !visited[i]) {
            std::cout << "NO\n"; // A cycle was detected or disconnected components within 's'
            return;
        }
    }

    // Add remaining characters not in s
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            layout += (char)('a' + i);
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

