void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_diff = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_diff++;
        } else {
            initial_diff--;
        }
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // diff_L[i] = (count of 1s - count of 2s) in jars 1 to i
    std::vector<int> diff_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_L[i + 1] = diff_L[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right side (jars n+1 to 2n)
    // diff_R[i] = (count of 1s - count of 2s) in jars i to 2n
    // We store this as diff_R_from_n_plus_1[k] = (count of 1s - count of 2s) in jars n+1 to n+k
    std::vector<int> diff_R_from_n_plus_1(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_R_from_n_plus_1[i + 1] = diff_R_from_n_plus_1[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars removed from the left to achieve a certain difference
    // key: difference, value: number of jars removed (index)
    std::map<int, int> left_diff_to_removed_count;
    for (int i = 0; i <= n; ++i) {
        // diff_L[i] is the difference if we keep jars i+1 to n on the left side.
        // This means we removed 'i' jars from the left (jars 1 to i).
        // The difference of the *removed* jars is diff_L[i].
        // The difference of the *remaining* jars on the left is (initial_diff_left - diff_L[i]).
        // No, this is simpler.
        // If we remove 'i' jars from the left (jars 1 to i), the difference of these removed jars is diff_L[i].
        // We want to find the minimum 'i' for each possible diff_L[i].
        if (left_diff_to_removed_count.find(diff_L[i]) == left_diff_to_removed_count.end()) {
            left_diff_to_removed_count[diff_L[i]] = i;
        }
    }

    int min_removed_jars = 2 * n; // Initialize with max possible

    // Iterate through possible number of jars removed from the right side
    for (int j = 0; j <= n; ++j) {
        // diff_R_from_n_plus_1[j] is the difference of jars n+1 to n+j.
        // These are the 'j' jars removed from the right.
        // The total difference of all removed jars would be diff_L[i] + diff_R_from_n_plus_1[j].
        // We want the remaining jars to have a difference of 0.
        // This means the sum of differences of removed jars must be equal to the initial_diff.
        // So, diff_L[i] + diff_R_from_n_plus_1[j] = initial_diff.
        // We need to find if (initial_diff - diff_R_from_n_plus_1[j]) exists in left_diff_to_removed_count.

        int target_diff_from_left_removed = initial_diff - diff_R_from_n_plus_1[j];

        if (left_diff_to_removed_count.count(target_diff_from_left_removed)) {
            int i = left_diff_to_removed_count[target_diff_from_left_removed];
            min_removed_jars = std::min(min_removed_jars, i + j);
        }
    }

    std::cout << min_removed_jars << std::endl;
}

