long long binToDec(const std::string& s, int start, int end) {
    long long val = 0;
    long long power = 1;
    for (int i = end; i >= start; --i) {
        if (s[i] == '1') {
            val += power;
        }
        if (i > start && power > 2000000000000000000LL / 2) { // Prevent overflow for power
            return 2000000000000000000LL; // Return a value larger than any possible length
        }
        power *= 2;
    }
    return val;
}

