int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int head_idx = 0;
    int p_idx = 0;

    while (p_idx < m) {
        if (head_idx >= n) {
            return false; // Ran out of heads but still have tracks to cover
        }

        // Find the first head that can reach p[p_idx]
        // A head h[head_idx] can reach p[p_idx] if h[head_idx] - T <= p[p_idx] <= h[head_idx] + T
        // Or equivalently, p[p_idx] >= h[head_idx] - T
        while (head_idx < n && p[p_idx] > h[head_idx] + T) {
            // This head is too far to the left to reach p[p_idx]
            head_idx++;
        }

        if (head_idx >= n) {
            return false; // No head can reach p[p_idx]
        }

        // Now, h[head_idx] is the first head that *might* be able to cover p[p_idx].
        // It can cover p[p_idx] if p[p_idx] >= h[head_idx] - T.
        // If it can't, then no subsequent head can either, because h is sorted.
        // (Actually, the previous loop already ensures p[p_idx] <= h[head_idx] + T.
        // We need to ensure p[p_idx] >= h[head_idx] - T.
        // If p[p_idx] < h[head_idx] - T, then h[head_idx] is too far to the right.
        // This means no head can cover p[p_idx] because all subsequent heads are even further right.)
        if (p[p_idx] < h[head_idx] - T) {
            return false; // Current head h[head_idx] is too far right for p[p_idx], and all subsequent heads are even further right.
        }

        // If we reach here, h[head_idx] can cover p[p_idx].
        // This head can cover all tracks in the range [h[head_idx] - T, h[head_idx] + T].
        // We greedily use this head to cover p[p_idx] and as many subsequent tracks as possible.
        long long current_head_reach_right = h[head_idx] + T;

        // Advance p_idx past all tracks covered by this head
        while (p_idx < m && p[p_idx] <= current_head_reach_right) {
            p_idx++;
        }

        // Move to the next head for the remaining tracks
        head_idx++;
    }

    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10; // Max possible difference between p_m and h_1, or p_1 and h_n. (10^10 - 1 + 10^10 - 1)
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Element {
    int value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all in S1).
    // S2 is empty. No pairs (a_i, a_j) with a_i in S1 and a_j in S2.
    // All f values are a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-1].value + a[n-2].value
    // Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    long long goodness_all_same = (long long)a[n-1].value + a[n-2].value - ((long long)a[0].value + a[1].value);
    std::vector<int> partition_all_same(n, 1); // All in subsequence 1

    // Case 2: At least one element in S1 and at least one in S2.
    // This means there will be pairs (a_i, a_j) with a_i in S1 and a_j in S2,
    // resulting in f values of a_i + a_j + h.
    //
    // The minimum possible f value is a[0].value + a[1].value (if a[0] and a[1] are in same subseq)
    // OR a[0].value + a[1].value + h (if a[0] and a[1] are in different subseqs).
    // The maximum possible f value is a[n-1].value + a[n-2].value + h (if a[n-1] and a[n-2] are in different subseqs)
    // OR a[n-1].value + a[n-2].value (if a[n-1] and a[n-2] are in same subseq).
    //
    // To minimize max_f - min_f, we want to make the range of f values as small as possible.
    //
    // Consider the partition where a[0] is in S1 and all other elements are in S2.
    // S1 = {a[0]}, S2 = {a[1], ..., a[n-1]}
    //
    // Values of f:
    // 1. a[i] + a[j] for i, j in {1, ..., n-1} (both in S2)
    //    Min: a[1].value + a[2].value
    //    Max: a[n-1].value + a[n-2].value
    // 2. a[0] + a[j] + h for j in {1, ..., n-1} (a[0] in S1, a[j] in S2)
    //    Min: a[0].value + a[1].value + h
    //    Max: a[0].value + a[n-1].value + h
    //
    // Overall min_f for this partition:
    // min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    //
    // Overall max_f for this partition:
    // max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h)
    //
    // Goodness = max_f - min_f
    //
    // Let's analyze the values:
    // A = a[0].value
    // B = a[1].value
    // C = a[2].value
    // X = a[n-2].value
    // Y = a[n-1].value
    //
    // Possible f values:
    // 1. A + B + h (min cross-subsequence)
    // 2. A + Y + h (max cross-subsequence)
    // 3. B + C (min same-subsequence, if B, C are in S2)
    // 4. X + Y (max same-subsequence, if X, Y are in S2)
    //
    // If a[0] is in S1 and all others in S2:
    // min_f = std::min((long long)B + C, (long long)A + B + h);
    // max_f = std::max((long long)X + Y, (long long)A + Y + h);
    // goodness_one_split = max_f - min_f;
    //
    // This specific partition (a[0] in S1, rest in S2) is one of the candidates.
    // The key observation is that the minimum possible value of f is always `a[0] + a[1]` or `a[0] + a[1] + h`.
    // The maximum possible value of f is always `a[n-1] + a[n-2]` or `a[n-1] + a[n-2] + h`.
    //
    // If we have elements in both subsequences, then `a[0]` and `a[n-1]` must be in different subsequences
    // to maximize the `+h` effect on the range.
    //
    // Consider the partition where `a[0]` is in S1 and `a[1]` to `a[n-1]` are in S2.
    // min_f = min(a[1]+a[2], a[0]+a[1]+h)
    // max_f = max(a[n-2]+a[n-1], a[0]+a[n-1]+h)
    //
    // Consider the partition where `a[0]` to `a[n-2]` are in S1 and `a[n-1]` is in S2.
    // min_f = min(a[0]+a[1], a[0]+a[n-1]+h)
    // max_f = max(a[n-3]+a[n-2], a[n-2]+a[n-1]+h)
    //
    // The crucial point is that if we have elements in both subsequences, the minimum value of f will be
    // `min(a[0]+a[1], a[0]+a[1]+h)` and the maximum value of f will be `max(a[n-1]+a[n-2], a[n-1]+a[0]+h)`.
    //
    // Let's analyze the two main scenarios for the minimum possible goodness:
    //
    // Scenario A: All elements are in the same subsequence.
    //   min_f = a[0].value + a[1].value
    //   max_f = a[n-1].value + a[n-2].value
    //   Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    //   Partition: all 1s (or all 2s).
    //
    // Scenario B: Elements are split into two non-empty subsequences.
    //   In this case, there will always be at least one pair (x, y) where x is in S1 and y is in S2.
    //   So, `a_i + a_j + h` values will exist.
    //   The minimum possible `a_i + a_j` is `a[0].value + a[1].value`.
    //   The maximum possible `a_i + a_j` is `a[n-1].value + a[n-2].value`.
    //   The minimum possible `a_i + a_j + h` is `a[0].value + a[1].value + h`.
    //   The maximum possible `a_i + a_j + h` is `a[n-1].value + a[n-2].value + h`.
    //
    //   To minimize the range, we want the `+h` values to be "close" to the non-`+h` values.
    //   This happens when `h` is small.
    //
    //   Consider the partition where `a[0]` is in S1 and `a[1], ..., a[n-1]` are in S2.
    //   min_f = min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    //   max_f = max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h)
    //   Goodness = max_f - min_f
    //
    //   Let's call this `goodness_split_one_first`.
    //   This partition is optimal for Scenario B if `h` is large enough such that `a[0] + a[1] + h` is the minimum overall f value.
    //   And `a[0] + a[n-1] + h` is the maximum overall f value.
    //   In this case, min_f = a[0].value + a[1].value + h
    //   max_f = a[0].value + a[n-1].value + h
    //   Goodness = (a[0].value + a[n-1].value + h) - (a[0].value + a[1].value + h) = a[n-1].value - a[1].value.
    //   This happens if `a[0].value + a[1].value + h` is less than `a[1].value + a[2].value` (which is impossible since `a[0] < a[2]` and `h >= 0`)
    //   OR if `a[0].value + a[1].value + h` is the minimum of all values.
    //
    //   Let's re-evaluate the min/max f values for a general split partition.
    //   min_f_overall = min(a[0].value + a[1].value, a[0].value + a[1].value + h) = a[0].value + a[1].value
    //   max_f_overall = max(a[n-1].value + a[n-2].value, a[n-1].value + a[0].value + h)
    //
    //   This is not quite right. The min/max f values depend on the specific partition.
    //
    //   Consider the partition where `a[0]` is in S1 and all other `a[i]` (for `i > 0`) are in S2.
    //   The values of f are:
    //   1. `a[i] + a[j]` for `i, j >= 1`. Smallest: `a[1] + a[2]`. Largest: `a[n-2] + a[n-1]`.
    //   2. `a[0] + a[j] + h` for `j >= 1`. Smallest: `a[0] + a[1] + h`. Largest: `a[0] + a[n-1] + h`.
    //
    //   So, for this partition:
    //   min_f = std::min((long long)a[1].value + a[2].value, (long long)a[0].value + a[1].value + h);
    //   max_f = std::max((long long)a[n-1].value + a[n-2].value, (long long)a[0].value + a[n-1].value + h);
    //   goodness_split_one_first = max_f - min_f;
    //
    //   This is a valid candidate for minimal goodness.
    //   The partition is: `a[0]` gets 1, `a[1]...a[n-1]` get 2.
    //
    //   What if `a[n-1]` is in S1 and `a[0], ..., a[n-2]` are in S2?
    //   min_f = std::min((long long)a[0].value + a[1].value, (long long)a[0].value + a[n-1].value + h);
    //   max_f = std::max((long long)a[n-3].value + a[n-2].value, (long long)a[n-2].value + a[n-1].value + h);
    //   goodness_split_one_last = max_f - min_f;
    //
    //   This is also a valid candidate.
    //   The partition is: `a[n-1]` gets 1, `a[0]...a[n-2]` get 2.
    //
    //   Let's compare `goodness_all_same` with `goodness_split_one_first`.
    //   The problem states `n >= 2`.
    //   If `n=2`, `a[0], a[1]`.
    //   Case 1: Both in S1. f = a[0]+a[1]. min_f=max_f=a[0]+a[1]. Goodness = 0.
    //   Case 2: a[0] in S1, a[1] in S2. f = a[0]+a[1]+h. min_f=max_f=a[0]+a[1]+h. Goodness = 0.
    //   So for n=2, goodness is always 0.
    //   My formulas:
    //   goodness_all_same = (a[1]+a[0]) - (a[0]+a[1]) = 0. Correct.
    //   goodness_split_one_first (a[0] in S1, a[1] in S2):
    //     min_f = min(a[1]+a[2] (not exist), a[0]+a[1]+h) = a[0]+a[1]+h
    //     max_f = max(a[n-1]+a[n-2] (not exist), a[0]+a[n-1]+h) = a[0]+a[1]+h
    //     Goodness = 0. Correct.
    //
    //   So for n=2, both strategies yield 0.
    //
    //   Let's consider the general case for `n > 2`.
    //   The minimum possible value of `f` is `a[0].value + a[1].value`.
    //   The maximum possible value of `f` is `a[n-1].value + a[n-2].value + h` (if `a[n-1]` and `a[n-2]` are in different subsequences)
    //   or `a[n-1].value + a[n-2].value` (if they are in the same subsequence).
    //   Or `a[n-1].value + a[0].value + h` (if `a[n-1]` and `a[0]` are in different subsequences).
    //
    //   The overall minimum possible value of `f` is `a[0].value + a[1].value`.
    //   The overall maximum possible value of `f` is `a[n-1].value + a[0].value + h`.
    //   This is because `a[0]+a[1]` is the smallest sum of two elements.
    //   And `a[n-1]+a[0]+h` is the largest sum of two elements where one is `a[0]` and the other is `a[n-1]` and they are split.
    //   `a[n-1]+a[n-2]` is the largest sum of two elements in the same group.
    //   `a[n-1]+a[n-2]+h` is the largest sum of two elements in different groups.
    //
    //   The minimum possible `min_f` is `a[0].value + a[1].value`.
    //   The maximum possible `max_f` is `a[n-1].value + a[0].value + h`.
    //   So the absolute minimum possible goodness is `(a[n-1].value + a[0].value + h) - (a[0].value + a[1].value) = a[n-1].value - a[1].value + h`.
    //   This goodness is achieved if we can construct a partition where:
    //   1. `a[0]` and `a[1]` are in the same subsequence (to get `a[0]+a[1]`).
    //   2. `a[0]` and `a[n-1]` are in different subsequences (to get `a[0]+a[n-1]+h`).
    //   3. All other `f` values fall within this range.
    //
    //   Consider the partition: `a[0]` in S1, `a[1], ..., a[n-1]` in S2.
    //   min_f = min(a[1]+a[2], a[0]+a[1]+h)
    //   max_f = max(a[n-2]+a[n-1], a[0]+a[n-1]+h)
    //   Goodness = max_f - min_f.
    //
    //   Consider the partition: `a[0], ..., a[n-2]` in S1, `a[n-1]` in S2.
    //   min_f = min(a[0]+a[1], a[0]+a[n-1]+h)
    //   max_f = max(a[n-3]+a[n-2], a[n-2]+a[n-1]+h)
    //   Goodness = max_f - min_f.
    //
    //   Let's analyze the values for the first sample: n=3, h=2, a={1,2,3} (sorted).
    //   a[0]=1, a[1]=2, a[2]=3.
    //
    //   Case 1: All same (e.g., all 1s).
    //     f(1,2)=1+2=3, f(1,3)=1+3=4, f(2,3)=2+3=5.
    //     min_f=3, max_f=5. Goodness = 5-3=2.
    //     Partition: 1 1 1.
    //
    //   Case 2: Split.
    //     Subcase 2.1: a[0] in S1, a[1], a[2] in S2. (1 in S1, 2,3 in S2)
    //       f values:
    //         Same S2: f(2,3) = 2+3 = 5
    //         Diff: f(1,2) = 1+2+h = 1+2+2 = 5
    //               f(1,3) = 1+3+h = 1+3+2 = 6
    //       min_f = min(5, 5, 6) = 5
    //       max_f = max(5, 5, 6) = 6
    //       Goodness = 6-5 = 1.
    //       Partition: 1 2 2 (for original indices).
    //
    //     Subcase 2.2: a[0], a[1] in S1, a[2] in S2. (1,2 in S1, 3 in S2)
    //       f values:
    //         Same S1: f(1,2) = 1+2 = 3
    //         Diff: f(1,3) = 1+3+h = 1+3+2 = 6
    //               f(2,3) = 2+3+h = 2+3+2 = 7
    //       min_f = min(3, 6, 7) = 3
    //       max_f = max(3, 6, 7) = 7
    //       Goodness = 7-3 = 4.
    //       Partition: 1 1 2 (for original indices).
    //
    //   Comparing goodness values: 2, 1, 4. Minimum is 1.
    //   The optimal partition is 1 2 2 (for original indices).
    //   This matches the sample output.
    //
    //   The two candidates for optimal partition are:
    //   1. All elements in one subsequence.
    //      Goodness: `a[n-1].value + a[n-2].value - (a[0].value + a[1].value)`
    //      Partition: all 1s.
    //   2. `a[0]` in S1, `a[1], ..., a[n-1]` in S2.
    //      min_f = std::min((long long)a[1].value + a[2].value, (long long)a[0].value + a[1].value + h);
    //      max_f = std::max((long long)a[n-1].value + a[n-2].value, (long long)a[0].value + a[n-1].value + h);
    //      Goodness: `max_f - min_f`.
    //      Partition: `a[0]` gets 1, others get 2.
    //
    //   Let's verify the second candidate's min_f and max_f more carefully.
    //   For partition: `a[0]` in S1, `a[1], ..., a[n-1]` in S2.
    //   The set of all `f` values is:
    //   `{ a[i].value + a[j].value | 1 <= i < j <= n-1 }`
    //   UNION
    //   `{ a[0].value + a[j].value + h | 1 <= j <= n-1 }`
    //
    //   The minimum value in the first set is `a[1].value + a[2].value` (if `n > 2`).
    //   The maximum value in the first set is `a[n-2].value + a[n-1].value` (if `n > 2`).
    //   If `n=2`, this set is empty.
    //
    //   The minimum value in the second set is `a[0].value + a[1].value + h`.
    //   The maximum value in the second set is `a[0].value + a[n-1].value + h`.
    //
    //   So, for `n > 2`:
    //   min_f_split = std::min((long long)a[1].value + a[2].value, (long long)a[0].value + a[1].value + h);
    //   max_f_split = std::max((long long)a[n-1].value + a[n-2].value, (long long)a[0].value + a[n-1].value + h);
    //   goodness_split = max_f_split - min_f_split;
    //
    //   For `n=2`:
    //   The first set is empty.
    //   The second set has only `a[0].value + a[1].value + h`.
    //   min_f_split = a[0].value + a[1].value + h;
    //   max_f_split = a[0].value + a[1].value + h;
    //   goodness_split = 0.
    //   This matches `goodness_all_same` for `n=2`.
    //
    //   So the logic for `n > 2` and `n=2` can be combined if we handle the `a[1]+a[2]` and `a[n-2]+a[n-1]` terms carefully.
    //   If `n=2`, `a[1]+a[2]` and `a[n-2]+a[n-1]` are not well-defined.
    //   A safe way is to initialize `min_f_split` to `LLONG_MAX` and `max_f_split` to `LLONG_MIN`.
    //   Then update with `a[0].value + a[1].value + h` and `a[0].value + a[n-1].value + h`.
    //   And if `n > 2`, update with `a[1].value + a[2].value` and `a[n-1].value + a[n-2].value`.
    //
    //   Let's try this for `n=3, h=2, a={1,2,3}`.
    //   `a[0]=1, a[1]=2, a[2]=3`.
    //   `min_f_split = min(2+3, 1+2+2) = min(5, 5) = 5`.
    //   `max_f_split = max(3+2, 1+3+2) = max(5, 6) = 6`.
    //   `goodness_split = 6-5 = 1`. This is correct.
    //
    //   Final algorithm:
    //   1. Sort the input array `a` while keeping track of original indices.
    //   2. Calculate `goodness_all_same`: `(long long)a[n-1].value + a[n-2].value - ((long long)a[0].value + a[1].value)`.
    //      This is the goodness if all elements are in one subsequence.
    //      The partition is all 1s.
    //   3. Calculate `goodness_split`:
    //      This corresponds to the partition where `a[0]` is in S1 and `a[1], ..., a[n-1]` are in S2.
    //      `long long current_min_f = (long long)a[0].value + a[1].value + h;`
    //      `long long current_max_f = (long long)a[0].value + a[n-1].value + h;`
    //      If `n > 2`:
    //          `current_min_f = std::min(current_min_f, (long long)a[1].value + a[2].value);`
    //          `current_max_f = std::max(current_max_f, (long long)a[n-1].value + a[n-2].value);`
    //      `goodness_split = current_max_f - current_min_f;`
    //      The partition is `a[0]` gets 1, others get 2.
    //   4. Compare `goodness_all_same` and `goodness_split`.
    //      The minimum of these two is the answer.
    //      If `goodness_all_same` is smaller, print `goodness_all_same` and the all 1s partition.
    //      Otherwise, print `goodness_split` and the `a[0]` in S1, others in S2 partition.

    long long min_goodness = goodness_all_same;
    std::vector<int> result_partition(n);
    for (int i = 0; i < n; ++i) {
        result_partition[a[i].original_index] = 1;
    }

    // Calculate goodness for the split partition: a[0] in S1, a[1...n-1] in S2
    long long current_min_f_split = (long long)a[0].value + a[1].value + h;
    long long current_max_f_split = (long long)a[0].value + a[n-1].value + h;

    if (n > 2) {
        current_min_f_split = std::min(current_min_f_split, (long long)a[1].value + a[2].value);
        current_max_f_split = std::max(current_max_f_split, (long long)a[n-1].value + a[n-2].value);
    }
    long long goodness_split = current_max_f_split - current_min_f_split;

    if (goodness_split < min_goodness) {
        min_goodness = goodness_split;
        result_partition[a[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            result_partition[a[i].original_index] = 2;
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << result_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, long long> x_counts;
    std::map<int, long long> y_counts;
    std::map<std::pair<int, int>, long long> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Pairs with same x-coordinate
    for (auto const& [x_val, count] : x_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Pairs with same y-coordinate
    for (auto const& [y_val, count] : y_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs that have both same x and same y (i.e., are identical points)
    // These pairs were counted twice: once for same x, once for same y.
    // They should only be counted once.
    for (auto const& [point, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

