#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    int current_a1 = a[0];
    int remaining_days = d;

    for (int i = 1; i < n; ++i) {
        int pile_idx = i; // 0-indexed pile index
        int haybales_in_pile = a[pile_idx];
        int cost_per_haybale = pile_idx; // cost to move to pile 0 (1-indexed pile 1)

        if (cost_per_haybale == 0) { // Should not happen for i > 0
            continue;
        }

        // Calculate how many haybales can be moved from this pile
        // based on remaining days
        int max_haybales_movable_by_days = remaining_days / cost_per_haybale;

        // The actual number of haybales to move is the minimum of
        // haybales available in the pile and haybales that can be moved
        // within the remaining days.
        int haybales_to_move = std::min(haybales_in_pile, max_haybales_movable_by_days);

        current_a1 += haybales_to_move;
        remaining_days -= haybales_to_move * cost_per_haybale;

        if (remaining_days <= 0) {
            break; // No more days left
        }
    }

    std::cout << current_a1 << std::endl;
}

