#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_suffix = a[n - 1]; // Initialize with the last element

    // Iterate from right to left, starting from the second to last element
    // (index n-2) down to the first element (index 0).
    // For each element a[i], we compare it with the minimum price found
    // so far in the suffix a[i+1...n-1].
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix, it means a[i] is
            // a new minimum for the suffix a[i...n-1].
            min_suffix = a[i];
        }
    }

    std::cout << bad_prices_count << "\n";
}

