int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        // The string s has length n. Cells are 0, 1, ..., n, n+1.
        // s[i] corresponds to cell i+1.
        // The frog starts at cell 0.
        // The target is cell n+1.
        // We need to find the minimum d.

        // The frog can only jump right from cell 0.
        // If s[i-1] is 'R', frog at cell i can jump right.
        // If s[i-1] is 'L', frog at cell i can jump left.

        // To reach n+1, the frog must always make progress towards n+1.
        // If the frog lands on an 'L' cell, it must jump left. This is bad.
        // The only way to avoid 'L' cells is to jump over them.
        // Consider the sequence of 'R' cells.
        // The frog starts at 0. It needs to reach n+1.
        // It can jump from 0 to any cell in [1, d].
        // If it lands on an 'R' cell (say cell i), it can jump to [i+1, min(n+1, i+d)].
        // If it lands on an 'L' cell (say cell i), it can jump to [max(0, i-d), i-1].
        // This means if it lands on an 'L' cell, it moves away from n+1.
        // To reach n+1, the frog must never land on an 'L' cell, or if it does, it must be able to jump back to an 'R' cell or directly to n+1.

        // The problem guarantees it's always possible.
        // The critical observation is that the frog must always be able to jump from its current position (or 0) to an 'R' cell or directly to n+1.
        // If the frog is at cell `current_pos`, and it needs to reach `target_pos`, it needs `d >= target_pos - current_pos`.
        // The frog wants to avoid 'L' cells.
        // This means the frog must be able to jump from 0, over any sequence of 'L' cells, to the next 'R' cell or to n+1.
        // Or, if there are no 'R' cells, it must jump from 0 directly to n+1.

        // Let's find the positions of all 'R' characters.
        // The string s has length n. Cells are 1 to n.
        // s[i] is for cell i+1.
        // So, if s[k] is 'R', it means cell k+1 is an 'R' cell.
        // We can consider cell 0 as an 'R' cell (always jump right).
        // We can consider cell n+1 as an 'R' cell (the destination).

        std::vector<int> r_positions;
        r_positions.push_back(0); // Start at cell 0
        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                r_positions.push_back(i + 1); // Cell i+1 is an 'R' cell
            }
        }
        r_positions.push_back(s.length() + 1); // Target cell n+1

        int max_gap = 0;
        for (size_t i = 0; i < r_positions.size() - 1; ++i) {
            // The frog must be able to jump from r_positions[i] to r_positions[i+1].
            // The cells between r_positions[i] and r_positions[i+1] (exclusive) are all 'L' cells.
            // The frog must jump over all these 'L' cells.
            // The distance required for this jump is r_positions[i+1] - r_positions[i].
            max_gap = std::max(max_gap, r_positions[i+1] - r_positions[i]);
        }
        std::cout << max_gap << "\n";
    }
    return 0;
}

