#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1]. It's always beautiful.
        // For m > 1, we extend the segment from m-1 to include m.
        // The segment for m-1 was [min_idx, max_idx] containing 1..m-1.
        // To include m, we must extend this segment to cover pos[m].
        // So the new segment will be [min(current_min_idx, pos[m]), max(current_max_idx, pos[m])].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number m is beautiful if the segment [current_min_idx, current_max_idx]
        // contains exactly numbers 1 to m.
        // This means its length must be m.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

