        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // d^2 - 4d >= 0 is true for d >= 4
            // a = (d + sqrt(d^2 - 4d)) / 2
            // b = (d - sqrt(d^2 - 4d)) / 2
            // We need a, b >= 0.
            // Since d >= 4, sqrt(d^2 - 4d) is real.
            // d - sqrt(d^2 - 4d) >= 0?
            // d >= sqrt(d^2 - 4d)
            // d^2 >= d^2 - 4d (since d >= 0, both sides are non-negative)
            // 0 >= -4d
            // 4d >= 0
            // This is true for d >= 0.
            // So both a and b will be non-negative.

            double discriminant = d * d - 4.0 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            // Ensure a >= b for consistent output, though problem doesn't strictly require it.
            // The problem statement implies a and b are interchangeable.
