// Function to determine if a box can be the special box
// Parameters:
//   a, b, c, d: initial counts of toys in boxes 1, 2, 3, 4
//   target_box: the box we are checking (1, 2, 3, or 4)
// Returns: true if target_box can be the special box, false otherwise
bool can_be_special(long long a, long long b, long long c, long long d, int target_box) {
    long long total_toys = a + b + c + d;

    if (total_toys == 0) { // Should not happen based on constraints A+B+C+D > 0
        return false;
    }
    if (total_toys == 1) {
        if (a == 1 && target_box == 1) return true;
        if (b == 1 && target_box == 2) return true;
        if (c == 1 && target_box == 3) return true;
        if (d == 1 && target_box == 4) return true;
        return false;
    }

    // Parity of negative numbers
    long long initial_neg_count = a + b;
    bool initial_neg_parity_odd = (initial_neg_count % 2 != 0);

    // Case 1: Target Box 1 (Negative, magnitude >= 1)
    if (target_box == 1) {
        // Final result must be negative, so initial_neg_parity_odd must be true.
        if (!initial_neg_parity_odd) return false;

        // To get magnitude >= 1:
        // We need at least one toy with magnitude >= 1 (from Box 1 or Box 4)
        // OR we need to be able to generate one.
        // If there are no toys in Box 1 or Box 4 initially, we can only get magnitude >= 1
        // if we multiply enough toys from Box 2 and Box 3.
        // This is impossible if all initial toys are in Box 2 and Box 3, as their product will always be < 1.
        // So, if a+d == 0, it's impossible to get magnitude >= 1.
        if (a + d == 0) return false;

        // If there are toys in Box 1 or Box 4, we can always arrange multiplications
        // to keep a magnitude >= 1 until the end, as long as we have at least one such toy.
        // For example, always multiply a large magnitude toy with another toy.
        // If the other toy is from Box 2 or Box 3, the magnitude might decrease but can be kept >= 1.
        // If the other toy is from Box 1 or Box 4, magnitude will stay >= 1.
        // The only way to guarantee magnitude < 1 is if all toys with magnitude >= 1 are multiplied
        // by toys with magnitude < 1 in such a way that all intermediate products become < 1.
        // However, we can always choose to multiply two toys with magnitude >= 1 if available,
        // or multiply a toy with magnitude >= 1 with a toy from Box 2/3 and then multiply that
        // with another toy from Box 2/3 to reduce its magnitude.
        // The crucial part is that we can *choose* the order.
        // If a+d > 0, we can always ensure the final magnitude is >= 1.
        // For example, keep one toy from Box 1 or Box 4 aside. Multiply all other toys.
        // If the product of others is P, then multiply P with the kept toy.
        // If P has magnitude < 1, and the kept toy has magnitude >= 1, the final product can be < 1 or >= 1.
        // But we can also multiply the kept toy with another toy from Box 1/4 if available,
        // or with a toy from Box 2/3 to keep its magnitude large.
        // The problem states "takes two different toys randomly". This implies we can't control the choice.
        // However, the question is "which boxes *can* be the special box", implying existence of *some* sequence.
        // So, we assume we can choose the sequence.
        // If a+d > 0, we can always ensure the final magnitude is >= 1.
        // Example: If we have one toy with value 10, and many toys with value 0.1.
        // We can multiply 10 * 0.1 = 1. Then 1 * 0.1 = 0.1.
        // Or we can multiply all 0.1s together first, getting a very small number. Then multiply by 10.
        // If we want magnitude >= 1, we need to ensure that the last multiplication involves a toy
        // that either has magnitude >= 1, or is formed by multiplying two toys with magnitude >= 1.
        // If a+d > 0, we can always ensure the final magnitude is >= 1.
        // Consider the product of all toys. If it has magnitude >= 1, then Box 1 or Box 4 is possible.
        // If it has magnitude < 1, then Box 2 or Box 3 is possible.
        // The problem is about *existence* of a sequence.
        // If a+d > 0, we can always ensure the final magnitude is >= 1.
        // We can always keep one toy from Box 1 or Box 4 until the very last step.
        // Let this toy be $X$ with $|X| \ge 1$.
        // Let $P$ be the product of all other $N-1$ toys.
        // The final product is $X \cdot P$.
        // If $P$ has magnitude < 1, then $|X \cdot P|$ can be < 1 or >= 1.
        // If $P$ has magnitude >= 1, then $|X \cdot P|$ is >= 1.
        // The crucial part is that we can choose the *values* of the toys.
        // If a+d > 0, we can pick values such that the final product has magnitude >= 1.
        // For example, if we have one toy in Box 4 (value 10) and many in Box 2 (value -0.1).
        // We can choose to multiply all -0.1s first, resulting in a small positive or negative number.
        // Then multiply by 10. The final magnitude will be small.
        // But we can also choose the values.
        // If a+d > 0, we can set one toy to a very large value (e.g., 1000) and all others to values close to 1.
        // Then the final product will have a large magnitude.
        // So, if a+d > 0, it's possible to get magnitude >= 1.
        return true;
    }

    // Case 2: Target Box 2 (Negative, magnitude < 1)
    if (target_box == 2) {
        // Final result must be negative, so initial_neg_parity_odd must be true.
        if (!initial_neg_parity_odd) return false;

        // To get magnitude < 1:
        // If a+d == 0, all initial toys have magnitude < 1. Their product will always have magnitude < 1.
        // So if a+d == 0, Box 2 is possible (given negative parity).
        if (a + d == 0) return true;

        // If a+d > 0, we have toys with magnitude >= 1.
        // Can we still make the final product have magnitude < 1? Yes.
        // Example: one toy with value 10 (Box 4), one toy with value -0.1 (Box 2).
        // Multiply them: 10 * -0.1 = -1. This is Box 1.
        // But if we have 10 (Box 4), -0.1 (Box 2), -0.1 (Box 2).
        // Sequence 1: (-0.1) * (-0.1) = 0.01 (Box 3). Then 10 * 0.01 = 0.1 (Box 3).
        // Sequence 2: 10 * (-0.1) = -1 (Box 1). Then (-1) * (-0.1) = 0.1 (Box 3).
        // This shows that the final box depends on the sequence.
        // If we want magnitude < 1, we can choose values such that most toys have magnitude < 1,
        // and if there are toys with magnitude >= 1, we can choose them to be close to 1 (e.g., 1.00001).
        // Then, by multiplying them with many small numbers, the final product can be < 1.
        // For example, if we have one toy with value 1.1 (Box 4) and many toys with value 0.1 (Box 3).
        // We can multiply 1.1 * 0.1 * 0.1 * ... to get a small number.
        // So, if initial_neg_parity_odd is true, Box 2 is always possible.
        return true;
    }

    // Case 3: Target Box 3 (Positive, magnitude < 1)
    if (target_box == 3) {
        // Final result must be positive, so initial_neg_parity_odd must be false.
        if (initial_neg_parity_odd) return false;

        // To get magnitude < 1:
        // If a+d == 0, all initial toys have magnitude < 1. Their product will always have magnitude < 1.
        // So if a+d == 0, Box 3 is possible (given positive parity).
        if (a + d == 0) return true;

        // If a+d > 0, we have toys with magnitude >= 1.
        // Can we still make the final product have magnitude < 1? Yes, by choosing values.
        // Similar logic to Box 2. If initial_neg_parity_odd is false, Box 3 is always possible.
        return true;
    }

    // Case 4: Target Box 4 (Positive, magnitude >= 1)
    if (target_box == 4) {
        // Final result must be positive, so initial_neg_parity_odd must be false.
        if (initial_neg_parity_odd) return false;

        // To get magnitude >= 1:
        // Similar logic to Box 1. If a+d == 0, it's impossible to get magnitude >= 1.
        if (a + d == 0) return false;

        // If a+d > 0, we can always ensure the final magnitude is >= 1.
        // Similar logic to Box 1.
        return true;
    }

    return false; // Should not reach here
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        std::cout << (can_be_special(A, B, C, D, 1) ? "Ya" : "Tidak");
        std::cout << " " << (can_be_special(A, B, C, D, 2) ? "Ya" : "Tidak");
        std::cout << " " << (can_be_special(A, B, C, D, 3) ? "Ya" : "Tidak");
        std::cout << " " << (can_be_special(A, B, C, D, 4) ? "Ya" : "Tidak") << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    std::vector<long long> prefix_min_val(n);
    prefix_min_val[0] = 0; // a_1 must be >= 0
    for (int i = 1; i < n; ++i) {
        prefix_min_val[i] = std::max(prefix_min_val[i-1] + 1, 0LL); // a_i must be > a_{i-1}
    }

    std::vector<long long> suffix_min_val(n);
    suffix_min_val[n-1] = 0; // a_n must be >= 0
    for (int i = n - 2; i >= 0; --i) {
        suffix_min_val[i] = std::max(suffix_min_val[i+1] + 1, 0LL); // a_i must be > a_{i+1}
    }

    bool possible = false;
    for (int k = 0; k < n; ++k) { // k is 0-indexed peak position
        // Check if a_k can be the peak
        // For the left side: a_0 < a_1 < ... < a_k
        // This requires a_i >= i for i <= k
        // And a_i must be at least prefix_min_val[i]
        // So, a_i >= prefix_min_val[i] for i <= k
        bool left_ok = true;
        for (int i = 0; i <= k; ++i) {
            if (a[i] < prefix_min_val[i]) {
                left_ok = false;
                break;
            }
        }
        if (!left_ok) continue;

        // For the right side: a_k > a_{k+1} > ... > a_{n-1}
        // This requires a_i >= (n-1-i) for i >= k
        // And a_i must be at least suffix_min_val[i]
        // So, a_i >= suffix_min_val[i] for i >= k
        bool right_ok = true;
        for (int i = k; i < n; ++i) {
            if (a[i] < suffix_min_val[i]) {
                right_ok = false;
                break;
            }
        }
        if (!right_ok) continue;

        // Check the peak condition: a_k must be strictly greater than its neighbors (if they exist)
        // If k=0, only right neighbor: a_0 > a_1
        // If k=n-1, only left neighbor: a_{n-2} < a_{n-1}
        // If 0 < k < n-1: a_{k-1} < a_k > a_{k+1}

        // The conditions a_i >= prefix_min_val[i] and a_i >= suffix_min_val[i]
        // already ensure that we can construct a sequence b_i such that
        // b_i = i for i <= k and b_i = (n-1-i) for i >= k,
        // and b_k = k = (n-1-k) if k is the peak.
        // This means b_k must be at least max(k, n-1-k).
        // And we must have a_k >= max(k, n-1-k).
        // The values prefix_min_val[k] and suffix_min_val[k] already capture this.
        // prefix_min_val[k] = k
        // suffix_min_val[k] = n-1-k
        // So we need a_k >= k AND a_k >= n-1-k.
        // This is equivalent to a_k >= std::max(prefix_min_val[k], suffix_min_val[k]).
        // Since we already checked a_k >= prefix_min_val[k] and a_k >= suffix_min_val[k],
        // this condition is implicitly covered.

        // The only remaining condition is that the peak value must be strictly greater than its neighbors.
        // The construction b_i = i for i <= k and b_i = n-1-i for i >= k
        // ensures b_k = k and b_k = n-1-k.
        // If k is the peak, then b_k must be strictly greater than b_{k-1} (if k>0) and b_{k+1} (if k<n-1).
        // b_{k-1} = k-1, b_k = k. So b_k > b_{k-1} is true.
        // b_{k+1} = n-1-(k+1) = n-k-2, b_k = n-1-k. So b_k > b_{k+1} is true.
        // The only thing we need to ensure is that we can actually make a_k large enough
        // to be the peak.
        // The minimum value for b_k is max(prefix_min_val[k], suffix_min_val[k]).
        // If a_k is greater than or equal to this minimum, we can always set b_k to this minimum.
        // And this minimum value for b_k will satisfy the strict inequalities with its neighbors.
        // For example, if k > 0, b_{k-1} = k-1. b_k = k. k > k-1.
        // If k < n-1, b_{k+1} = n-k-2. b_k = n-k-1. n-k-1 > n-k-2.
        // So, if all individual a_i >= required_min_val[i] conditions are met,
        // then it's possible.

        possible = true;
        break;
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

