        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // Elements to the left of median_idx must be <= s
    // If a[i] > s, we must decrease it to s.
    // If a[i] <= s, it's fine.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Elements to the right of median_idx must be >= s
    // If a[i] < s, we must increase it to s.
    // If a[i] >= s, it's fine.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

