    for (int i = 0; i < n; ++i) { // Pointer for the original positions (the 'a' array elements)
        // We are trying to find an element a[b_ptr] from the sorted array
        // that is strictly greater than a[i] (the element at the current original position).
        // Since both arrays are sorted, if a[b_ptr] > a[i], it's a valid match.
        // We want to use the smallest possible a[b_ptr] to beat a[i] to save larger elements
        // for larger a[i] values later.
        // So, we advance b_ptr until a[b_ptr] > a[i].
        while (b_ptr < n && a[b_ptr] <= a[i]) {
            b_ptr++;
        }
        // If we found such an element, we use it.
        if (b_ptr < n) {
            count++;
            b_ptr++; // Move to the next element in 'b' for the next match
        } else {
            // If b_ptr reaches n, it means all remaining elements in 'b' are
            // less than or equal to a[i], or we've run out of elements in 'b'.
            // No more matches are possible for the current a[i] or subsequent ones.
            break;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

