#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<ElementB> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    std::sort(a_elements.begin(), a_elements.end(), compareA);
    std::sort(b_elements.begin(), b_elements.end(), compareB);

    std::vector<long long> result_a_prime(m);

    // The optimal strategy is to assign the largest A_i to the B_j that results in the largest F value.
    // F(N, K) = N / (K+1).
    // To maximize sum(A_i' / (B_i + 1)), we should pair largest A_i with smallest (B_i + 1).
    // This means largest A_i with smallest B_i.
    // Since both A and B are sorted in ascending order,
    // a_elements[i].value should be paired with b_elements[i].value.
    // However, we need to output the rearranged A array in the original order of B.
    // So, if b_elements[i] was originally at index `idx_b`, then result_a_prime[idx_b] should be a_elements[i].value.

    for (int i = 0; i < m; ++i) {
        result_a_prime[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> is_suffix_perm(n + 1, false);

    // Check for prefix permutations
    std::vector<bool> seen_prefix(n + 1, false);
    int max_prefix = 0;
    bool possible_prefix = true;
    for (int i = 0; i < n; ++i) {
        if (seen_prefix[a[i]]) {
            possible_prefix = false;
        }
        seen_prefix[a[i]] = true;
        max_prefix = std::max(max_prefix, a[i]);
        if (possible_prefix && max_prefix == (i + 1)) {
            is_prefix_perm[i + 1] = true;
        }
    }

    // Check for suffix permutations
    std::vector<bool> seen_suffix(n + 1, false);
    int max_suffix = 0;
    bool possible_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        if (seen_suffix[a[i]]) {
            possible_suffix = false;
        }
        seen_suffix[a[i]] = true;
        max_suffix = std::max(max_suffix, a[i]);
        if (possible_suffix && max_suffix == (n - i)) {
            is_suffix_perm[n - i] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, and l2 must be at least 1, so l1 < n
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

