void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
    // Let X = current_xor_sum
    // Let S = current_sum
    // We want S' = 2 * X'
    //
    // Consider appending two elements: X and S.
    // New XOR sum: X' = X ^ X ^ S = S
    // New sum: S' = S + X + S = 2S + X
    //
    // For the array to be good, we need S' = 2 * X'.
    // So, we need 2S + X = 2 * S.
    // This simplifies to 2S + X = 2S, which means X = 0.
    // This is not generally true.
    //
    // Let's try appending two elements: X and current_sum.
    // Let b1 = current_xor_sum
    // Let b2 = current_sum
    //
    // New XOR sum: X' = current_xor_sum ^ b1 ^ b2 = current_xor_sum ^ current_xor_sum ^ current_sum = current_sum
    // New sum: S' = current_sum + b1 + b2 = current_sum + current_xor_sum + current_sum = 2 * current_sum + current_xor_sum
    //
    // We need S' = 2 * X'.
    // So, we need (2 * current_sum + current_xor_sum) = 2 * (current_sum).
    // This simplifies to 2 * current_sum + current_xor_sum = 2 * current_sum, which implies current_xor_sum = 0.
    // This is only true if current_xor_sum is already 0.
    //
    // The problem states we can append at most 3 elements.
    // Let's try appending two elements: current_xor_sum and current_sum.
    // Let b1 = current_xor_sum
    // Let b2 = current_sum
    //
    // New XOR sum: X_new = current_xor_sum ^ b1 ^ b2 = current_xor_sum ^ current_xor_sum ^ current_sum = current_sum
    // New sum: S_new = current_sum + b1 + b2 = current_sum + current_xor_sum + current_sum = 2 * current_sum + current_xor_sum
    //
    // Now, we have an array with sum S_new and XOR sum X_new.
    // We need S_new = 2 * X_new.
    //
    // If we append these two elements, the new state is:
    // sum = 2 * current_sum + current_xor_sum
    // xor_sum = current_sum
    //
    // Let's check the condition: (2 * current_sum + current_xor_sum) == 2 * (current_sum).
    // This is true if and only if current_xor_sum == 0.
    //
    // So, if current_xor_sum is 0, we can append 0 elements.
    // If current_xor_sum is not 0, we can append two elements: current_xor_sum and current_sum.
    // After appending these two, the new XOR sum is `current_sum` and the new total sum is `2 * current_sum + current_xor_sum`.
    // The condition `S' = 2 * X'` becomes `2 * current_sum + current_xor_sum = 2 * current_sum`.
    // This means `current_xor_sum` must be 0. But we just assumed `current_xor_sum` is not 0.
    // This strategy is flawed.

    // Let's use the property: sum = xor_sum + 2 * (sum_of_pairwise_ANDs)
    // The condition is S' = 2 * X'.
    // This means S' - 2 * X' = 0.
    //
    // Consider appending two elements: X and S.
    // Let X_orig = current_xor_sum
    // Let S_orig = current_sum
    //
    // Append b1 = X_orig.
    // New XOR sum: X_1 = X_orig ^ X_orig = 0.
    // New sum: S_1 = S_orig + X_orig.
    //
    // Now we have an array with sum S_1 and XOR sum X_1 = 0.
    // We need S_1 = 2 * X_1.
    // This means S_orig + X_orig = 2 * 0 = 0.
    // This is only true if S_orig = 0 and X_orig = 0, which is not generally the case.
    //
    // So, after appending X_orig, the XOR sum becomes 0.
    // The sum becomes S_orig + X_orig.
    //
    // Now, we need to append one more element, say `b2`, such that:
    // (S_orig + X_orig + b2) = 2 * (0 ^ b2)
    // (S_orig + X_orig + b2) = 2 * b2
    // S_orig + X_orig = b2
    //
    // So, if we append `X_orig` and then `S_orig + X_orig`, the array becomes good.
    //
    // Let's verify this strategy:
    // Initial state: sum = S_orig, xor_sum = X_orig.
    //
    // Append b1 = X_orig.
    // New sum = S_orig + X_orig.
    // New xor_sum = X_orig ^ X_orig = 0.
    //
    // Append b2 = S_orig + X_orig.
    // Final sum = (S_orig + X_orig) + (S_orig + X_orig) = 2 * (S_orig + X_orig).
    // Final xor_sum = 0 ^ (S_orig + X_orig) = S_orig + X_orig.
    //
    // Check condition: Final sum = 2 * Final xor_sum.
    // 2 * (S_orig + X_orig) = 2 * (S_orig + X_orig).
    // This is always true!
    //
    // So, we can always append two elements: `current_xor_sum` and `current_sum + current_xor_sum`.
    // The problem states we don't have to minimize the number of added elements.
    // If the array is already good, we can output 0 elements.
    // Otherwise, we can output 2 elements.

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl << std::endl;
    } else {
        std::cout << 2 << std::endl;
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
    }
}

