int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // will eventually need to pass this 'b'.
            // Each 'a' passing this 'b' contributes 'count_a' steps
            // (because it creates a new 'b' which also needs to be passed by 'a's).
            // The total steps for this 'b' is 'count_a'.
            // After this 'b' is passed, it effectively doubles the number of 'a's
            // that will interact with 'b's further to the left.
            // This is because 'ab' -> 'bba'. The 'a' moves past, and a new 'b' is created.
            // The 'a' that moved past will then interact with 'b's to its left.
            // The new 'b' created will also interact with 'a's to its left.
            // This is equivalent to saying that each 'a' to the left of this 'b'
            // will effectively "double" its contribution to future 'b's.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' will eventually
            // need to pass all 'b's to its right.
            // It adds 1 to the current count of 'a's that are "active"
            // and will interact with 'b's to their left.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

