int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // 'i' represents the number of items taken from the left (0 to n)
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Calculate energy for items taken from the left
        // These are w[0]...w[i-1]
        long long left_sum = prefix_sum[i];
        current_energy += left_sum * l;

        // Calculate energy for items taken from the right
        // These are w[i]...w[n-1]
        long long right_sum = prefix_sum[n] - prefix_sum[i];
        current_energy += right_sum * r;

        // Calculate penalty
        int num_left = i;
        int num_right = n - i;

        if (num_left > num_right) {
            // More items taken from left.
            // The difference is (num_left - num_right).
            // If num_left - num_right == 1, no penalty.
            // If num_left - num_right > 1, penalty for (num_left - num_right - 1) extra left items.
            current_energy += (long long)(num_left - num_right - 1) * Ql;
        } else if (num_right > num_left) {
            // More items taken from right.
            // The difference is (num_right - num_left).
            // If num_right - num_left == 1, no penalty.
            // If num_right - num_left > 1, penalty for (num_right - num_left - 1) extra right items.
            current_energy += (long long)(num_right - num_left - 1) * Qr;
        }
        // If num_left == num_right, no penalty.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

