        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the longest suffix that is non-increasing
    // This is the rightmost point where the array stops being non-increasing
    // Example: [1, 3, 1, 4, 5, 3, 2]
    // Suffixes:
    // [2] -> non-increasing
    // [3, 2] -> non-increasing
    // [5, 3, 2] -> non-increasing
    // [4, 5, 3, 2] -> NOT non-increasing (4 < 5)
    // So, the suffix starting at index 3 (value 4) is not non-increasing.
    // The longest non-increasing suffix starts at index 4 (value 5).
    // This means elements a[4], a[5], a[6] are 5, 3, 2.
    // The "peak" is at index 4.
    int p = n - 1;
    while (p > 0 && a[p-1] >= a[p]) {
        p--;
    }
    // After this loop, a[p...n-1] is non-increasing.
    // If p=0, the whole array is non-increasing.
    // If p>0, then a[p-1] < a[p].

    // Now, find the longest suffix of a[0...p-1] that is non-decreasing
    // This is the rightmost point where the array stops being non-decreasing
    // Example: [1, 3, 1, 4, 5, 3, 2]
    // p = 4 (a[4]=5)
    // Consider a[0...3] = [1, 3, 1, 4]
    // Suffixes:
    // [4] -> non-decreasing
    // [1, 4] -> non-decreasing
    // [3, 1, 4] -> NOT non-decreasing (3 > 1)
    // So, the suffix starting at index 1 (value 3) is not non-decreasing.
    // The longest non-decreasing suffix of a[0...p-1] starts at index 2 (value 1).
    // This means elements a[2], a[3] are 1, 4.
    // The "valley" is at index 2.
    int q = p; // Start from p, which is the first element of the non-increasing suffix
    while (q > 0 && a[q-1] <= a[q]) {
        q--;
    }
    // After this loop, a[q...p-1] is non-decreasing.
    // If q=0, then a[0...p-1] is non-decreasing.
    // If q>0, then a[q-1] > a[q].

    // The length of the prefix to erase is q.
    std::cout << q << std::endl;
}

