// Function to get prime factors of a number
// Returns a vector of pairs: (prime_factor, exponent)
std::vector<std::pair<long long, int>> get_prime_factors(long long n) {
    std::vector<std::pair<long long, int>> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            int count = 0;
            while (n % i == 0) {
                n /= i;
                count++;
            }
            factors.push_back({i, count});
        }
    }
    if (n > 1) {
        factors.push_back({n, 1});
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that p % x == 0 and x % q != 0.
        // This means x must be p / (some factor of p) such that x is not divisible by q.
        // Or, equivalently, x must be p / (some factor of q) such that x is not divisible by q.
        // More generally, x must be p / k for some k, where (p/k) % q != 0.
        // We want to maximize p/k, which means minimizing k.
        // The condition (p/k) % q != 0 means that p/k does not contain all prime factors of q with sufficient powers.

        // Let's find prime factors of q.
        std::vector<std::pair<long long, int>> q_factors = get_prime_factors(q);

        long long max_x = 1;

        // For each prime factor f of q, we try to remove enough f's from p
        // such that the resulting number is no longer divisible by q.
        // The resulting number will be p / (f^k) for some k.
        // We want to find the largest such p / (f^k).
        for (const auto& factor_pair : q_factors) {
            long long prime_factor = factor_pair.first;
            // int q_exponent = factor_pair.second; // Not directly used, but conceptually important

            // Calculate the maximum power of prime_factor that divides p
            long long temp_p = p;
            long long current_p_prime_power = 0;
            while (temp_p > 0 && temp_p % prime_factor == 0) {
                temp_p /= prime_factor;
                current_p_prime_power++;
            }

            // Calculate the maximum power of prime_factor that divides q
            long long temp_q = q;
            long long current_q_prime_power = 0;
            while (temp_q > 0 && temp_q % prime_factor == 0) {
                temp_q /= prime_factor;
                current_q_prime_power++;
            }

            // If p is divisible by q, then current_p_prime_power >= current_q_prime_power.
            // To make x not divisible by q, we need to reduce the power of prime_factor in x
            // to be less than current_q_prime_power.
            // The largest such x would be p / (prime_factor ^ (current_q_prime_power)).
            // This x is guaranteed to be a divisor of p.
            // This x is guaranteed not to be divisible by q because its prime_factor exponent is
            // current_p_prime_power - current_q_prime_power, which is less than current_q_prime_power
            // if current_p_prime_power - current_q_prime_power < current_q_prime_power.
            // No, this is not correct. We need to reduce the power of prime_factor in x to be
            // current_q_prime_power - 1.
            // So, x = p / (prime_factor ^ (current_p_prime_power - (current_q_prime_power - 1)))
            // which simplifies to x = p / (prime_factor ^ (current_p_prime_power - current_q_prime_power + 1)).

            // Let's rephrase:
            // We have p = P * f^A and q = Q * f^B, where f does not divide P or Q.
            // Since p % q == 0, we know A >= B.
            // We want to find x = p / k such that x % q != 0.
            // To maximize x, we want to minimize k.
            // Consider x = p / (f^(A - B + 1)).
            // This x has f^(B-1) as its power of f.
            // Since B >= 1, B-1 < B, so x is not divisible by q.
            // This x is a divisor of p.
            // This is one candidate for max_x.

            long long current_x_candidate = p;
            for (int i = 0; i < current_p_prime_power - current_q_prime_power + 1; ++i) {
                current_x_candidate /= prime_factor;
            }
            max_x = std::max(max_x, current_x_candidate);
        }
        std::cout << max_x << "\n";
    }

    return 0;
}

