int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    // We need to handle division by 2 with modulo.
    // (b-1) * b can be large, so calculate modulo at each step.
    long long sum_r_term1 = (b - 1);
    long long sum_r_term2 = b;

    long long sum_r;
    if (sum_r_term1 % 2 == 0) {
        sum_r = (sum_r_term1 / 2) % MOD;
        sum_r = (sum_r * sum_r_term2) % MOD;
    } else {
        sum_r = (sum_r_term2 / 2) % MOD;
        sum_r = (sum_r * sum_r_term1) % MOD;
    }

    // Calculate sum_k_term = sum_{k=1 to a} (k * b + 1)
    // sum_k_term = sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // sum_k_term = b * sum_{k=1 to a} k + a
    // sum_{k=1 to a} k = a * (a+1) / 2
    long long sum_k_inner_term1 = a;
    long long sum_k_inner_term2 = (a + 1);

    long long sum_k_inner;
    if (sum_k_inner_term1 % 2 == 0) {
        sum_k_inner = (sum_k_inner_term1 / 2) % MOD;
        sum_k_inner = (sum_k_inner * sum_k_inner_term2) % MOD;
    } else {
        sum_k_inner = (sum_k_inner_term2 / 2) % MOD;
        sum_k_inner = (sum_k_inner * sum_k_inner_term1) % MOD;
    }

    long long sum_k_term = (b % MOD * sum_k_inner) % MOD;
    sum_k_term = (sum_k_term + a) % MOD;

    // Total sum = (sum_r * sum_k_term) % MOD
    long long total_sum = (sum_r * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_password;

    for (size_t i = 0; i < s.length() - 1; ++i) {
        char c1 = s[i];
        char c2 = s[i+1];
        adj[c1].insert(c2);
        adj[c2].insert(c1);
        used_in_password.insert(c1);
        used_in_password.insert(c2);
    }
    if (s.length() == 1) { // Handle single character password
        used_in_password.insert(s[0]);
    }

    char start_char = '\0';
    bool possible = true;

    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj.count(c)) { // If character appeared in password
            if (adj[c].size() > 2) {
                possible = false;
                break;
            }
            if (adj[c].size() == 1) {
                start_char = c;
            }
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // If no character has degree 1, it means either:
    // 1. All characters have degree 0 (empty password or single char password, handled by start_char logic)
    // 2. All characters have degree 2 (a cycle)
    // 3. Some characters have degree 0, others have degree 2 (multiple disjoint cycles)
    // A valid keyboard must be a single path.
    // If used_in_password is not empty and start_char is still '\0', it means all characters in password have degree 2.
    // This implies a cycle, which is not a path.
    // Exception: if used_in_password has only one character, it has degree 0.
    if (!used_in_password.empty() && start_char == '\0') {
        // If there's only one character in the password, it has no neighbors, so degree 0.
        // It should be picked as start_char.
        if (used_in_password.size() == 1) {
            start_char = *used_in_password.begin();
        } else {
            // If more than one character and no degree 1 node, it's a cycle.
            std::cout << "NO\n";
            return;
        }
    }

    // If password is empty or single character, start_char might still be '\0'.
    // Pick any character that appeared in password as start_char.
    if (start_char == '\0' && !used_in_password.empty()) {
        start_char = *used_in_password.begin();
    }
    // If password is empty, used_in_password is empty, start_char is '\0'.
    // In this case, any layout is fine. We'll just print "abcdef...".

    std::string layout = "";
    std::set<char> visited;
    char current_char = start_char;

    if (current_char != '\0') {
        while (current_char != '\0' && visited.find(current_char) == visited.end()) {
            layout += current_char;
            visited.insert(current_char);

            char next_char = '\0';
            for (char neighbor : adj[current_char]) {
                if (visited.find(neighbor) == visited.end()) {
                    next_char = neighbor;
                    break;
                }
            }
            current_char = next_char;
        }
    }

    // Check if all characters from the password were included in the layout
    if (layout.length() != used_in_password.size()) {
        // This means there were multiple disjoint components in the graph formed by password characters.
        // A single row keyboard can only represent one connected component.
        std::cout << "NO\n";
        return;
    }

    // Add remaining characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited.find(c) == visited.end()) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        solve();
    }
    return 0;
}

