int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char t0_char = s[k_actual];

        std::vector<int> possible_k_initial = char_indices[t0_char - 'a'];

        if (possible_k_initial.size() == 1) {
            total_win_prob += 1.0;
            continue;
        }

        double max_win_prob_for_k_actual = 0.0;

        for (int p = 1; p < L; ++p) {
            char tp_char = s[(k_actual + p) % L];

            std::map<std::pair<char, char>, std::vector<int>> groups;
            for (int k_cand : possible_k_initial) {
                groups[{s[k_cand], s[(k_cand + p) % L]}].push_back(k_cand);
            }

            double current_p_win_prob = 0.0;
            for (const auto& pair_group : groups) {
                if (pair_group.second.size() == 1) {
                    current_p_win_prob += 1.0;
                }
            }
            max_win_prob_for_k_actual = std::max(max_win_prob_for_k_actual, current_p_win_prob / possible_k_initial.size());
        }
        total_win_prob += max_win_prob_for_k_actual;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // We need to track the transformation for two specific inputs: 0 and 1023.
    // Let's call them `val0` and `val1023`.
    // `val0` will store the result of applying all operations to 0.
    // `val1023` will store the result of applying all operations to 1023.
    // The maximum value for constants is 1023, which is 0b1111111111 (10 bits).
    // So we only care about bits 0-9.
    int val0 = 0;
    int val1023 = 1023; // All bits set

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val0 &= x;
            val1023 &= x;
        } else if (op_char == '|') {
            val0 |= x;
            val1023 |= x;
        } else if (op_char == '^') {
            val0 ^= x;
            val1023 ^= x;
        }
    }

    // Now we have the final state for input 0 and input 1023.
    // Let's determine the equivalent operations.
    // We need to find A, B, C such that:
    // (x & A | B) ^ C = final_result(x) for all x in [0, 1023]
    // Or, more generally, a sequence of at most 5 operations.

    // Let's analyze bit by bit. For each bit `j` (0 to 9):
    // Let `x_j` be the j-th bit of input `x`.
    // Let `f_j(x_j)` be the j-th bit of the final result.
    // We know `f_j(0)` (j-th bit of `val0`) and `f_j(1)` (j-th bit of `val1023` if `x_j` was 1).
    // The j-th bit of `val0` is `(val0 >> j) & 1`.
    // The j-th bit of `val1023` is `(val1023 >> j) & 1`.

    // Case 1: `f_j(0) = 0`, `f_j(1) = 0` => `x_j` always becomes 0. This is `x_j & 0`.
    // Case 2: `f_j(0) = 0`, `f_j(1) = 1` => `x_j` becomes `x_j`. This is `x_j & 1` or `x_j | 0` or `x_j ^ 0`.
    // Case 3: `f_j(0) = 1`, `f_j(1) = 0` => `x_j` becomes `!x_j`. This is `x_j ^ 1`.
    // Case 4: `f_j(0) = 1`, `f_j(1) = 1` => `x_j` always becomes 1. This is `x_j | 1`.

    // We can combine these into three operations:
    // 1. An AND operation to set certain bits to 0.
    // 2. An OR operation to set certain bits to 1.
    // 3. An XOR operation to flip certain bits.

    // Let's find the constants for these three operations.
    // `and_const`: bits that must be 0 (Case 1) or can be `x_j` (Case 2) or `!x_j` (Case 3).
    //              If `f_j(0)=0` and `f_j(1)=0`, then `and_const_j` must be 0.
    //              Otherwise, `and_const_j` can be 1.
    // `or_const`: bits that must be 1 (Case 4) or can be `x_j` (Case 2) or `!x_j` (Case 3).
    //             If `f_j(0)=1` and `f_j(1)=1`, then `or_const_j` must be 1.
    //             Otherwise, `or_const_j` can be 0.
    // `xor_const`: bits that must be flipped (Case 3) or can be `x_j` (Case 2) or `!x_j` (Case 3).
    //              If `f_j(0)=1` and `f_j(1)=0`, then `xor_const_j` must be 1.
    //              Otherwise, `xor_const_j` can be 0.

    // Let's define the constants for the three operations:
    // `final_and_val`: bits that are forced to 0. If `f_j(0)=0` and `f_j(1)=0`, then `final_and_val_j` is 0. Otherwise 1.
    // `final_or_val`: bits that are forced to 1. If `f_j(0)=1` and `f_j(1)=1`, then `final_or_val_j` is 1. Otherwise 0.
    // `final_xor_val`: bits that are flipped. If `f_j(0)=1` and `f_j(1)=0`, then `final_xor_val_j` is 1. Otherwise 0.

    int final_and_val = 0b1111111111; // Initialize to all 1s
    int final_or_val = 0;             // Initialize to all 0s
    int final_xor_val = 0;            // Initialize to all 0s

    for (int j = 0; j < 10; ++j) {
        int bit0 = (val0 >> j) & 1;
        int bit1 = (val1023 >> j) & 1;

        if (bit0 == 0 && bit1 == 0) { // Case 1: x_j -> 0
            final_and_val &= ~(1 << j); // Force this bit to 0
        } else if (bit0 == 0 && bit1 == 1) { // Case 2: x_j -> x_j
            // No change to final_and_val, final_or_val, final_xor_val for this bit
        } else if (bit0 == 1 && bit1 == 0) { // Case 3: x_j -> !x_j
            final_xor_val |= (1 << j); // Flip this bit
        } else if (bit0 == 1 && bit1 == 1) { // Case 4: x_j -> 1
            final_or_val |= (1 << j); // Force this bit to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;

    // The order of operations matters. A common canonical form is:
    // (x & A | B) ^ C
    // Let's verify this.
    // For a bit j:
    // If x_j -> 0 (Case 1): A_j=0, B_j=0, C_j=0. (x_j & 0 | 0) ^ 0 = 0. Correct.
    // If x_j -> x_j (Case 2): A_j=1, B_j=0, C_j=0. (x_j & 1 | 0) ^ 0 = x_j. Correct.
    // If x_j -> !x_j (Case 3): A_j=1, B_j=0, C_j=1. (x_j & 1 | 0) ^ 1 = !x_j. Correct.
    // If x_j -> 1 (Case 4): A_j=1, B_j=1, C_j=0. (x_j & 1 | 1) ^ 0 = 1. Correct.

    // So, the constants are:
    // A = final_and_val
    // B = final_or_val
    // C = final_xor_val

    // Add operations if their constants are not identity.
    // & 1023 is identity for AND.
    // | 0 is identity for OR.
    // ^ 0 is identity for XOR.

    if (final_and_val != 1023) {
        result_ops.push_back({'&', final_and_val});
    }
    if (final_or_val != 0) {
        result_ops.push_back({'|', final_or_val});
    }
    if (final_xor_val != 0) {
        result_ops.push_back({'^', final_xor_val});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
