    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        long long good_substrings_count = 0;

        // Precompute positions of '1's
        std::vector<int> one_indices;
        for (int i = 0; i < n; ++i) {
            if (s[i] == '1') {
                one_indices.push_back(i);
            }
        }

        for (int i = 0; i < one_indices.size(); ++i) {
            int l_one = one_indices[i]; // Current '1' is at index l_one

            // Iterate over possible ending '1's for the binary value
            // We need to consider up to 19 bits for the value to exceed 2*10^5
            // Max length is N = 2*10^5. Max value is 2^18 approx 2.6*10^5.
            // So, we need to check up to 18-19 bits after the leading '1'.
            // The loop for j goes up to i + MAX_BITS - 1.
            // MAX_BITS is chosen to be around 19-20 to cover values up to N.
            // If N=2e5, max value is 2e5. 2^17 = 131072, 2^18 = 262144.
            // So, we need to check up to 18 bits.
            // The length of the binary string is (one_indices[j] - l_one + 1).
            // If this length is 18, then j = i + 17.
            // So j can go up to i + 17. Let's use 20 for safety.
            for (int j = i; j < std::min((int)one_indices.size(), i + 20); ++j) {
                int r_one = one_indices[j]; // Current rightmost '1' for the binary value
                long long current_val = 0;

                // Calculate the binary value f(s_{l_one} ... s_{r_one})
                // This loop calculates the value of the substring from l_one to r_one
                // It's guaranteed that s[l_one] is '1'.
                // The length of this part is r_one - l_one + 1.
                // If this length exceeds 19, the value will be too large.
                // We can break early if current_val exceeds N.
                // The maximum possible value for current_val is N (2e5).
                // 2^18 is 262144. So, if r_one - l_one + 1 > 18, current_val can exceed N.
                // We can use a fixed max_bits, say 19 or 20.
                // The loop for j already limits the number of bits.
                // The maximum length of the binary string we consider is 20.
                // So, current_val will not overflow long long.

                for (int k = l_one; k <= r_one; ++k) {
                    current_val = (current_val << 1) | (s[k] - '0');
                    if (current_val > n + 20) { // Optimization: if value exceeds N + max_leading_zeros, it's too large
                        break;
                    }
                }

                if (current_val == 0) continue; // Should not happen if l_one is '1'

                // Now we have current_val = f(s_{l_one} ... s_{r_one})
                // We need to find substrings s_l ... s_r such that:
                // 1. s_l ... s_r contains s_{l_one} ... s_{r_one}
                // 2. s_l ... s_{l_one-1} are all '0's
                // 3. r = r_one
                // 4. r - l + 1 = current_val

                // The length of the substring is current_val.
                // The right endpoint is r_one.
                // So, the left endpoint must be l = r_one - current_val + 1.

                int l_candidate = r_one - (int)current_val + 1;

                // Check if l_candidate is valid:
                // 1. l_candidate >= 0 (within string bounds)
                // 2. l_candidate <= l_one (the leading '1' must be at or after l_candidate)
                // 3. All characters s[l_candidate ... l_one-1] must be '0's.
                //    This is equivalent to checking if there are no '1's in this range.
                //    The previous '1' before l_one is at one_indices[i-1] (if i > 0).
                //    So, l_candidate must be greater than one_indices[i-1].

                if (l_candidate >= 0 && l_candidate <= l_one) {
                    // Check condition 3: no '1's between l_candidate and l_one-1
                    // This means l_candidate must be greater than the index of the previous '1'
                    // If i == 0, there are no previous '1's, so l_candidate can be 0.
                    // If i > 0, the previous '1' is at one_indices[i-1].
                    // So, l_candidate must be > one_indices[i-1].
                    if (i == 0 || l_candidate > one_indices[i-1]) {
                        good_substrings_count++;
                    }
                }
            }
        }
        std::cout << good_substrings_count << "\n";
    }
    return 0;
}

