                current_delta_prefix[j] += ops[i].val;
            }
        } else { // type 2 operation
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], ops[i].val - current_delta_prefix[j]);
            }
        }
    }

    // If `b[j]` is still `numeric_limits<long long>::max()`, it means `j` was never part of a query.
    // In this case, `a_0[j]` can be anything. We can set it to 0.
    for (int j = 0; j < n; ++j) {
        if (b[j] == std::numeric_limits<long long>::max()) {
            b[j] = 0;
        }
    }

    // Now, verify if this candidate initial array `b` works.
    // We simulate all operations with `b` as the initial array.
    std::vector<long long> current_a(n);
    for (int j = 0; j < n; ++j) {
        current_a[j] = b[j];
    }

    std::vector<long long> current_delta_sim(n, 0); // Sum of d_k applied to current_a
    bool possible = true;
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta_sim[j] += ops[i].val;
            }
        } else { // type 2 operation
            long long max_val = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, b[j] + current_delta_sim[j]);
            }
            if (max_val != ops[i].val) {
                possible = false;
                break;
            }
        }
    }

    if (possible) {
        std::cout << "YES\n";
        for (int j = 0; j < n; ++j) {
            std::cout << b[j] << (j == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_queue;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_queue = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_queue) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_queue = false; // Child i goes to the doctor

        long long current_v_effect = children[i].v;
        long long total_d_effect = 0; // Accumulates d_j from children crying in the hall

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_queue) {
                continue;
            }

            // Apply accumulated d_effect from previous children who left
            if (total_d_effect > 0) {
                children[j].p -= total_d_effect;
            }

            // Apply v_effect from child i
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect = std::max(0LL, current_v_effect - 1);
            }

            // Check if child j cries and leaves
            if (children[j].p < 0) {
                children[j].in_queue = false;
                total_d_effect += children[j].d; // Add d_j to the total effect for subsequent children
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // A single cut divides s into s_prefix and s_suffix.
    // We can rearrange them to s_suffix + s_prefix.
    // We need s_suffix + s_prefix to be a palindrome and not equal to s.
    for (int i = 1; i < n; ++i) { // Cut position i means s[0...i-1] and s[i...n-1]
        std::string s_prefix = s.substr(0, i);
        std::string s_suffix = s.substr(i);
        std::string s_new = s_suffix + s_prefix;
        if (s_new != s && is_palindrome(s_new)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 didn't work, check for k=2.
    // With k=2, we can cut s into 3 pieces: s_left, s_middle, s_right.
    // s = s_left + s_middle + s_right.
    // We can rearrange them to s_right + s_middle + s_left.
    // This is equivalent to reversing the order of the pieces.
    // For this to be a palindrome, s_right + s_middle + s_left must be a palindrome.
    // Also, s_right + s_middle + s_left must not be equal to s.
    // Since s is already a palindrome, s_left + s_middle + s_right is a palindrome.
    // If s_right + s_middle + s_left is also a palindrome, and s_right + s_middle + s_left != s,
    // then k=2 is a possible answer.
    //
    // Consider the structure of s. If all characters in s are the same (e.g., "aaaa"),
    // then any rearrangement of pieces will result in the same string "aaaa".
    // In this case, it's impossible to form a new string s' != s.
    // We can check this by counting distinct characters.

    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }

    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work,
        // then k=2 is always possible.
        // Example: "nolon" -> "no|l|on" -> "on|l|no" (k=2)
        // The logic for k=2 is that we can always find two cuts
        // such that reversing the order of the three pieces creates a new palindrome.
        // For example, cut s into s[0...i-1], s[i...j-1], s[j...n-1].
        // If s is not all same characters, there must be at least two distinct characters.
        // Since s is a palindrome, s[0] == s[n-1], s[1] == s[n-2], etc.
        // If s is not all same characters, then there exists some `i` such that `s[i] != s[0]`.
        // This implies that `s` is not of the form `aaaaa...`.
        //
        // Consider cutting s into s[0...0], s[1...n-2], s[n-1...n-1].
        // This is s[0], s[1...n-2], s[n-1].
        // Rearranging to s[n-1], s[1...n-2], s[0].
        // Since s is a palindrome, s[0] == s[n-1].
        // So this new string is s[0] + s[1...n-2] + s[0].
        // This is the same as s. This specific rearrangement doesn't work.
        //
        // The problem statement implies that if k=1 doesn't work, and it's not "Impossible",
        // then k=2 is the answer.
        // The only case where it's "Impossible" is when all characters are the same.
        // If s is not all same characters, then there must be at least two distinct characters.
        // Since s is a palindrome, it means it's not of the form "aaaaa".
        // For example, "ababa".
        // If we cut "ababa" into "a|bab|a", and rearrange to "a|bab|a", it's the same.
        // But we can cut "ababa" into "ab|a|ba". Rearrange to "ba|a|ab". This is "baab". Not a palindrome.
        //
        // The key insight for k=2 is that if s is a palindrome and not all characters are the same,
        // we can always find two cuts to form a new palindrome.
        // For example, take s = "abacaba".
        // Cut at index 1: "a" | "bacaba". New string "bacabaa". Not palindrome.
        // Cut at index 2: "ab" | "acaba". New string "acabaab". Not palindrome.
        //
        // The problem statement implies that if k=1 doesn't work, and it's not "Impossible",
        // then k=2 is the answer. This is a common pattern in competitive programming problems
        // where the answer is usually small (0, 1, 2, or Impossible).
        // The "Impossible" case is correctly identified as all characters being the same.
        // If not all characters are the same, and k=1 didn't yield a solution, then k=2 must be the answer.
        // This is because we can always make two cuts to get a new palindrome.
        // For example, consider s = "nolon".
        // k=1: "n|olon" -> "olonn" (not pal)
        //      "no|lon" -> "lonno" (not pal)
        //      "nol|on" -> "onnol" (not pal)
        //      "nolo|n" -> "nnolo" (not pal)
        // So k=1 doesn't work.
        // Since "nolon" is not all same characters, the answer is 2.
        // Example cuts for "nolon": "no|l|on" -> "on|l|no" which is "onlno", a palindrome, and != "nolon".
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long min_a = elements[0].value;
    long long max_a = elements[n - 1].value;

    long long best_goodness = -1;
    std::vector<int> best_partition(n);

    // Case 1: All elements in one subsequence (e.g., all 1s or all 2s).
    // min_f = min_a + min_a
    // max_f = max_a + max_a
    // goodness = (max_a + max_a) - (min_a + min_a) = 2 * (max_a - min_a)
    best_goodness = 2 * (max_a - min_a);
    for (int i = 0; i < n; ++i) {
        best_partition[elements[i].original_index] = 1;
    }

    // Case 2: Two subsequences, but h is small enough that it might be better to split.
    // This case is relevant if min_a + max_a + h < 2 * max_a.
    // This simplifies to h < max_a - min_a.
    // Or, more generally, if the split creates a smaller range.
    //
    // Consider the partition where elements[0] is in S1 and elements[1]...elements[n-1] are in S2.
    // Or elements[0]...elements[n-2] in S1 and elements[n-1] in S2.
    //
    // Let's try a specific partition:
    // elements[0] in S1
    // elements[1]...elements[n-1] in S2
    //
    // min_f:
    //   - elements[0] + elements[1] + h (S1-S2)
    //   - elements[1] + elements[1] (S2-S2, if n-1 >= 2)
    //   - elements[0] + elements[0] (S1-S1, if n-1 >= 1)
    // The smallest possible sum is elements[0] + elements[1].
    // So min_f = min(elements[0] + elements[0], elements[1] + elements[1], elements[0] + elements[1] + h)
    // This simplifies to elements[0] + elements[0] if n=1, or elements[0] + elements[1] if n>=2.
    //
    // max_f:
    //   - elements[n-1] + elements[n-1] (S2-S2)
    //   - elements[0] + elements[n-1] + h (S1-S2)
    //
    // So, min_f = min(elements[0].value + elements[0].value, elements[0].value + elements[1].value + h);
    // if n >= 2, min_f = min(elements[0].value + elements[0].value, elements[1].value + elements[1].value, elements[0].value + elements[1].value + h);
    // The smallest possible sum of two elements is elements[0].value + elements[0].value.
    // The smallest possible sum of two elements from S2 is elements[1].value + elements[1].value.
    // The smallest possible sum of two elements from different sets is elements[0].value + elements[1].value + h.
    // So, min_f = elements[0].value + elements[0].value.
    //
    // max_f = max(elements[n-1].value + elements[n-1].value, elements[0].value + elements[n-1].value + h);
    //
    // Goodness = max_f - min_f
    //
    // Let's consider two specific partitions:
    // Partition A: elements[0] in S1, all others in S2.
    // Partition B: elements[n-1] in S2, all others in S1.
    //
    // For Partition A (elements[0] in S1, elements[1...n-1] in S2):
    // min_f_A = elements[0].value + elements[0].value;
    // max_f_A = std::max(elements[n-1].value + elements[n-1].value, elements[0].value + elements[n-1].value + h);
    // goodness_A = max_f_A - min_f_A;
    //
    // For Partition B (elements[n-1] in S2, elements[0...n-2] in S1):
    // min_f_B = elements[0].value + elements[0].value;
    // max_f_B = std::max(elements[n-1].value + elements[n-1].value, elements[0].value + elements[n-1].value + h);
    // goodness_B = max_f_B - min_f_B;
    //
    // These two partitions are symmetric and result in the same goodness.
    //
    // Let's re-evaluate the min/max f values for a general partition.
    // Let min_S1 be the minimum element in S1, max_S1 be the maximum element in S1.
    // Let min_S2 be the minimum element in S2, max_S2 be the maximum element in S2.
    //
    // The overall minimum f value will be:
    // min(
    //   (min_S1 + min_S1 if S1 has at least 2 elements),
    //   (min_S2 + min_S2 if S2 has at least 2 elements),
    //   (min_S1 + min_S2 + h if S1 and S2 are both non-empty)
    // )
    // This is always at least elements[0].value + elements[0].value.
    //
    // The overall maximum f value will be:
    // max(
    //   (max_S1 + max_S1 if S1 has at least 2 elements),
    //   (max_S2 + max_S2 if S2 has at least 2 elements),
    //   (max_S1 + max_S2 + h if S1 and S2 are both non-empty)
    // )
    // This is always at most elements[n-1].value + elements[n-1].value + h.
    //
    // Consider the partition where elements[0] is in S1, and all other elements are in S2.
    // min_f = elements[0].value + elements[0].value;
    // max_f = std::max(elements[n-1].value + elements[n-1].value, elements[0].value + elements[n-1].value + h);
    // current_goodness = max_f - min_f;
    //
    // If this current_goodness is better than best_goodness, update.
    // This partition is only valid if n >= 2.
    if (n >= 2) {
        long long current_min_f = elements[0].value + elements[0].value;
        long long current_max_f = std::max(elements[n-1].value + elements[n-1].value, elements[0].value + elements[n-1].value + h);
        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < best_goodness) {
            best_goodness = current_goodness;
            best_partition[elements[0].original_index] = 1;
            for (int i = 1; i < n; ++i) {
                best_partition[elements[i].original_index] = 2;
            }
        }
    }

    // Consider the partition where elements[n-1] is in S2, and all other elements are in S1.
    // This is symmetric to the previous case and yields the same goodness.
    // The partition would be: elements[n-1] in S2, elements[0...n-2] in S1.
    // The min_f would be elements[0].value + elements[0].value.
    // The max_f would be max(elements[n-1].value + elements[n-1].value, elements[0].value + elements[n-1].value + h).
    // So the goodness is the same. No need to recompute, just update partition if needed.
    // If current_goodness (from above) is equal to best_goodness, we can choose this partition.
    // The problem states "any of them". So we don't need to explicitly check this.

    // Consider the partition where elements[0] and elements[1] are in S1, and others in S2.
    // This is only relevant if n >= 3.
    // min_f = elements[0].value + elements[0].value
    // max_f = max(elements[n-1].value + elements[n-1].value, elements[0].value + elements[n-1].value + h, elements[1].value + elements[n-1].value + h)
    // This is max(elements[n-1].value + elements[n-1].value, elements[1].value + elements[n-1].value + h)
    if (n >= 3) {
        long long current_min_f = elements[0].value + elements[0].value;
        long long current_max_f = std::max(elements[n-1].value + elements[n-1].value, elements[1].value + elements[n-1].value + h);
        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < best_goodness) {
            best_goodness = current_goodness;
            best_partition[elements[0].original_index] = 1;
            best_partition[elements[1].original_index] = 1;
            for (int i = 2; i < n; ++i) {
                best_partition[elements[i].original_index] = 2;
            }
        }
    }

    // Consider the partition where elements[n-1] and elements[n-2] are in S2, and others in S1.
    // This is symmetric to the previous case.
    // min_f = elements[0].value + elements[0].value
    // max_f = max(elements[n-1].value + elements[n-1].value, elements[0].value + elements[n-2].value + h)
    if (n >= 3) {
        long long current_min_f = elements[0].value + elements[0].value;
        long long current_max_f = std::max(elements[n-1].value + elements[n-1].value, elements[0].value + elements[n-2].value + h);
        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < best_goodness) {
            best_goodness = current_goodness;
            best_partition[elements[n-1].original_index] = 2;
            best_partition[elements[n-2].original_index] = 2;
            for (int i = 0; i < n - 2; ++i) {
                best_partition[elements[i].original_index] = 1;
            }
        }
    }

    std::cout << best_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // last_valid_r[i] stores the maximum r such that the substring s[i...r]
    // does NOT contain any bad triplet.
    // Initialize with n-1, meaning s[i...n-1] is initially considered valid
    // until a bad triplet forces r to be smaller.
    std::vector<int> last_valid_r(n);
    std::iota(last_valid_r.begin(), last_valid_r.end(), 0); // last_valid_r[i] = i initially

    // The actual meaning of last_valid_r[i] will be the smallest index j
    // such that s[i...j] contains a bad triplet.
    // Or, more precisely, for a given l, any r < last_valid_r[l] is valid.
    // So, last_valid_r[l] will store the minimum r_prime such that
    // s[l...r_prime] contains a bad triplet.
    // If no bad triplet starts at or after l, then last_valid_r[l] = n.
    // Initialize last_valid_r[i] = n for all i.
    std::fill(last_valid_r.begin(), last_valid_r.end(), n);

    // Iterate through all possible starting positions x for a bad triplet
    // and all possible steps k.
    // The maximum k is such that x + 2k < n, so 2k < n - x.
    // The maximum x is n-3 (for k=1).
    for (int x = 0; x <= n - 3; ++x) {
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a bad triplet: s[x], s[x+k], s[x+2k]
                // This triplet affects any range [l, r] where l <= x and r >= x + 2k.
                // For any l <= x, the minimum r that makes [l, r] "bad" is x + 2k.
                // So, for each l from 0 to x, we update last_valid_r[l].
                // We want last_valid_r[l] to store the smallest r_prime such that
                // s[l...r_prime] contains a bad triplet.
                // So, for current l, if x+2k is smaller than the current last_valid_r[l],
                // it means we found an earlier bad triplet for this l.
                last_valid_r[x] = std::min(last_valid_r[x], x + 2 * k);

                // Optimization: k can be at most 2.
                // If k > 2, then x+k and x+2k are too far apart to be relevant
                // for the "minimal r" calculation for any l.
                // Specifically, if k >= 3, then x+2k >= x+6.
                // The problem statement implies that we only care about small k.
                // The maximum k for which s[x]=s[x+k]=s[x+2k] can be the *first*
                // bad triplet for some l is k=2.
                // If k=1, the triplet is (x, x+1, x+2).
                // If k=2, the triplet is (x, x+2, x+4).
                // If k=3, the triplet is (x, x+3, x+6).
                // Any triplet (x, x+3, x+6) would be "covered" by (x, x+1, x+2) or (x, x+2, x+4)
                // if those exist.
                // The crucial observation is that if s[x]=s[x+k]=s[x+2k] for k >= 3,
                // then any interval [l, r] that contains this triplet (i.e., l <= x, r >= x+2k)
                // must also contain a triplet with k=1 or k=2.
                // This is because the maximum distance between x and x+2k is 4 for k=2.
                // If k=3, x+2k = x+6.
                // The maximum span of a bad triplet is 4 (for k=2).
                // If we have s[x]=s[x+k]=s[x+2k] for k >= 3, then the span is at least 6.
                // Any interval of length 6 or more must contain a bad triplet of span at most 4
                // if one exists.
                // This optimization is based on the fact that we only need to find the *first*
                // bad triplet for any given l.
                // The maximum span of a bad triplet is 4 (for k=2).
                // So, if a bad triplet (x, x+k, x+2k) exists, and k >= 3,
                // then x+2k >= x+6.
                // Any interval [l, r] that contains this triplet (l <= x, r >= x+6)
                // must also contain a bad triplet with k=1 or k=2 if one exists
                // within the range [x, x+5].
                // The maximum index for a bad triplet is x+4 (for k=2).
                // So, we only need to check k=1 and k=2.
                if (k == 2) break; // No need to check k > 2 for this x
            }
        }
    }

    // Propagate the minimum r_prime backwards.
    // For any l, last_valid_r[l] should be the minimum of itself and last_valid_r[l+1].
    // This ensures that last_valid_r[l] stores the smallest r_prime such that
    // s[l...r_prime] contains *any* bad triplet starting at or after l.
    for (int l = n - 2; l >= 0; --l) {
        last_valid_r[l] = std::min(last_valid_r[l], last_valid_r[l + 1]);
    }

    // Now, for each l, the number of valid r's (that do not contain a bad triplet)
    // is (last_valid_r[l] - 1) - l + 1 = last_valid_r[l] - l.
    // These are r values such that l <= r < last_valid_r[l].
    // The number of such r's is last_valid_r[l] - l.
    for (int l = 0; l < n; ++l) {
        bad_pairs += (n - last_valid_r[l]);
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

