// Function to check if all tracks can be read within 'time' units
bool check(long long time, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    // dp[i][j] = minimum rightmost track covered by using first i heads to cover first j target tracks
    // This DP state is too complex and likely not needed.
    // A greedy approach for check(T) is more appropriate.

    // We need to cover all p_j tracks.
    // Iterate through the heads and greedily cover as many p_j tracks as possible.

    int p_idx = 0; // Current target track index to be covered
    for (int i = 0; i < n; ++i) { // For each head
        if (p_idx == m) { // All target tracks are already covered
            break;
        }

        // The current head h[i] can cover tracks in the range [h[i] - time, h[i] + time].
        // We need to cover p[p_idx].
        // If h[i] is too far to the right to cover p[p_idx] even by moving left as much as possible,
        // then this head cannot cover p[p_idx].
        // Specifically, if h[i] - time > p[p_idx], then this head cannot reach p[p_idx].
        // In this case, we must use a previous head (which is not possible if we are iterating heads)
        // or this head is useless for p[p_idx] and subsequent tracks.
        // This implies that if h[i] - time > p[p_idx], then p[p_idx] cannot be covered by h[i] or any subsequent head.
        // This is incorrect. A head h[i] can be used to cover p[p_idx] if h[i] is within [p[p_idx] - time, p[p_idx] + time].
        // The greedy strategy should be: for the current p[p_idx] that needs to be covered,
        // find the first available head h[i] that can cover it.
        // Once h[i] covers p[p_idx], it can also cover other tracks to its right.
        // We want to maximize the rightmost track covered by h[i] to help subsequent p_j's.

        // Let's re-evaluate the greedy strategy for check(T).
        // We have 'n' heads and 'm' target tracks.
        // We want to cover all 'p_j's.
        // We iterate through the heads. For each head, we try to cover the leftmost uncovered target track.
        // If head h[i] can cover p[p_idx], it means h[i] is in the range [p[p_idx] - time, p[p_idx] + time].
        // If h[i] is to the left of p[p_idx] (h[i] < p[p_idx]), it must move right.
        // If h[i] is to the right of p[p_idx] (h[i] > p[p_idx]), it must move left.
        // The crucial part is that a head can cover a *range* of tracks.
        // If head h[i] is used to cover p[p_idx], it can cover any track x such that |h[i] - x| <= time.
        // To cover p[p_idx] and maximize the reach to the right, the head h[i] should be positioned
        // such that its rightmost reachable point is maximized, while still covering p[p_idx].

        // If h[i] is used to cover p[p_idx]:
        // The head h[i] can reach tracks in [h[i] - time, h[i] + time].
        // If p[p_idx] is not in this range, h[i] cannot cover p[p_idx].
        // Specifically, if p[p_idx] < h[i] - time, then h[i] is too far right.
        // If p[p_idx] > h[i] + time, then h[i] is too far left.

        // The greedy strategy should be:
        // For each head h[i], determine the range of tracks it can cover.
        // We want to cover p[p_idx] (the current leftmost uncovered track).
        // If h[i] can cover p[p_idx], then it can cover tracks up to max_reach = h[i] + time.
        // However, if h[i] is far to the right of p[p_idx], say h[i] - time > p[p_idx],
        // then h[i] cannot cover p[p_idx].
        // If h[i] is far to the left of p[p_idx], say h[i] + time < p[p_idx],
        // then h[i] cannot cover p[p_idx].

        // The correct greedy approach for check(T):
        // We have 'n' heads and 'm' target tracks.
        // We iterate through the heads. For each head h[i], we try to cover the leftmost uncovered target track p[p_idx].
        // If h[i] can cover p[p_idx], it means that p[p_idx] is within the range [h[i] - time, h[i] + time].
        // If it can, then this head can cover all tracks from p[p_idx] up to h[i] + time.
        // We then advance p_idx past all tracks covered by this head.

        // Let's refine:
        // `p_idx` points to the first target track that still needs to be covered.
        // For each head `h[i]`:
        // 1. Calculate the leftmost track this head can reach: `left_reach = h[i] - time`.
        // 2. Calculate the rightmost track this head can reach: `right_reach = h[i] + time`.
        // 3. If `p_idx == m`, all tracks are covered, return true.
        // 4. If `left_reach > p[p_idx]`, this head `h[i]` is too far to the right to cover `p[p_idx]`.
        //    Since heads are sorted and target tracks are sorted, no subsequent head `h[j]` (j > i)
        //    will be able to cover `p[p_idx]` either, because `h[j] >= h[i]`.
        //    So, if `h[i] - time > p[p_idx]`, it's impossible to cover `p[p_idx]` with current or future heads.
        //    Return `false`.
        // 5. If `right_reach < p[p_idx]`, this head `h[i]` is too far to the left to cover `p[p_idx]`.
        //    This head cannot cover `p[p_idx]`. We must use the next head `h[i+1]` for `p[p_idx]`.
        //    So, we continue to the next head `h[i+1]`.
        // 6. If `left_reach <= p[p_idx] <= right_reach`, this head `h[i]` can cover `p[p_idx]`.
        //    It can also cover all other target tracks `p[k]` such that `p[k] <= right_reach`.
        //    We advance `p_idx` past all such tracks.
        //    `while (p_idx < m && p[p_idx] <= right_reach) { p_idx++; }`
        //    Then we move to the next head `h[i+1]`.

        // This greedy strategy is correct.
        // If a head h[i] can cover p[p_idx], it should be used to cover p[p_idx] and extend its reach as far right as possible.
        // This is because using h[i] for p[p_idx] frees up subsequent heads for subsequent target tracks.
        // If h[i] cannot cover p[p_idx] (because h[i] + time < p[p_idx]), then it's useless for p[p_idx] and we must use a later head.
        // If h[i] is too far right (h[i] - time > p[p_idx]), then no later head can cover p[p_idx].

        long long current_head_pos = h[i];
        long long head_left_bound = current_head_pos - time;
        long long head_right_bound = current_head_pos + time;

        // If the current head is too far to the right to cover the current target track p[p_idx]
        // (even if it moves all the way to its left_bound), then it's impossible.
        // Since h is sorted, no subsequent head can cover p[p_idx] either.
        if (head_left_bound > p[p_idx]) {
            return false;
        }

        // If the current head is too far to the left to cover p[p_idx]
        // (even if it moves all the way to its right_bound), then this head cannot cover p[p_idx].
        // We must use a later head. So, we skip this head and continue to the next one.
        if (head_right_bound < p[p_idx]) {
            continue;
        }

        // At this point, head h[i] can cover p[p_idx].
        // It can cover all tracks up to head_right_bound.
        // Advance p_idx past all tracks covered by this head.
        while (p_idx < m && p[p_idx] <= head_right_bound) {
            p_idx++;
        }
    }

    // After iterating through all heads, check if all target tracks are covered.
    return p_idx == m;
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    // Binary search for the minimum time
    long long low = 0;
    // Max possible time: difference between max p and min h, or max h and min p, plus some buffer.
    // A safe upper bound is max(p_m - h_1, h_n - p_1) or simply max(p_m, h_n) - min(p_1, h_1).
    // A very loose upper bound is 10^10 (max coordinate) - 1 (min coordinate) = 10^10.
    long long high = 2e10; // Max possible coordinate is 10^10, so max diff is 10^10. 2*10^10 is safe.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

