    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // diff_L[k] = (count of 1s in a[0...k-1]) - (count of 2s in a[0...k-1])
    // for k from 0 to n
    std::vector<int> diff_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_L[i + 1] = diff_L[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right side (jars n+1 to 2n)
    // diff_R[k] = (count of 1s in a[2n-k...2n-1]) - (count of 2s in a[2n-k...2n-1])
    // for k from 0 to n
    std::vector<int> diff_R(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_R[i + 1] = diff_R[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars emptied from the left
    // to achieve a certain difference.
    // key: difference (S-B), value: number of jars emptied from left (n - k)
    std::map<int, int> left_diff_to_emptied_count;
    for (int k = 0; k <= n; ++k) { // k is number of jars remaining on left
        int current_diff = diff_L[k];
        int emptied_count = n - k;
        if (left_diff_to_emptied_count.find(current_diff) == left_diff_to_emptied_count.end()) {
            left_diff_to_emptied_count[current_diff] = emptied_count;
        } else {
            left_diff_to_emptied_count[current_diff] = std::min(left_diff_to_emptied_count[current_diff], emptied_count);
        }
    }

    int min_total_emptied = 2 * n; // Initialize with max possible

    for (int k = 0; k <= n; ++k) { // k is number of jars remaining on right
        int current_diff_right = diff_R[k];
        int emptied_count_right = n - k;

        // We need total_S - total_B = 0
        // (S_L + S_R) - (B_L + B_R) = 0
        // (S_L - B_L) + (S_R - B_R) = 0
        // (S_L - B_L) = -(S_R - B_R)
        // So, we need diff_L_remaining = -current_diff_right
        int target_diff_left = -current_diff_right;

        if (left_diff_to_emptied_count.count(target_diff_left)) {
            int emptied_count_left = left_diff_to_emptied_count[target_diff_left];
            min_total_emptied = std::min(min_total_emptied, emptied_count_left + emptied_count_right);
        }
    }

