void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // For n=2, reversing is the only option and it works.
    // For n > 2, reversing the permutation p' = [p_n, p_{n-1}, ..., p_1]
    // gives sums [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
    // These are the same sums as [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n]
    // just in reverse order. So their sorted lists (fingerprints) will be identical.
    // The reversed permutation p' is different from p unless p is a palindrome.
    // A permutation p is a palindrome if p_i = p_{n-1-i} for all i.
    // For example, [1,2,1] is not a permutation. [1,2,3,2,1] is not a permutation.
    // A permutation of distinct numbers from 1 to n cannot be a palindrome
    // unless n=1 (which is not allowed, n>=2) or n=2 and p=[1,2] or p=[2,1].
    // If p=[1,2], reversed is [2,1], which is different.
    // If p=[2,1], reversed is [1,2], which is different.
    // So reversing always produces a different permutation.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

