        // Let Class 2 be $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$. Its size is $n$.
        //
        // If $n$ is odd:
        // Class 1 has size $n$. Its median is $a_{(n-1)/2}$.
        // Class 2 has size $n$. Its median is $a_{n + (n-1)/2}$.
        // The difference is $a_{n + (n-1)/2} - a_{(n-1)/2}$. This is not necessarily $a_n - a_{n-1}$.
        //
        // The example case $n=3$, $a = [1,2,3,4,5,6]$. Sorted $a = [1,2,3,4,5,6]$.
        // $n=3$. $a[n-1]=a[2]=3$, $a[n]=a[3]=4$. Difference $4-3=1$.
        // Example output is 1.
        //
        // If $n=3$, $n$ is odd.
        // Class 1: $a[0], a[1], a[2]$ i.e., $[1,2,3]$. Median is $a[(3-1)/2] = a[1] = 2$.
        // Class 2: $a[3], a[4], a[5]$ i.e., $[4,5,6]$. Median is $a[3+(3-1)/2] = a[4] = 5$.
        // Difference is $|5-2|=3$. This is not 1.
        //
        // The example output for $n=3$ is 1, achieved by Class 1: $[6,4,2]$ (median 4), Class 2: $[5,1,3]$ (median 3).
        // Sorted $a = [1,2,3,4,5,6]$.
        // $a[n-1] = a[2] = 3$. $a[n] = a[3] = 4$.
        // The medians are 3 and 4.
        //
        // This means we need to pick $a[n-1]$ as the median of one class and $a[n]$ as the median of the other.
        //
        // How to construct this?
        // Class 1: $a[n-1]$ as median. Need $k_1$ elements smaller than $a[n-1]$ and $k_1$ elements larger than $a[n-1]$.
        // Class 2: $a[n]$ as median. Need $k_2$ elements smaller than $a[n]$ and $k_2$ elements larger than $a[n]$.
        //
        // We have $k_1+k_2 = n-1$.
        //
        // Let's try to make $k_1 = n-1$ and $k_2 = 0$.
        // Class 1 size $2(n-1)+1 = 2n-1$. Median $a[n-1]$.
        // Class 2 size $2(0)+1 = 1$. Median $a[n]$.
        //
        // Class 1: $a[n-1]$ is median. We need $n-1$ elements smaller than $a[n-1]$ and $n-1$ elements larger than $a[n-1]$.
        // We can pick $a_0, \dots, a_{n-2}$ as the $n-1$ smaller elements.
        // We can pick $a_{n+1}, \dots, a_{2n-1}$ as the $n-1$ larger elements.
        // So Class 1 is $\{a_0, \dots, a_{n-2}, a_{n-1}, a_{n+1}, \dots, a_{2n-1}\}$.
        // This class has $(n-1) + 1 + (n-1) = 2n-1$ students.
        // Its median is $a_{n-1}$.
        //
        // The remaining student is $a_n$.
        // Class 2: $\{a_n\}$. Its size is 1. Its median is $a_n$.
        //
        // This partition is always valid:
        // Class 1 has size $2n-1$ (odd).
        // Class 2 has size $1$ (odd).
        // All $2n$ students are assigned.
        // The medians are $a_{n-1}$ and $a_n$.
        // The absolute difference is $|a_n - a_{n-1}|$.
        //
        // Since we proved that the difference must be at least $a_n - a_{n-1}$, and we found a construction that achieves this difference,
        // then $a_n - a_{n-1}$ is the minimum possible absolute difference.

        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) { // Cannot increase if no 1 is available before current index
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_neg_one) { // Cannot decrease if no -1 is available before current index
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation needed for this element.
        // The flags has_pos_one and has_neg_one are updated based on a[i]
        // for future elements.
        // This is crucial: the flags must reflect elements *before* the current index.
        // The loop structure naturally handles this as flags are updated after checking a[i] vs b[i].
    }

    std::cout << "YES\n";
}

