void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n);

    int current_color_for_half = 0; // 0 for white, 1 for black

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < T / 2.0) { // Use floating point for T/2 to handle odd T correctly
            p[i] = 0; // Assign to white (array c)
        } else if (a[i] > T / 2.0) {
            p[i] = 1; // Assign to black (array d)
        } else { // a[i] == T/2
            // Alternate colors for elements equal to T/2
            p[i] = current_color_for_half;
            current_color_for_half = 1 - current_color_for_half;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

