#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);

    for (int i = 0; i < n; ++i) {
        int max_val_for_i = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) {
                max_val_for_i = std::max(max_val_for_i, a[i][j]);
            }
        }
        p[i] = max_val_for_i;
    }

    // Check if any p[i] is n-1 and no other p[j] is n.
    // If so, it means the actual value for p[i] should be n.
    // This happens if all other elements p[j] (j!=i) are less than n.
    // In this case, min(p[i], p[j]) = p[j] for all j!=i.
    // So max(a[i][j] for j!=i) would be max(p[j] for j!=i), which is n-1.
    // But p[i] itself is n.
    // So we need to find if there's a position that should be n.
    // The value n is unique in the permutation.
    // If n is not present in the calculated p values, it means one of the
    // elements that was calculated as n-1 should actually be n.
    // This happens if all other elements are smaller than n.
    // The element p[k] that is n will have max(a[k][j] for j!=k) = n-1,
    // because all other p[j] are at most n-1.
    // So, if n is not found in the current p, we find the first element
    // that is n-1 and change it to n.
    bool n_found = false;
    for (int val : p) {
        if (val == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    // Initialize min_suffix_price with the last element, as it has no elements after it.
    // The last element itself can never be a bad price by definition.
    int min_suffix_price = a[n - 1]; 

    // Iterate from the second to last element backwards to the first element
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix_price) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix_price, it means a[i] is
            // either equal to or less than the current minimum.
            // In either case, a[i] becomes the new minimum for elements to its left.
            min_suffix_price = a[i];
        }
    }
    std::cout << bad_prices_count << "\n";
}

