int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by:
        // 1. The number of coders (each team needs at least one coder).
        // 2. The number of mathematicians (each team needs at least one mathematician).
        // 3. The total number of students available (each team needs 3 students).
        // So, k <= c, k <= m, and 3*k <= c + m + x.
        // This means k <= min(c, m, (c + m + x) / 3).
        // Let's call this upper bound 'max_possible_teams'.
        long long max_possible_teams = std::min({c, m, (c + m + x) / 3});

        // This 'max_possible_teams' is a valid upper bound.
        // We can always form 'max_possible_teams' teams.
        // For each team, we use 1 coder, 1 mathematician, and 1 student from the remaining pool.
        // The remaining pool consists of (c - k) coders, (m - k) mathematicians, and x students.
        // The total number of "extra" students available to fill the third slot for k teams is:
        // (c - k) + (m - k) + x.
        // We need k such students to form k teams.
        // So, (c - k) + (m - k) + x >= k must hold.
        // c + m + x - 2k >= k
        // c + m + x >= 3k
        // (c + m + x) / 3 >= k
        // This condition is already covered by max_possible_teams.

        // The crucial observation is that if we have k teams, we need k coders and k mathematicians.
        // The remaining students are (c-k) coders, (m-k) mathematicians, and x unspecialized students.
        // The total number of these remaining students is (c-k) + (m-k) + x.
        // These students must fill the 'third slot' for each of the k teams.
        // So, we need at least k students for these third slots.
        // The total number of students available for these third slots is (c-k) + (m-k) + x.
        // Thus, (c-k) + (m-k) + x >= k must be true.
        // This simplifies to c + m + x >= 3k, or k <= (c + m + x) / 3.
        // This means that the number of teams is limited by the total number of students divided by 3.
        // It is also limited by the minimum of coders and mathematicians, as each team needs at least one of each.
        // So, the maximum number of teams is indeed min(c, m, (c + m + x) / 3).

        std::cout << max_possible_teams << "\n";
    }
    return 0;
}

