int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The numbers from 1 to k+1 will be used to generate k distinct differences.
                       // The differences will be k, k-1, ..., 1.

    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) {
            std::cout << left++;
        } else {
            std::cout << right--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // After generating k distinct differences using numbers from 1 to k+1,
    // the remaining numbers are k+2, k+3, ..., n.
    // We can append these in increasing order to ensure the differences are 1.
    // This will not introduce new distinct differences if k >= 1.
    // The last number printed was either left-1 or right+1.
    // If k is even, the last number printed was right (which is now right+1).
    // If k is odd, the last number printed was left (which is now left-1).
    // In both cases, the next number to print is left.
    // So, the remaining numbers are from left to n.
    for (int i = k + 1; i < n; ++i) {
        std::cout << left++;
        std::cout << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

