        long long count = n / m; // Number of multiples of m up to n

        if (count == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Calculate the sum of last digits for the first 10 multiples of m
        // (m % 10), (2m % 10), ..., (10m % 10)
        long long sum_of_first_ten_last_digits = 0;
        for (int i = 1; i <= 10; ++i) {
            sum_of_first_ten_last_digits += (static_cast<long long>(i) * m) % 10;
        }

        // Number of full cycles of 10 multiples
        long long num_cycles = count / 10;
        long long total_sum = num_cycles * sum_of_first_ten_last_digits;

        // Remaining multiples after full cycles
        long long remaining_multiples = count % 10;
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (i * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <iomanip>
#include <algorithm> // For std::min/max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y " << std::fixed << std::setprecision(9) << 0.0 << " " << 0.0 << "\n";
            continue;
        }

        // For a and b to be real, the discriminant d^2 - 4d must be non-negative.
        // d^2 - 4d >= 0
        // d(d - 4) >= 0
        // Since d >= 0, we need d - 4 >= 0, which means d >= 4.
        // If d < 4 (and d > 0), there are no real solutions.
        if (d < 4.0) {
            std::cout << "N\n";
        } else {
            double discriminant = d * d - 4.0 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // Both a and b must be non-negative.
            // Since d >= 4, d is positive.
            // sqrt_discriminant = sqrt(d(d-4)).
            // If d >= 4, then d-4 >= 0, so sqrt_discriminant is real and non-negative.
            // a1 = (d + sqrt_discriminant) / 2.0 is clearly non-negative.
            // b1 = (d - sqrt_discriminant) / 2.0.
            // We need d - sqrt_discriminant >= 0, which means d >= sqrt_discriminant.
            // Squaring both sides (both are non-negative): d^2 >= discriminant
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // This is true since d >= 4.
            // So both a1 and b1 are guaranteed to be non-negative.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] = index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the range is just pos[1].
        // For m > 1, we need to expand the range to include 'm'.
        // The number 'm' is at pos[m].
        // We update current_min_idx and current_max_idx to cover the range [1, ..., m].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number 'm' is beautiful if the segment p[current_min_idx ... current_max_idx]
        // contains all numbers from 1 to m, and its length is exactly m.
        // The length of this segment is (current_max_idx - current_min_idx + 1).
        // If this length equals m, it means all numbers from 1 to m are within this
        // contiguous segment, and no other numbers are.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

