    // 3. Ensure elements to the right of median are >= s
    // These are elements a[median_idx+1]...a[n-1]
    // After sorting, if a[i] < s for i > median_idx, we must increase it to s.
    // The cost is s - a[i].
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

