    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in descending order
    // We need to sort B values, but keep track of their original indices
    // to place the A' values correctly in the final output array.
    std::sort(b_elements.begin(), b_elements.end(), [](const Element& x, const Element& y) {
        return x.value > y.value;
    });

    std::vector<long long> result_a_prime(m);

    // Assign sorted A values to positions determined by sorted B values
    // The smallest A value (a_elements[0].value) should be paired with the largest B value (b_elements[0].value)
