#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

// Function to check if a prefix of length `len` is a permutation
bool is_permutation_prefix(int len, const std::vector<int>& a, const std::vector<int>& prefix_max_val, const std::vector<int>& prefix_distinct_count) {
    if (len == 0) return false; // Permutation length must be non-zero
    return prefix_max_val[len - 1] == len && prefix_distinct_count[len - 1] == len;
}

// Function to check if a suffix of length `len` is a permutation
bool is_permutation_suffix(int len, const std::vector<int>& a, const std::vector<int>& suffix_max_val, const std::vector<int>& suffix_distinct_count) {
    if (len == 0) return false; // Permutation length must be non-zero
    return suffix_max_val[a.size() - len] == len && suffix_distinct_count[a.size() - len] == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute prefix properties
    std::vector<int> prefix_max_val(n);
    std::vector<int> prefix_distinct_count(n);
    std::vector<bool> seen_prefix(n + 1, false); // Max value can be n, so size n+1
    int current_distinct_prefix = 0;
    int current_max_prefix = 0;

    for (int i = 0; i < n; ++i) {
        if (!seen_prefix[a[i]]) {
            seen_prefix[a[i]] = true;
            current_distinct_prefix++;
        }
        current_max_prefix = std::max(current_max_prefix, a[i]);
        prefix_max_val[i] = current_max_prefix;
        prefix_distinct_count[i] = current_distinct_prefix;
    }

    // Precompute suffix properties
    std::vector<int> suffix_max_val(n);
    std::vector<int> suffix_distinct_count(n);
    std::vector<bool> seen_suffix(n + 1, false); // Max value can be n, so size n+1
    int current_distinct_suffix = 0;
    int current_max_suffix = 0;

    for (int i = n - 1; i >= 0; --i) {
        if (!seen_suffix[a[i]]) {
            seen_suffix[a[i]] = true;
            current_distinct_suffix++;
        }
        current_max_suffix = std::max(current_max_suffix, a[i]);
        suffix_max_val[i] = current_max_suffix;
        suffix_distinct_count[i] = current_distinct_suffix;
    }

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points
    // l1 is the length of the first permutation
    // l2 is the length of the second permutation
    // l1 + l2 = n
    for (int l1 = 1; l1 < n; ++l1) { // l1 can range from 1 to n-1
        int l2 = n - l1;

        // Check if prefix a[0...l1-1] is a permutation of length l1
        bool prefix_ok = is_permutation_prefix(l1, a, prefix_max_val, prefix_distinct_count);

        // Check if suffix a[l1...n-1] is a permutation of length l2
        bool suffix_ok = is_permutation_suffix(l2, a, suffix_max_val, suffix_distinct_count);

        if (prefix_ok && suffix_ok) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

