                // N=5: Chanek takes 1. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1.
                // Chanek: 1+1=2. Opponent: 2+1=3. (Example output: 2)
                // N=6: Chanek takes 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
                // Chanek: 1+2+1=4. Opponent: 1+1=2. (Example output: 4)
                // This matches the example outputs.

                // How to check if N is a power of 2? (N > 0) && ((N & (N - 1)) == 0)
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N is even but not a power of 2
                    chanek_coins += 1;
                    n -= 1;
                }
            }
        } else { // Opponent's turn
            // Opponent uses the same optimal strategy
            if (n == 1) {
                opponent_coins += 1;
                n = 0;
            } else if (n % 2 == 1) { // Odd number of coins
                opponent_coins += 1;
                n -= 1;
            } else { // Even number of coins
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    opponent_coins += n / 2;
                    n /= 2;
                } else { // N is even but not a power of 2
                    opponent_coins += 1;
                    n -= 1;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

