#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long current_a_count = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means this 'b' can be paired with
            // any 'a' to its left. Each such 'a' will eventually pass this 'b'.
            // When an 'a' passes a 'b' (i.e., "ab" -> "bba"), it generates
            // a new 'b'. This new 'b' will also need to be passed by any
            // 'a's that are still to its left.
            // The number of 'a's currently to the left that will pass this 'b'
            // (and any 'b's generated by this 'b') is `current_a_count`.
            // Each such 'a' passing this 'b' (or a 'b' generated by it)
            // costs 1 step.
            // So, `current_a_count` steps are added.
            // Additionally, this 'b' itself will generate `current_a_count`
            // new 'b's (one for each 'a' that passes it).
            // These new 'b's effectively double the number of 'b's that
            // subsequent 'a's (further to the left) will have to pass.
            // So, `current_a_count` effectively doubles.
            total_steps = (total_steps + current_a_count) % MOD;
            current_a_count = (current_a_count * 2) % MOD;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' will eventually
            // pass all 'b's to its right.
            // The number of 'b's it needs to pass is `current_a_count`.
            // Each 'b' it passes costs 1 step.
            // So, `current_a_count` steps are added.
            // This 'a' itself will then be available to pass 'b's further
            // to its left. So, we increment `current_a_count`.
            total_steps = (total_steps + current_a_count + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We want S' = 2 * X'
    // Let S' = current_sum + b1 + b2 + ...
    // Let X' = current_xor_sum ^ b1 ^ b2 ^ ...

    // Case 1: Append 0 elements.
    // If current_sum == 2 * current_xor_sum, it's already good.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
        return;
    }

    // Case 2: Append 2 elements.
    // We need to find b1, b2 such that:
    // (current_sum + b1 + b2) = 2 * (current_xor_sum ^ b1 ^ b2)
    // Let X_target = current_xor_sum.
    // We want to find b1, b2 such that:
    // current_sum + b1 + b2 = 2 * (X_target ^ b1 ^ b2)
    //
    // Consider appending two elements: X_target and current_sum.
    // Let b1 = X_target.
    // Let b2 = current_sum.
    //
    // New XOR sum: X' = current_xor_sum ^ b1 ^ b2 = current_xor_sum ^ X_target ^ current_sum
    // Since b1 = X_target = current_xor_sum, then X_target ^ b1 = 0.
    // So, X' = 0 ^ current_sum = current_sum.
    //
    // New sum: S' = current_sum + b1 + b2 = current_sum + X_target + current_sum = 2 * current_sum + X_target.
    //
    // We need S' = 2 * X'.
    // So, 2 * current_sum + X_target = 2 * current_sum.
    // This implies X_target = 0.
    // This strategy works if current_xor_sum is 0, but we already handled the case where it's good.
    //
    // Let's try a different strategy for 2 elements.
    // We know that for any numbers A, B, A+B = (A^B) + 2*(A&B).
    // This implies A+B >= A^B.
    // Also, A+B and A^B have the same parity.
    //
    // Let X = current_xor_sum.
    // Let S = current_sum.
    // We want to find b1, b2 such that S + b1 + b2 = 2 * (X ^ b1 ^ b2).
    //
    // Consider appending b1 = X.
    // Then the new XOR sum is X' = X ^ X ^ b2 = b2.
    // The new sum is S' = S + X + b2.
    // We need S' = 2 * X'.
    // So, S + X + b2 = 2 * b2.
    // This implies S + X = b2.
    //
    // So, if we append b1 = X and b2 = S + X, the new array will have:
    // XOR sum: X' = X ^ X ^ (S + X) = S + X.
    // Sum: S' = S + X + (S + X) = 2 * (S + X).
    //
    // This satisfies S' = 2 * X'.
    // The two elements to append are X and S + X.
    // These are non-negative since X >= 0 and S >= 0.
    //
    // This strategy always works and uses 2 elements.
    // The problem statement says "at most 3 elements" and "you don't have to minimize the number of added elements".
    // So, appending 2 elements is fine.

    long long b1 = current_xor_sum;
    long long b2 = current_sum + current_xor_sum;

    std::cout << 2 << std::endl;
    std::cout << b1 << " " << b2 << std::endl;
}

