    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    for (int i = 0; i <= n; ++i) {
        // i is the number of items taken from the left
        // n - i is the number of items taken from the right
        int j = n - i;

        long long current_energy = 0;

