                            // Initially, the frog is at 0, which allows a right jump.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // If we encounter an 'R' at index i (cell i+1),
                // it means we can jump from cell i+1 to the right.
