                // The current cell is i+1. The previous 'R' was at last_R_pos.
                // The distance needed to cover this segment is (i+1) - last_R_pos.
                max_gap = std::max(max_gap, (i + 1) - last_R_pos);
                last_R_pos = i + 1;
            }
        }
        // After iterating through the string, we need to consider the jump
        // from the last 'R' position to the target n+1.
        // The distance needed is (n+1) - last_R_pos.
        max_gap = std::max(max_gap, (n + 1) - last_R_pos);

        std::cout << max_gap << "\n";
    }
