// Function to get prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // Let q = f1^a1 * f2^a2 * ... * fk^ak be the prime factorization of q.
        // If x is divisible by q, then x must have at least a_i factors of f_i for all i.
        // To make x not divisible by q, we must remove at least one factor f_i from p
        // such that the resulting x has fewer than a_i factors of f_i.
        // To maximize x, we should remove as few factors as possible, and specifically,
        // remove factors that are "small" in terms of their contribution to p.

        // The strategy is to iterate through each distinct prime factor f of q.
        // For each f, we find the largest divisor of p that is not divisible by q.
        // This divisor is obtained by dividing p by f until it's no longer divisible by q.
        // More precisely, we find the largest power of f, say f^k, such that p / f^k is still divisible by q.
        // Then p / f^(k+1) would be a candidate for x.
        // We want to find the largest x such that x | p and x % q != 0.
        // If p % q == 0, then p is not a valid answer.
        // We need to find a divisor of p, say p', such that p' % q != 0.
        // To maximize p', we should remove factors from p.
        // Consider prime factors of q. Let q = f1^a1 * f2^a2 * ... * fk^ak.
        // If p is divisible by q, then p must contain at least a_i factors of f_i for all i.
        // To make p' not divisible by q, we must reduce the count of some f_i in p' below a_i.
        // To maximize p', we should pick one f_i, and divide p by f_i until p is no longer divisible by q.
        // For each distinct prime factor f of q:
        //   Let current_p = p.
        //   While current_p is divisible by q:
        //     current_p /= f.
        //   The resulting current_p is a candidate for x.
        // We take the maximum among all such candidates.

        std::vector<long long> prime_factors_q = get_prime_factors(q);
        long long max_x = 0;

        for (long long f : prime_factors_q) {
            long long current_p = p;
            while (current_p % q == 0) {
                current_p /= f;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool possible = false;

    for (int pivot_val = 0; pivot_val <= 9; ++pivot_val) {
        char last_d1 = '0' - 1; // Represents a value smaller than any digit
        char last_d2 = '0' - 1; // Represents a value smaller than any digit
        bool current_possible = true;

        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];
            if (current_digit < pivot_val + '0') {
                // Must be color 1
                if (current_digit < last_d1) {
                    current_possible = false;
                    break;
                }
                result[i] = '1';
                last_d1 = current_digit;
            } else if (current_digit > pivot_val + '0') {
                // Must be color 2
                if (current_digit < last_d2) {
                    current_possible = false;
                    break;
                }
                result[i] = '2';
                last_d2 = current_digit;
            } else { // current_digit == pivot_val + '0'
                // Can be either color 1 or color 2
                // Prioritize color 2 if it maintains non-decreasing order for S2
                // This is because digits equal to pivot_val + '0' can be the boundary.
                // If we put it in S2, it must be >= last_d2.
                // If we put it in S1, it must be >= last_d1.
                // To maximize chances, we want last_d1 to be as small as possible,
                // and last_d2 to be as small as possible.
                // If current_digit can go to S2 (i.e., current_digit >= last_d2),
                // we put it in S2. This keeps last_d1 potentially smaller.
                if (current_digit >= last_d2) {
                    result[i] = '2';
                    last_d2 = current_digit;
                } else if (current_digit >= last_d1) {
                    result[i] = '1';
                    last_d1 = current_digit;
                } else {
                    current_possible = false;
                    break;
                }
            }
        }

        if (current_possible) {
            // Final check: last digit of S1 <= first digit of S2
            // We need to find the actual last_d1 and first_d2 from the constructed result
            char actual_last_d1 = '0' - 1;
            char actual_first_d2 = '9' + 1;
            bool found_d1 = false;
            bool found_d2 = false;

            for (int i = 0; i < n; ++i) {
                if (result[i] == '1') {
                    actual_last_d1 = s[i];
                    found_d1 = true;
                }
            }
            for (int i = 0; i < n; ++i) {
                if (result[i] == '2') {
                    actual_first_d2 = s[i];
                    found_d2 = true;
                    break; // Found the first '2' digit
                }
            }

            if (!found_d1 || !found_d2 || actual_last_d1 <= actual_first_d2) {
                possible = true;
                break;
            }
        }
    }

    if (possible) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

