            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // The problem guarantees that if a solution exists, one exists within [-10^5, 10^5].
            // We can pick any valid point. min_x, min_y are valid choices.
            // However, the problem statement says "Both X and Y should not exceed 10^5 by absolute value".
            // Our min_x/min_y could be outside this range if the initial coordinates are large.
            // The guarantee implies that if min_x <= max_x and min_y <= max_y, then there must be
            // some (X, Y) in the intersection that also satisfies |X|, |Y| <= 10^5.
            // A simple way to satisfy this is to clamp the chosen point to the guaranteed range.
            // However, the problem statement is "if there exists at least one point reachable by all robots,
            // then at least one of such points has both coordinates not exceeding 10^5 by absolute value."
            // This means we don't need to clamp our chosen min_x, min_y if they are outside the range,
            // as long as they are valid according to our logic. The problem implies that if our
            // min_x, max_x, min_y, max_y define a valid range, then there's *some* point in that range
            // that also fits the absolute value constraint.
            // The simplest is to just output min_x, min_y. If they are outside [-10^5, 10^5],
            // it's fine because the problem guarantees *some* point exists within that range.
            // The judge will accept any valid point.
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>

long long power(long long base, long long exp) {
    long long res = 1;
    base %= 1000000007;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % 1000000007;
        base = (base * base) % 1000000007;
        exp /= 2;
    }
    return res;
}

long long modInverse(long long n) {
    return power(n, 1000000007 - 2);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_{r=1 to b-1} r
    // This is (b-1) * b / 2
    long long sum_r_term;
    if (b == 1) { // If b=1, then b-1=0, sum is 0.
        sum_r_term = 0;
    } else {
        long long b_minus_1 = b - 1;
        long long inv2 = modInverse(2);
        sum_r_term = (b_minus_1 % MOD * (b % MOD)) % MOD;
        sum_r_term = (sum_r_term * inv2) % MOD;
    }

    // Calculate sum_{k=1 to a} (k * b + 1)
    // This is sum_{k=1 to a} (k*b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // = b * (a * (a+1) / 2) + a
    long long sum_k_term;
    long long a_plus_1 = a + 1;
    long long inv2 = modInverse(2);
    long long sum_k_val = (a % MOD * (a_plus_1 % MOD)) % MOD;
    sum_k_val = (sum_k_val * inv2) % MOD;

    long long term1 = (b % MOD * sum_k_val) % MOD;
    long long term2 = a % MOD;
    sum_k_term = (term1 + term2) % MOD;

    // Total sum = sum_k_term * sum_r_term
    long long total_sum = (sum_k_term * sum_r_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> next_char_pos(L, std::vector<int>(26, L));
    for (int i = L - 1; i >= 0; --i) {
        if (i + 1 < L) {
            next_char_pos[i] = next_char_pos[i + 1];
        }
        next_char_pos[i][s[i] - 'a'] = i;
    }

    std::vector<std::vector<int>> prev_char_pos(L, std::vector<int>(26, -1));
    for (int i = 0; i < L; ++i) {
        if (i - 1 >= 0) {
            prev_char_pos[i] = prev_char_pos[i - 1];
        }
        prev_char_pos[i][s[i] - 'a'] = i;
    }

    std::vector<std::vector<int>> next_char_pos_cyclic(L, std::vector<int>(26));
    for (int i = 0; i < L; ++i) {
        for (int char_code = 0; char_code < 26; ++char_code) {
            int pos = next_char_pos[i][char_code];
            if (pos == L) { // Not found in s[i...L-1]
                pos = next_char_pos[0][char_code]; // Search in s[0...L-1]
            }
            next_char_pos_cyclic[i][char_code] = pos;
        }
    }

    std::vector<std::vector<int>> prev_char_pos_cyclic(L, std::vector<int>(26));
    for (int i = 0; i < L; ++i) {
        for (int char_code = 0; char_code < 26; ++char_code) {
            int pos = prev_char_pos[i][char_code];
            if (pos == -1) { // Not found in s[0...i]
                pos = prev_char_pos[L - 1][char_code]; // Search in s[0...L-1]
            }
            prev_char_pos_cyclic[i][char_code] = pos;
        }
    }

    double total_win_prob = 0.0;

    for (int k_true = 0; k_true < L; ++k_true) {
        char c1 = s[k_true];

        std::vector<int> possible_k_indices;
        for (int i = 0; i < L; ++i) {
            if (s[i] == c1) {
                possible_k_indices.push_back(i);
            }
        }

        if (possible_k_indices.size() == 1) {
            total_win_prob += 1.0;
            continue;
        }

        int max_p_wins = 0;
        int best_p = -1;

        for (int p = 1; p < L; ++p) {
            std::map<std::pair<char, char>, std::vector<int>> groups;
            for (int pk_idx : possible_k_indices) {
                char c2 = s[(pk_idx + p) % L];
                groups[{c1, c2}].push_back(pk_idx);
            }

            int current_p_wins = 0;
            for (auto const& [key, group_list] : groups) {
                if (group_list.size() == 1) {
                    current_p_wins++;
                }
            }

            if (current_p_wins > max_p_wins) {
                max_p_wins = current_p_wins;
                best_p = p;
            }
        }

        if (best_p != -1) {
            char c2_true = s[(k_true + best_p) % L];
            std::map<std::pair<char, char>, std::vector<int>> groups;
            for (int pk_idx : possible_k_indices) {
                char c2_val = s[(pk_idx + best_p) % L];
                groups[{c1, c2_val}].push_back(pk_idx);
            }
            if (groups[{c1, c2_true}].size() == 1) {
                total_win_prob += 1.0;
            }
        }
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

