#include <iostream>
#include <algorithm> // For std::min, std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n <= m by swapping if necessary.
        // This simplifies calculations as we always deal with the smaller coordinate first.
        if (n > m) {
            std::swap(n, m);
        }

        // Calculate the minimum number of moves required to reach (n, m)
        // This is max(|n|, |m|) if we only use diagonal moves and straight moves.
        // Since we assumed n, m >= 0 and n <= m, this is m.
        // The minimum number of moves is m.
        // If k < m, it's impossible to reach (n, m) in k moves.
        if (k < m) {
            std::cout << -1 << "\n";
            continue;
        }

        // The number of diagonal moves is limited by the smaller coordinate n.
        // We can make n diagonal moves to reach (n, n) or (-n, n) etc.
        // After n diagonal moves, we are at (n, n) (or equivalent).
        // The remaining distance is (0, m-n).
        // The remaining moves are k - n.
        long long remaining_moves = k - n;
        long long remaining_dist_y = m - n;

        // If remaining_moves is less than remaining_dist_y, it's impossible.
        // This check is actually covered by k < m, because if k >= m, then
        // k - n >= m - n, so remaining_moves >= remaining_dist_y.

        // Now we are at (n, n) and need to reach (n, m) in remaining_moves.
        // This means we need to cover a distance of (0, m-n) in remaining_moves.
        // We have remaining_dist_y to cover along the y-axis.
        // We have remaining_moves available.

        // Case 1: remaining_dist_y is even.
        // We need to make an even number of moves to cover an even distance.
        // If remaining_moves is odd, we can't reach (n, m) from (n, n)
        // in remaining_moves while covering an even distance (m-n).
        // We need to "waste" one move.
        // Example: (0,0) to (0,2) in 3 moves. (0,0)->(0,1)->(0,0)->(0,1) is 3 moves, but ends at (0,1).
        // (0,0)->(0,1)->(0,2)->(0,1) is 3 moves, ends at (0,1).
        // (0,0)->(0,1)->(0,2)->(1,2) is 3 moves, ends at (1,2).
        // The parity of (x+y) changes with each move.
        // (n,n) has parity (n+n) = 2n (even).
        // (n,m) has parity (n+m).
        // If remaining_moves is odd, (n,m) must have odd parity (n+m).
        // If remaining_moves is even, (n,m) must have even parity (n+m).
        // This is equivalent to checking if (k - (n+m)) is even.
        // Or, (k - n - m) % 2 == 0.
        // Or, (k - n) % 2 == (m % 2).
        // Or, remaining_moves % 2 == remaining_dist_y % 2.

        if ((remaining_moves % 2) == (remaining_dist_y % 2)) {
            // If parities match, we can reach (n, m) from (n, n) in remaining_moves.
            // The maximum number of diagonal moves is n (initial) + (k-n) (remaining moves).
            // All remaining moves can be non-diagonal, or we can use diagonal moves
            // that don't change the x-coordinate (e.g., (x,y) -> (x+1, y+1) then (x+1, y+1) -> (x,y)).
            // But we want to maximize diagonal moves.
            // The initial n moves are diagonal.
            // The remaining k-n moves are used to cover m-n distance.
            // We can make (m-n) straight moves along y-axis.
            // This leaves (k-n) - (m-n) = k-m moves.
            // These k-m moves must be "wasted" by moving back and forth.
            // Each pair of wasted moves can be (x,y)->(x+1,y+1)->(x,y) which is 2 diagonal moves.
            // Or (x,y)->(x+1,y)->(x,y) which is 0 diagonal moves.
            // To maximize diagonal moves, we want to use diagonal moves for the wasted steps.
            // Each wasted move can be a diagonal move if we pair it up.
            // So, k-m moves can be used as (k-m)/2 pairs of diagonal moves.
            // Total diagonal moves = n (initial) + (k-m) (wasted moves, if they are diagonal).
            // This is k - (m-n).
            // The number of diagonal moves is n + (k-n) = k.
            // But this is only if we can make all k moves diagonal.
            // The maximum number of diagonal moves is k.
            // However, we must reach (n,m).
            // The number of diagonal moves is n + (k-n) = k.
            // This is the case where we make n diagonal moves to (n,n), and then
            // k-n moves to reach (n,m).
            // If (k-n) is even, we can make (k-n)/2 pairs of (0,1) and (0,-1) moves,
            // or (1,1) and (-1,-1) moves.
            // The maximum number of diagonal moves is k.
            // But we need to consider the parity of (k-n) and (m-n).
            // If (k-n) and (m-n) have the same parity, we can reach (n,m) from (n,n).
            // The number of diagonal moves is n + (k-n) = k.
            // This is because we can make n diagonal moves to (n,n).
            // Then we have k-n moves left. We need to cover m-n distance.
            // We can make m-n moves in the y-direction (e.g., (0,1)).
            // This leaves k-n-(m-n) = k-m moves.
            // These k-m moves must be "wasted".
            // If k-m is even, we can make (k-m)/2 pairs of (0,1) and (0,-1) moves.
            // If k-m is odd, we can make (k-m-1)/2 pairs of (0,1) and (0,-1) moves,
            // and one additional (0,1) or (0,-1) move.
            // The maximum number of diagonal moves is n + (k-m).
            // This is because we make n diagonal moves to reach (n,n).
            // Then we make m-n straight moves along y-axis.
            // This leaves k-m moves. These k-m moves can be made diagonal by
            // moving (x,y) -> (x+1,y+1) -> (x,y) or similar.
            // So, total diagonal moves = n + (k-m).
            // This is correct if k-m is even.
            // If k-m is odd, we can make n diagonal moves to (n,n).
            // Then we make m-n straight moves along y-axis.
            // This leaves k-m moves.
            // If k-m is odd, we can make (k-m-1) diagonal moves (by pairing them up)
            // and one straight move.
            // So, total diagonal moves = n + (k-m-1).
            // This is equivalent to k-1 if k-m is odd.
            // This is equivalent to k if k-m is even.
            // This can be written as k if (k-m) is even, and k-2 if (k-m) is odd.
            // No, it's k if (k-m) is even, and k-1 if (k-m) is odd.
            // Let's re-evaluate.
            // We make n diagonal moves to reach (n,n).
            // We have k-n moves left. We need to reach (n,m).
            // The remaining distance is (0, m-n).
            // We need to make at least m-n moves.
            // We have k-n moves.
            // The number of "wasted" moves is (k-n) - (m-n) = k-m.
            // If k-m is even, we can use all k-m moves as pairs of (0,1) and (0,-1) or (1,1) and (-1,-1).
            // To maximize diagonal moves, we use (1,1) and (-1,-1) for wasted moves.
            // So, n diagonal moves + (k-m) diagonal moves = n + k - m.
            // This is the maximum.
            // If k-m is odd, we have one "wasted" move that cannot be paired up.
            // This one move must be a non-diagonal move (e.g., (0,1) or (0,-1)).
            // So, n diagonal moves + (k-m-1) diagonal moves = n + k - m - 1.
            // This is the maximum.
            // Combining these: n + k - m - ( (k-m) % 2 ).
            // This is the correct formula.
            std::cout << n + (k - n) - ( (m - n) % 2 ) << "\n";
        } else {
            // If parities don't match, we cannot reach (n, m) from (n, n) in remaining_moves
            // using only straight moves along y-axis and paired diagonal moves.
            // We need to "waste" one more move to change parity.
            // This means we need to make one more non-diagonal move.
            // So, the total number of diagonal moves will be n + (k-n) - 1 = k-1.
            // But we need to consider the parity of (k-m).
            // If (k-n) and (m-n) have different parities, it means (k-m) is odd.
            // We need to make one more non-diagonal move.
            // So, the maximum number of diagonal moves is n + (k-n) - 1 = k-1.
            // This is because we make n diagonal moves to (n,n).
            // We have k-n moves left. We need to cover m-n distance.
            // Since (k-n) and (m-n) have different parities, (k-n) - (m-n) = k-m is odd.
            // We need to make m-n moves along y-axis.
            // We have k-m "wasted" moves. Since k-m is odd, we can make (k-m-1) diagonal moves
            // and one non-diagonal move.
            // So, total diagonal moves = n + (k-m-1).
            // This is equivalent to k-1 if k-m is odd.
            // This is the correct formula.
            std::cout << n + (k - n) - 1 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_and_mask = 1023; // All bits set (0b1111111111)
    int current_or_mask = 0;    // All bits clear (0b0000000000)
    int current_xor_mask = 0;   // All bits clear (0b0000000000)

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        if (op_char == '&') {
            current_and_mask &= val;
            current_or_mask &= val;
            current_xor_mask &= val;
        } else if (op_char == '|') {
            current_and_mask |= val;
            current_or_mask |= val;
            current_xor_mask |= val;
        } else if (op_char == '^') {
            current_and_mask ^= val;
            current_or_mask ^= val;
            current_xor_mask ^= val;
        }
    }

    std::vector<std::pair<char, int>> result_ops;

    // Determine the final AND constant
    // If input bit is 0, output bit is (0 & current_and_mask_bit) | (0 & current_or_mask_bit) ^ current_xor_mask_bit
    // which simplifies to 0 | 0 ^ current_xor_mask_bit = current_xor_mask_bit
    // So, if current_xor_mask_bit is 0, final_and_const_bit is 0.
    // If current_xor_mask_bit is 1, final_and_const_bit is 1.
    // This means final_and_const_bit = current_xor_mask_bit for the 0-input case.
    // Let's call this `val_if_input_0`.
    int val_if_input_0 = current_xor_mask; // This is the value of (0 & A) | (0 & O) ^ X = X

    // Determine the final XOR constant
    // If input bit is 1, output bit is (1 & current_and_mask_bit) | (1 & current_or_mask_bit) ^ current_xor_mask_bit
    // which simplifies to current_and_mask_bit | current_or_mask_bit ^ current_xor_mask_bit
    // Let's call this `val_if_input_1`.
    int val_if_input_1 = (current_and_mask | current_or_mask) ^ current_xor_mask;

    // The final transformation for an input `x` is `(x & A_final) | O_final ^ X_final`.
    // We need to find A_final, O_final, X_final such that:
    // For input 0: (0 & A_final) | O_final ^ X_final = O_final ^ X_final = val_if_input_0
    // For input 1: (1 & A_final) | O_final ^ X_final = A_final | O_final ^ X_final = val_if_input_1

    // Let's find A_final, O_final, X_final bit by bit.
    // For each bit `j` from 0 to 9:
    // Let `x0_j` be the j-th bit of `val_if_input_0`.
    // Let `x1_j` be the j-th bit of `val_if_input_1`.
    // We need `(O_final_j ^ X_final_j) == x0_j`
    // We need `(A_final_j | O_final_j ^ X_final_j) == x1_j`

    // Case 1: x0_j = 0, x1_j = 0
    // O_final_j ^ X_final_j = 0  => O_final_j = X_final_j
    // A_final_j | (O_final_j ^ X_final_j) = A_final_j | 0 = 0 => A_final_j = 0
    // So, A_final_j = 0, O_final_j = X_final_j.
    // To minimize operations, we can choose O_final_j = 0, X_final_j = 0.
    // This means the bit is always 0, regardless of input.
    // This is achieved by `& 0`.

    // Case 2: x0_j = 0, x1_j = 1
    // O_final_j ^ X_final_j = 0  => O_final_j = X_final_j
    // A_final_j | (O_final_j ^ X_final_j) = A_final_j | 0 = 1 => A_final_j = 1
    // So, A_final_j = 1, O_final_j = X_final_j.
    // To minimize operations, we can choose O_final_j = 0, X_final_j = 0.
    // This means the bit is `x & 1`.
    // This is achieved by `& 1`.

    // Case 3: x0_j = 1, x1_j = 0
    // O_final_j ^ X_final_j = 1
    // A_final_j | (O_final_j ^ X_final_j) = A_final_j | 1 = 0 => IMPOSSIBLE (A_final_j must be 0 or 1)
    // This means the bit is always 1 if input is 0, and always 0 if input is 1.
    // This is `x ^ 1`.
    // This is achieved by `^ 1`.

    // Case 4: x0_j = 1, x1_j = 1
    // O_final_j ^ X_final_j = 1
    // A_final_j | (O_final_j ^ X_final_j) = A_final_j | 1 = 1 => A_final_j can be 0 or 1.
    // To minimize operations, we can choose A_final_j = 0.
    // Then O_final_j ^ X_final_j = 1.
    // This means the bit is always 1, regardless of input.
    // This is achieved by `| 1`.

    // Let's construct the final A, O, X masks.
    int final_and_const = 0;
    int final_or_const = 0;
    int final_xor_const = 0;

    for (int j = 0; j < 10; ++j) {
        int bit_x0 = (val_if_input_0 >> j) & 1;
        int bit_x1 = (val_if_input_1 >> j) & 1;

        if (bit_x0 == 0 && bit_x1 == 0) { // Output bit is always 0
            // Achieved by `& 0`
            // (x & 0) | 0 ^ 0 = 0
            // A_final_j = 0, O_final_j = 0, X_final_j = 0
            // No change to final_and_const, final_or_const, final_xor_const for this bit
        } else if (bit_x0 == 0 && bit_x1 == 1) { // Output bit is `x`
            // Achieved by `& 1`
            // (x & 1) | 0 ^ 0 = x
            final_and_const |= (1 << j);
        } else if (bit_x0 == 1 && bit_x1 == 0) { // Output bit is `x ^ 1`
            // Achieved by `^ 1`
            // (x & 0) | 0 ^ 1 = x ^ 1
            final_xor_const |= (1 << j);
        } else { // bit_x0 == 1 && bit_x1 == 1 // Output bit is always 1
            // Achieved by `| 1`
            // (x & 0) | 1 ^ 0 = 1
            final_or_const |= (1 << j);
        }
    }

    // Add operations if their constants are non-zero
    if (final_and_const != 1023) { // If not all bits are 1, we need an AND operation
        result_ops.push_back({'&', final_and_const});
    }
    if (final_or_const != 0) { // If any bit is 1, we need an OR operation
        result_ops.push_back({'|', final_or_const});
    }
    if (final_xor_const != 0) { // If any bit is 1, we need an XOR operation
        result_ops.push_back({'^', final_xor_const});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
