#include <vector>
#include <cmath>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substring_count = 0;

    // Iterate through all possible starting positions l
    for (int l = 0; l < n; ++l) {
