// Using long long for y to prevent overflow
// Using int for x and array indices as n <= 2e5

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1); // a[0] is unused, a[1] will be set for each query
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    // dp_x[i] stores the final x value if we start at x=i and perform one full cycle (step 2 then step 3)
    // dp_y[i] stores the total y added if we start at x=i and perform one full cycle
    // dp_x[i] and dp_y[i] are only valid if the intermediate x values stay within [1, n]
    // If x goes out of bounds, we store the final x and y values directly.
    // We use a pair {final_x, final_y_contribution}
    std::vector<std::pair<int, long long>> dp(n + 1);
    std::vector<bool> visited(n + 1, false); // For cycle detection during DP calculation

    // Iterate backwards to fill DP table
    for (int i = n; i >= 1; --i) {
        // Simulate one full cycle starting at x = i
        // Initial state for this simulation: current_x = i, current_y_contribution = 0

        // Step 2: x = x + a[x], y = y + a[x]
        long long val_step2 = a[i];
        int next_x_after_step2 = i + val_step2;
        long long current_y_contribution = val_step2;

        if (next_x_after_step2 <= 0 || next_x_after_step2 > n) {
            // Terminates after step 2
            dp[i] = {next_x_after_step2, current_y_contribution};
        } else {
            // Step 3: x = x - a[x], y = y + a[x]
            long long val_step3 = a[next_x_after_step2];
            int next_x_after_step3 = next_x_after_step2 - val_step3;
            current_y_contribution += val_step3;

            if (next_x_after_step3 <= 0 || next_x_after_step3 > n) {
                // Terminates after step 3
                dp[i] = {next_x_after_step3, current_y_contribution};
            } else {
                // Does not terminate, lands on next_x_after_step3.
                // We can use the precomputed DP value for next_x_after_step3.
                // This is valid because we iterate backwards.
                dp[i] = {dp[next_x_after_step3].first, current_y_contribution + dp[next_x_after_step3].second};
            }
        }
    }

    // For each query (a_1 from 1 to n-1)
    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a_1 for the current query

        // Initial state: x = 1, y = 0
        // Step 2: x = x + a[x], y = y + a[x]
        long long val_step2 = a[1];
        int current_x = 1 + val_step2;
        long long total_y = val_step2;

        if (current_x <= 0 || current_x > n) {
            // Terminates after step 2
            std::cout << total_y << "\n";
        } else {
            // Step 3: x = x - a[x], y = y + a[x]
            long long val_step3 = a[current_x];
            current_x = current_x - val_step3;
            total_y += val_step3;

            if (current_x <= 0 || current_x > n) {
                // Terminates after step 3
                std::cout << total_y << "\n";
            } else {
                // Does not terminate, lands on current_x.
                // Now we can use the precomputed DP value for current_x.
                // The DP table `dp` stores the result of starting a *full cycle* from `current_x`.
                // The `dp` values were computed assuming `a[1]` is fixed to its original value (or not used).
                // However, for `i >= 2`, `a[i]` is fixed.
