#include <iostream>
#include <string>
#include <numeric>
#include <algorithm>

int count_ones(const std::string& s) {
    return std::count(s.begin(), s.end(), '1');
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string a, b;
    std::cin >> a >> b;

    int ones_a = count_ones(a);
    int ones_b = count_ones(b);

    // If ones_a is odd, we can append '1'. If even, we can append '0'.
    // This means we can always increase the number of ones by 1 if it's odd,
    // or keep it the same if it's even.
    // Effectively, we can always make the number of ones in 'a' become ones_a + 1
    // by appending parity.
    // For example, if a has 2 ones, parity is 0. a -> a0. Still 2 ones.
    // If a has 3 ones, parity is 1. a -> a1. Now 4 ones.
    // So, if we have `k` ones, we can get `k` ones (by appending '0' if `k` is even)
    // or `k+1` ones (by appending '1' if `k` is odd).
    // The maximum number of ones we can achieve is `|a| + 1` if `|a|` is odd,
    // or `|a|` if `|a|` is even.
    // More simply, we can always add a '1' if the current count of '1's is odd.
    // If the current count of '1's is even, we add a '0', keeping the count even.
    // To get an odd count of '1's from an even count, we need to add a '1'.
    // This means we need to have an odd count of '1's to begin with, or
    // we need to have an odd count of '1's after some operations.
    // The crucial point is that if we have `k` ones, we can always reach `k` or `k+1` ones
    // by appending parity.
    // If `k` is even, we can append '0' to get `k` ones.
    // If `k` is odd, we can append '1' to get `k+1` ones.
    // So, the maximum number of ones we can achieve is `ones_a` if `ones_a` is even,
    // and `ones_a + 1` if `ones_a` is odd.
    // This can be written as `ones_a + (ones_a % 2 == 1 ? 1 : 0)`.
    // Or simply `ones_a + (ones_a % 2)`.

    int max_ones_a_reachable = ones_a + (ones_a % 2);

    if (max_ones_a_reachable >= ones_b && a.length() <= b.length()) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

