#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    long long min_goodness = std::numeric_limits<long long>::max();
    std::vector<int> best_partition(n);

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    long long current_goodness_case1 = (a[n - 2].value + a[n - 1].value) - (a[0].value + a[1].value);
    if (current_goodness_case1 < min_goodness) {
        min_goodness = current_goodness_case1;
        for (int i = 0; i < n; ++i) {
            best_partition[a[i].original_index] = 1;
        }
    }

    // Case 2: Partition into two non-empty subsequences.
    // The optimal strategy for minimizing goodness often involves putting a[0] and a[1] in different groups
    // or a[n-1] and a[n-2] in different groups, or some combination.
    // Let's consider the partition where a[0] is in group 1, and a[1]...a[n-1] are in group 2.
    // Or more generally, a[0] is in group 1, and a[1] is in group 2.
    // The critical observation is that if we split the smallest element a[0] from the rest,
    // or the largest element a[n-1] from the rest, we can control the min/max values.

    // Consider a partition where a[0] is in group 1, and a[1]...a[n-1] are in group 2.
    // min_f:
    //   - a[1].value + a[2].value (if n >= 3, same group 2)
    //   - a[0].value + a[1].value + h (different groups)
    // max_f:
    //   - a[n-2].value + a[n-1].value (same group 2)
    //   - a[0].value + a[n-1].value + h (different groups)

    // Let's analyze the values:
    // min_val_same_group: a[1].value + a[2].value (if n >= 3)
    // min_val_diff_group: a[0].value + a[1].value + h
    // max_val_same_group: a[n-2].value + a[n-1].value
    // max_val_diff_group: a[0].value + a[n-1].value + h

    // The minimum possible f value will be min(a[0].value + a[1].value + h, a[1].value + a[2].value (if n>=3))
    // The maximum possible f value will be max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h)

    // This specific partition strategy: a[0] in group 1, a[1]...a[n-1] in group 2.
    // This is a specific case of splitting.
    // The values are:
    // f_min = min(a[0].value + a[1].value + h, a[1].value + a[2].value (if n>=3))
    // f_max = max(a[0].value + a[n-1].value + h, a[n-2].value + a[n-1].value)

    // Let's consider the four critical sums:
    // S1 = a[0].value + a[1].value
    // S2 = a[0].value + a[n-1].value
    // S3 = a[n-2].value + a[n-1].value
    // S4 = a[1].value + a[2].value (if n >= 3)

    // Option A: a[0] is in group 1, a[1]...a[n-1] are in group 2.
    // min_f = min(a[0].value + a[1].value + h, (n >= 3 ? a[1].value + a[2].value : std::numeric_limits<long long>::max()))
    // max_f = max(a[0].value + a[n-1].value + h, a[n-2].value + a[n-1].value)
    // This is the partition where a[0] is separated from the rest.
    // All elements a[1]...a[n-1] are in the same group (group 2).
    // a[0] is in group 1.
    // The minimum value of f will be min(a[0].value + a[1].value + h, a[1].value + a[2].value (if n>=3)).
    // The maximum value of f will be max(a[0].value + a[n-1].value + h, a[n-2].value + a[n-1].value).

    long long current_min_f_A;
    if (n >= 3) {
        current_min_f_A = std::min(a[0].value + a[1].value + h, a[1].value + a[2].value);
    } else { // n=2, only a[0] and a[1]. a[0] in group 1, a[1] in group 2.
        current_min_f_A = a[0].value + a[1].value + h;
    }
    long long current_max_f_A = std::max(a[0].value + a[n - 1].value + h, a[n - 2].value + a[n - 1].value);
    long long goodness_A = current_max_f_A - current_min_f_A;

    if (goodness_A < min_goodness) {
        min_goodness = goodness_A;
        best_partition[a[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            best_partition[a[i].original_index] = 2;
        }
    }

    // Option B: a[0] and a[1] are in group 1. a[2]...a[n-1] are in group 2.
    // This is only possible if n >= 2.
    // If n=2, this is the same as Case 1 (all in group 1).
    // If n=3, a[0], a[1] in group 1, a[2] in group 2.
    // min_f = min(a[0].value + a[1].value, a[0].value + a[2].value + h, a[1].value + a[2].value + h)
    // max_f = max(a[0].value + a[1].value, a[0].value + a[2].value + h, a[1].value + a[2].value + h)
    // This is the partition where a[0] and a[1] are together, and separated from a[2]...a[n-1].
    // Group 1: {a[0], a[1]}
    // Group 2: {a[2], ..., a[n-1]}
    //
    // min_f:
    //   - a[0].value + a[1].value (same group 1)
    //   - a[2].value + a[3].value (if n >= 4, same group 2)
    //   - a[0].value + a[2].value + h (different groups)
    // max_f:
    //   - a[0].value + a[1].value (same group 1)
    //   - a[n-2].value + a[n-1].value (if n >= 4, same group 2)
    //   - a[1].value + a[n-1].value + h (different groups)

    // The minimum possible f value will be min(a[0].value + a[1].value, a[0].value + a[2].value + h, a[2].value + a[3].value (if n>=4))
    // The maximum possible f value will be max(a[0].value + a[1].value, a[1].value + a[n-1].value + h, a[n-2].value + a[n-1].value (if n>=4))

    // This is the partition where a[0] and a[1] are in group 1, and a[2]...a[n-1] are in group 2.
    // This is only relevant if n >= 3. If n=2, it's the same as Case 1.
    if (n >= 3) {
        long long current_min_f_B = a[0].value + a[1].value; // min from group 1
        current_min_f_B = std::min(current_min_f_B, a[0].value + a[2].value + h); // min from diff groups
        if (n >= 4) {
            current_min_f_B = std::min(current_min_f_B, a[2].value + a[3].value); // min from group 2
        }

        long long current_max_f_B = a[0].value + a[1].value; // max from group 1
        current_max_f_B = std::max(current_max_f_B, a[1].value + a[n - 1].value + h); // max from diff groups
        if (n >= 4) {
            current_max_f_B = std::max(current_max_f_B, a[n - 2].value + a[n - 1].value); // max from group 2
        }

        long long goodness_B = current_max_f_B - current_min_f_B;

        if (goodness_B < min_goodness) {
            min_goodness = goodness_B;
            best_partition[a[0].original_index] = 1;
            best_partition[a[1].original_index] = 1;
            for (int i = 2; i < n; ++i) {
                best_partition[a[i].original_index] = 2;
            }
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

