    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_s.insert(s[i]);
        if (i > 0) {
            adj[s[i]].insert(s[i-1]);
            adj[s[i-1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_prefix = "";
    std::vector<bool> visited(26, false); // 'a' -> 0, 'b' -> 1, etc.

    for (char c_char : used_in_s) {
        int c_idx = c_char - 'a';
        if (!visited[c_idx]) {
            if (adj[c_char].size() <= 1) { // Start a new chain
                std::string current_chain = "";
                char current_node = c_char;

                while (true) {
                    if (visited[current_node - 'a']) {
                        // This can happen if we find a cycle or a character already part of another chain.
                        // For this problem, it implies an issue if it's not the end of a chain.
                        // If current_node is already visited, it means we've hit a node that's part of an existing chain.
                        // This should only happen if we're trying to extend a chain into an already formed one,
                        // which is fine if it's the end of the chain.
                        // But if it's a middle node, it means a character has more than 2 neighbors, which is caught earlier.
                        // So, if we reach a visited node, it must be the end of the chain.
                        break; 
                    }
                    visited[current_node - 'a'] = true;
                    current_chain += current_node;

                    char next_node = '\0';
                    for (char neighbor : adj[current_node]) {
                        if (!visited[neighbor - 'a']) {
                            next_node = neighbor;
                            break;
                        }
                    }

                    if (next_node == '\0') { // No unvisited neighbors
                        break;
                    }
                    current_node = next_node;
                }
                layout_prefix += current_chain;
            }
        }
    }

    if (layout_prefix.length() != used_in_s.size()) {
        // This means there's a cycle or a character with degree > 2 that wasn't caught.
        // Degree > 2 is caught. So it must be a cycle.
        // A cycle means a character has two neighbors, and following them leads back to itself.
        // E.g., a-b-c-a. This would form a chain 'abc' and then 'a' would be visited.
        // If we start at 'a', we go 'a', then 'b', then 'c'. From 'c', 'a' is a neighbor but visited.
        // So the chain would be 'abc'.
        // The issue is if we have multiple components that are not simple paths.
        // For example, if we have a-b, c-d, and then a-c. This would be a-b, c-d, and then a-c.
        // This would mean 'a' has neighbors 'b' and 'c'. 'b' has 'a'. 'c' has 'a' and 'd'. 'd' has 'c'.
        // This is fine.
        // The only way layout_prefix.length() != used_in_s.size() can happen
        // is if there's a character with degree > 2, which is already checked.
        // Or if there's a cycle that isn't a simple path.
        // E.g., a-b, b-c, c-a. This forms a cycle.
        // If we start at 'a', chain becomes 'abc'. All visited.
        // This condition should not be necessary if degree check is correct.
        // Let's re-evaluate. If a character has degree 2, it must be in the middle of a path or a cycle.
        // If it's a cycle, say a-b-c-a.
        // Start at 'a'. visited[a]=true, chain="a". Neighbors of 'a': 'b', 'c'. Pick 'b'.
        // current_node='b'. visited[b]=true, chain="ab". Neighbors of 'b': 'a', 'c'. 'a' visited. Pick 'c'.
        // current_node='c'. visited[c]=true, chain="abc". Neighbors of 'c': 'a', 'b'. Both visited. Break.
        // layout_prefix = "abc". used_in_s = {a,b,c}. Lengths match.
        // So, this check is not for cycles.
        // It's for disconnected components that are not simple paths.
        // E.g., a-b, c-d, e-f.
        // If we start at 'a', we get 'ab'.
        // Then we iterate through used_in_s again. 'c' is not visited. Start at 'c'. Get 'cd'.
        // Then 'e' is not visited. Start at 'e'. Get 'ef'.
        // layout_prefix = "abcdef". used_in_s = {a,b,c,d,e,f}. Lengths match.
        // The only way layout_prefix.length() != used_in_s.size() is if there's a character with degree > 2.
        // This check is redundant if the degree check is correct.
        // However, it's a good sanity check. If it fails, it means something is wrong.
        // For example, if the graph is not a collection of disjoint paths/cycles.
        // But the degree check already ensures it's a collection of disjoint paths/cycles.
        // So, this condition should always be true if the degree check passes.
    }

    std::cout << "YES\n";
