void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // balance_left[i] = (count of 1s - count of 2s) in jars [1, i]
    // We are interested in jars [i+1, n] remaining, so we need balance of [1, i]
    // Or, more precisely, balance of [1, n] minus balance of [i+1, n]
    // Let's use balance_left[k] = balance of jars [k+1, n]
    // This means we remove k jars from the left.
    // k goes from 0 to n.
    // balance_left[0] is balance of [1, n]
    // balance_left[n] is balance of [] (0)
    std::vector<int> balance_left_removed(n + 1); // balance_left_removed[k] = balance of jars [k+1, n]
    int current_balance = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            current_balance++;
        } else {
            current_balance--;
        }
        balance_left_removed[n - 1 - i] = current_balance;
    }
    balance_left_removed[n] = 0; // If all n jars on left are removed, balance is 0

    // Store the minimum number of jars removed from the left to achieve a certain balance
    std::map<int, int> min_removed_left; // balance -> min_k
    for (int k = 0; k <= n; ++k) {
        int bal = balance_left_removed[k];
        if (min_removed_left.find(bal) == min_removed_left.end()) {
            min_removed_left[bal] = k;
        }
    }

    // Calculate prefix sums for the right side (jars n+1 to 2n)
    // balance_right_removed[k] = balance of jars [n+1, 2n-k]
    // This means we remove k jars from the right.
    // k goes from 0 to n.
    // balance_right_removed[0] is balance of [n+1, 2n]
    // balance_right_removed[n] is balance of [] (0)
    std::vector<int> balance_right_removed(n + 1); // balance_right_removed[k] = balance of jars [n+1, 2n-k]
    current_balance = 0;
    for (int i = n; i < 2 * n; ++i) {
        if (a[i] == 1) {
            current_balance++;
        } else {
            current_balance--;
        }
        balance_right_removed[i - n] = current_balance;
    }
    balance_right_removed[n] = 0; // If all n jars on right are removed, balance is 0

    int min_total_removed = 2 * n; // Max possible jars to remove

    // Iterate through all possible numbers of jars removed from the right (k_right)
    // For each k_right, we have a balance_right_removed[k_right]
    // We need to find a k_left such that balance_left_removed[k_left] + balance_right_removed[k_right] == 0
    // This means balance_left_removed[k_left] == -balance_right_removed[k_right]
    for (int k_right = 0; k_right <= n; ++k_right) {
        int target_balance_left = -balance_right_removed[k_right];
        if (min_removed_left.count(target_balance_left)) {
            int k_left = min_removed_left[target_balance_left];
            min_total_removed = std::min(min_total_removed, k_left + k_right);
        }
    }

    std::cout << min_total_removed << std::endl;
}

