#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // Reversing the permutation p always yields a permutation p'
    // such that F(p) = F(p').
    //
    // Let p = [p_1, p_2, ..., p_n].
    // The sums of adjacent elements are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
    //
    // Let p' = [p_n, p_{n-1}, ..., p_1].
    // The sums of adjacent elements for p' are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
    //
    // These two sets of sums are identical, just in reverse order.
    // For example, p_1+p_2 is the last sum in p', and p_{n-1}+p_n is the first sum in p'.
    // Since F(p) and F(p') involve sorting these sums, their fingerprints will be identical.
    //
    // The only case where p' might be equal to p is if p is a palindrome.
    // However, a permutation of distinct integers from 1 to n cannot be a palindrome
    // unless n=1 (which is not allowed, n>=2) or n=0.
    // For n >= 2, p_1 must be different from p_n (unless n=1).
    // For example, if p = [1, 2, 3, 2, 1], this is not a permutation because 1 and 2 appear twice.
    // A permutation like [1, 2, 3] reversed is [3, 2, 1], which is different.
    // A permutation like [1, 2] reversed is [2, 1], which is different.
    //
    // Therefore, reversing the permutation always produces a different permutation
    // with the same fingerprint.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

