#include <algorithm>

void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_pile1_haybales = a[0];

    for (int i = 1; i < n; ++i) { // Iterate through piles from index 1 (pile 2) to n-1 (pile n)
        int pile_index = i + 1; // Convert 0-indexed i to 1-indexed pile number
        int cost_per_haybale = pile_index - 1; // Cost to move one haybale from pile_index to pile 1

        if (d < cost_per_haybale) {
            // Not enough days to move even one haybale from this pile.
            // Since costs increase with pile_index, we can't move from further piles either.
            break;
        }

        // Calculate how many haybales can be moved from this pile
        int haybales_to_move = a[i];
        int max_haybales_possible_with_days = d / cost_per_haybale;

        int actual_haybales_moved = std::min(haybales_to_move, max_haybales_possible_with_days);

        current_pile1_haybales += actual_haybales_moved;
        d -= actual_haybales_moved * cost_per_haybale;
    }

    std::cout << current_pile1_haybales << std::endl;
}

