void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << std::endl;
    } else {
        // For n >= 2, we can construct a number.
        // The strategy is to use '2' as the first digit,
        // '3' as the second digit, and '9' for all subsequent digits.
        // This number will be 2399...9.
        //
        // Let s be this number.
        // The digits are 2, 3, and 9.
        //
        // 1. Divisibility by 2:
        // The number ends in 9, which is odd. So, s is not divisible by 2.
        //
        // 2. Divisibility by 3:
        // The sum of digits is 2 + 3 + (n-2)*9.
        // Sum = 5 + 9n - 18 = 9n - 13.
        // For s to be divisible by 3, 9n - 13 must be divisible by 3.
        // Since 9n is always divisible by 3, this means -13 must be divisible by 3.
        // -13 is not divisible by 3 (-13 = -4*3 - 1).
        // So, s is not divisible by 3.
        //
        // 3. Divisibility by 9:
        // For s to be divisible by 9, 9n - 13 must be divisible by 9.
        // Since 9n is always divisible by 9, this means -13 must be divisible by 9.
        // -13 is not divisible by 9 (-13 = -2*9 + 5).
        // So, s is not divisible by 9.
        //
        // All digits are non-zero (2, 3, 9).
        // The number has n digits.
        // The number is positive.
        // This construction works for all n >= 2.

        std::cout << '2';
        if (n > 1) {
            std::cout << '3';
        }
        for (int i = 0; i < n - 2; ++i) {
            std::cout << '9';
        }
        std::cout << std::endl;
    }
}

