#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    // Update has_pos_one and has_neg_one for elements a[0]...a[i-1]
    // For a[0], it's already checked.
    // For a[i], we need to know if there's a 1 or -1 among a[0]...a[i-1].
    // So, we iterate from i=1 to n-1.
    // has_pos_one and has_neg_one will track if a 1 or -1 has been seen *before* the current index i.
    bool current_has_pos_one = (a[0] == 1);
    bool current_has_neg_one = (a[0] == -1);

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!current_has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!current_has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation needed for this element.
        // In any case, update current_has_pos_one and current_has_neg_one for the next iteration.
        if (a[i] == 1) {
            current_has_pos_one = true;
        } else if (a[i] == -1) {
            current_has_neg_one = true;
        }
    }

    std::cout << "YES\n";
}

