void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n); // 0 for white (c), 1 for black (d)

    bool T_is_even = (T % 2 == 0);
    long long T_half = T / 2;
    int T_half_color_toggle = 0; // 0 for white, 1 for black

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < T_half) {
            p[i] = 0; // Smaller elements go to white (c)
        } else if (a[i] > T_half) {
            p[i] = 1; // Larger elements go to black (d)
        } else { // a[i] == T_half
            if (T_is_even) {
                // Alternate colors for elements equal to T/2
                p[i] = T_half_color_toggle;
                T_half_color_toggle = 1 - T_half_color_toggle;
            } else {
                // T is odd, so T/2 is not an integer.
                // No two elements can sum to T if they are both T/2.
                // This case is actually covered by a[i] < T_half or a[i] > T_half
                // because T_half would be e.g. 3.5 for T=7, so no a[i] can be T_half.
                // However, if T_half is integer division, e.g. T=7, T_half=3.
                // Then a[i]=3 would be < T_half, a[i]=4 would be > T_half.
                // So this 'else' branch (a[i] == T_half) is only reached if T is even.
                // This branch is technically unreachable if T is odd and T_half is integer division.
                // But to be safe, if it somehow happens, assign to white.
                p[i] = 0; 
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

