#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);

    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) {
                max_val_in_row = std::max(max_val_in_row, a[i][j]);
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any p[i] is missing from 1 to n.
    // If n is not present in p, it means the actual p[i] for some i
    // must be n, and all other p[j] (j!=i) are less than n.
    // In this case, max_val_in_row for that i would be max(p[j] for j!=i),
    // which is n-1. So we need to find if n is missing.
    std::vector<bool> present(n + 1, false);
    for (int val : p) {
        if (val >= 1 && val <= n) { // Ensure val is within expected range
            present[val] = true;
        }
    }

    int missing_val = -1;
    for (int i = 1; i <= n; ++i) {
        if (!present[i]) {
            missing_val = i;
            break;
        }
    }

    // If a value is missing (it must be n), then one of the p[i] values
    // that was calculated as n-1 should actually be n.
    // We can pick any p[i] that is n-1 and change it to n.
    // The problem guarantees a solution exists, so n must be the missing value.
    if (missing_val != -1) { // This implies missing_val must be n
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; // Only one such p[i] needs to be changed
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
