#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_gap = 0;
        int last_R_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_R_pos = -1, it means the frog is at cell 0.
                             // If last_R_pos = i, it means the frog is at cell i.

        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1 (1-indexed).
                // The distance from the last 'R' (or 0) to this 'R' is (i+1) - (last_R_pos + 1).
                // If last_R_pos is -1, it means the previous 'R' was effectively at index -1 (cell 0).
                // So the distance is (i+1) - (0) = i+1.
                // If last_R_pos is some j, then the previous 'R' was at index j (cell j+1).
                // The distance is (i+1) - (j+1) = i - j.
                max_gap = std::max(max_gap, (i + 1) - (last_R_pos + 1));
                last_R_pos = i;
            }
        }
        // After iterating through the string, consider the gap from the last 'R' to n+1.
        // The last 'R' was at index last_R_pos (cell last_R_pos + 1).
        // The target is cell n+1.
        // The distance is (n+1) - (last_R_pos + 1).
        max_gap = std::max(max_gap, (int)s.length() + 1 - (last_R_pos + 1));

        std::cout << max_gap << "\n";
    }
    return 0;
}

