            if (open_count < target_open) {
                result += '(';
                open_count++;
            }
        } else { // c == ')'
            if (close_count < target_close && open_count > close_count) {
                result += ')';
                close_count++;
            }
        }
        if (open_count == target_open && close_count == target_close) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 1; // Cost for a 1-stair staircase (1 cell)
        long long k = 1;            // Represents the 'k' in 2^k - 1 stairs

        while (x >= current_cost) {
            x -= current_cost;
            count++;

            // Calculate cost for the next staircase
            // If current staircase has (2^k - 1) stairs, the next one has (2^(k+1) - 1) stairs.
            // The cost for a staircase with N stairs is N * (N+1) / 2.
            // The cost for a staircase with (2^k - 1) stairs is (2^k - 1) * 2^k / 2.
            // Let N_k = 2^k - 1. Cost_k = N_k * (N_k + 1) / 2 = (2^k - 1) * 2^k / 2.
            // Cost_{k+1} = (2^(k+1) - 1) * 2^(k+1) / 2.
            // The difference in cost is Cost_{k+1} - Cost_k.
            // This is not what we need. We need the cost of the *next* staircase.
            // The sequence of costs for nice staircases is:
            // k=1: N=1, Cost = 1*(2)/2 = 1
            // k=2: N=3, Cost = 3*(4)/2 = 6
            // k=3: N=7, Cost = 7*(8)/2 = 28
            // k=4: N=15, Cost = 15*(16)/2 = 120
            // The cost of the (k+1)-th nice staircase is (2^(k+1) - 1) * 2^k.
            // This is derived from the sum of squares formula: sum_{i=1 to k} i^2 = k(k+1)(2k+1)/6.
            // The problem states the cost of a nice staircase with N stairs is N*(N+1)/2.
            // The number of stairs N for a nice staircase is of the form 2^k - 1.
            // So, for k=1, N=1, cost = 1*(2)/2 = 1.
            // For k=2, N=3, cost = 3*(4)/2 = 6.
            // For k=3, N=7, cost = 7*(8)/2 = 28.
            // For k=4, N=15, cost = 15*(16)/2 = 120.
            // The cost of the (k+1)-th staircase is (2^(k+1) - 1) * (2^(k+1)) / 2.
            // This can be written as (2^(k+1) - 1) * 2^k.
            // The current_cost is for the staircase with 2^k - 1 stairs.
            // The next_cost will be for the staircase with 2^(k+1) - 1 stairs.
            // The formula for the cost of a staircase with (2^k - 1) stairs is (2^k - 1) * 2^k / 2.
            // Let's denote N_k = 2^k - 1.
            // Cost(N_k) = N_k * (N_k + 1) / 2 = (2^k - 1) * 2^k / 2.
            // The next cost will be Cost(N_{k+1}) = (2^(k+1) - 1) * 2^(k+1) / 2.
            // We can observe a pattern:
            // Cost(N_k) = (2^k - 1) * 2^(k-1).
            // So, current_cost = (2^k - 1) * 2^(k-1).
            // The next cost will be (2^(k+1) - 1) * 2^k.
            // This is equivalent to (2 * (2^k - 1) + 1) * 2^k.
            // Or, current_cost * 2 + (2^k * 2^k) / 2.
            // A simpler recurrence:
            // Cost(N_k) = (2^k - 1) * 2^(k-1)
            // Cost(N_{k+1}) = (2^(k+1) - 1) * 2^k
            // We can get Cost(N_{k+1}) from Cost(N_k) by:
            // Cost(N_{k+1}) = (2 * (2^k) - 1) * 2^k
            // Cost(N_{k+1}) = (2 * (N_k + 1) - 1) * (N_k + 1) / 2 * 2
            // This is not simple. Let's just compute it directly.
            // The number of stairs for the next nice staircase is (2 * (2^k - 1) + 1) = 2^(k+1) - 1.
            // The cost for the next nice staircase is (2^(k+1) - 1) * (2^(k+1)) / 2.
            // This is (2^(k+1) - 1) * 2^k.
            // We can update current_cost using k.
            // current_cost = (2^k - 1) * 2^(k-1)
            // next_cost = (2^(k+1) - 1) * 2^k
            // This is equivalent to:
            // current_cost = current_cost * 2 + (2^k * 2^k) / 2
            // No, this is not right.
            // The number of stairs for the current staircase is N = 2^k - 1.
            // The cost is N * (N+1) / 2.
            // The next staircase will have N' = 2 * N + 1 stairs.
            // Its cost will be N' * (N'+1) / 2.
            // Let's use N directly.
            // N_current = 2^k - 1.
            // N_next = 2^(k+1) - 1 = 2 * (2^k - 1) + 1 = 2 * N_current + 1.
            // Cost_next = N_next * (N_next + 1) / 2.

            long long N_current = (1LL << k) - 1; // Number of stairs for current nice staircase
            long long N_next = (1LL << (k + 1)) - 1; // Number of stairs for next nice staircase

            // Check for overflow before calculating N_next * (N_next + 1) / 2
            // N_next can be up to (2^62 - 1) if k+1 is 62.
            // N_next * (N_next + 1) can be up to (2^62 - 1) * 2^62, which is approx 2^124.
            // This will overflow long long.
            // The maximum value of x is 10^18.
            // The maximum cost we need to calculate is slightly above 10^18.
            // If N_next is around 2*10^9 (sqrt(2*10^18)), then N_next * (N_next+1)/2 is around 10^18.
            // 2^30 is approx 10^9. So N_next can be up to 2^30.
            // If k+1 = 30, N_next = 2^30 - 1. Cost = (2^30 - 1) * 2^30 / 2 = (2^30 - 1) * 2^29.
            // This is approx 10^9 * 0.5 * 10^9 = 0.5 * 10^18. This fits.
            // If k+1 = 31, N_next = 2^31 - 1. Cost = (2^31 - 1) * 2^30. This is approx 10^18.
            // If k+1 = 32, N_next = 2^32 - 1. Cost = (2^32 - 1) * 2^31. This is approx 2 * 10^18. This fits.
            // If k+1 = 33, N_next = 2^33 - 1. Cost = (2^33 - 1) * 2^32. This is approx 4 * 10^18. This fits.
            // If k+1 = 34, N_next = 2^34 - 1. Cost = (2^34 - 1) * 2^33. This is approx 8 * 10^18. This fits.
            // If k+1 = 35, N_next = 2^35 - 1. Cost = (2^35 - 1) * 2^34. This is approx 1.6 * 10^19. This will overflow.
            // So k+1 can go up to 34. k can go up to 33.
            // The loop will terminate when current_cost exceeds x.
            // The maximum value of k for which (1LL << (k+1)) - 1 is safe to calculate N_next * (N_next + 1) / 2
            // is when N_next * (N_next + 1) / 2 does not overflow long long.
            // N_next * (N_next + 1) / 2 <= LLONG_MAX (approx 9 * 10^18)
            // N_next * (N_next + 1) <= 2 * LLONG_MAX
            // N_next approx sqrt(2 * LLONG_MAX) approx sqrt(1.8 * 10^19) approx 4.2 * 10^9.
            // 2^32 approx 4.29 * 10^9. So N_next can be up to 2^32.
            // This means k+1 can be up to 32. So k can be up to 31.
            // If k=31, N_current = 2^31 - 1. current_cost = (2^31 - 1) * 2^30 approx 10^18.
            // N_next = 2^32 - 1. next_cost = (2^32 - 1) * 2^31 approx 2 * 10^18.
            // This is fine.
            // If k=32, N_current = 2^32 - 1. current_cost = (2^32 - 1) * 2^31 approx 2 * 10^18.
            // N_next = 2^33 - 1. next_cost = (2^33 - 1) * 2^32 approx 4 * 10^18.
            // This is fine.
            // If k=33, N_current = 2^33 - 1. current_cost = (2^33 - 1) * 2^32 approx 4 * 10^18.
            // N_next = 2^34 - 1. next_cost = (2^34 - 1) * 2^33 approx 8 * 10^18.
            // This is fine.
            // If k=34, N_current = 2^34 - 1. current_cost = (2^34 - 1) * 2^33 approx 8 * 10^18.
            // N_next = 2^35 - 1. next_cost = (2^35 - 1) * 2^34 approx 1.6 * 10^19. This will overflow.
            // So the loop should stop before k reaches 34.
            // The condition `x >= current_cost` will naturally handle this.
            // The maximum value of `current_cost` that can be stored in `long long` is `LLONG_MAX`.
            // The maximum `k` for which `(1LL << k) - 1` is a valid number of stairs and its cost fits in `long long`
            // is when `(1LL << k) - 1` is approximately `sqrt(2 * LLONG_MAX)`.
            // `sqrt(2 * 9 * 10^18)` is approximately `4.2 * 10^9`.
            // `2^32` is approximately `4.29 * 10^9`.
            // So `2^k - 1` can be up to `2^32 - 1`. This means `k` can be up to `32`.
            // If `k=32`, `N = 2^32 - 1`. Cost = `(2^32 - 1) * 2^31`. This is `2^63 - 2^31`, which fits in `long long`.
            // If `k=33`, `N = 2^33 - 1`. Cost = `(2^33 - 1) * 2^32`. This is `2^65 - 2^32`, which overflows `long long`.
            // So `k` will go up to `32` at most.
            // The loop will naturally terminate.

            k++;
            long long next_N = (1LL << k) - 1;
            // Check for potential overflow before calculating next_cost
            // next_N * (next_N + 1) / 2
            // If next_N is large, next_N + 1 might be 2^k.
            // So we are calculating (2^k - 1) * 2^k / 2 = (2^k - 1) * 2^(k-1).
            // If k=63, (2^63 - 1) * 2^62. This overflows.
            // The maximum k for which (2^k - 1) * 2^(k-1) fits in long long is k=32.
            // For k=32, cost = (2^32 - 1) * 2^31 = 2^63 - 2^31. This fits.
            // For k=33, cost = (2^33 - 1) * 2^32 = 2^65 - 2^32. This overflows.
            // So k will not exceed 32 in the loop.
            // The maximum value of k will be 32.
            // The maximum value of current_cost will be (2^32 - 1) * 2^31, which is approx 2 * 10^18.
            // This is fine.

            // Calculate the cost for the staircase with (2^k - 1) stairs.
            // This is (2^k - 1) * 2^k / 2.
            // To avoid overflow for 2^k * 2^k, we can write it as (2^k - 1) * 2^(k-1).
            // This is safe as long as k-1 is less than 63.
            // If k=63, 2^(k-1) = 2^62. (2^63 - 1) * 2^62 overflows.
            // But we established k won't exceed 32. So k-1 won't exceed 31.
            // 1LL << (k-1) is safe.
            current_cost = ((1LL << k) - 1) * (1LL << (k - 1));
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
