void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index 'i' such that a[i...n-1] is non-decreasing.
    // This is the potential start of the "good" suffix.
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now a[i...n-1] is non-decreasing.
    // If i is 0, the whole array is non-decreasing, which is good.

    // From this point 'i', we need to find the rightmost index 'j' (j <= i)
    // such that a[j...i-1] is non-increasing.
    // The combined suffix a[j...n-1] would then be non-increasing followed by non-decreasing.
    int j = i;
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now a[j...i-1] is non-increasing.
    // The suffix a[j...n-1] is a candidate for a "good" array.
    // The length of the prefix to erase would be j.

    std::cout << j << std::endl;
}

