    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long limit = n / m;

        if (limit == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Precompute the sum of last digits for one full cycle (10 multiples)
        // The last digit of (i * m) depends only on (i % 10) and (m % 10).
        // So, the sequence of last digits (m%10, 2m%10, ..., 10m%10) repeats.
        // The sum of these 10 last digits is constant for any block of 10 multiples.
        long long sum_of_first_10_last_digits = 0;
        for (int i = 1; i <= 10; ++i) {
            sum_of_first_10_last_digits += (static_cast<long long>(i) * m) % 10;
        }

        // Calculate how many full cycles of 10 multiples are there
        long long num_full_cycles = limit / 10;
        long long total_sum = num_full_cycles * sum_of_first_10_last_digits;

        // Calculate the sum for the remaining multiples
        long long remaining_multiples = limit % 10;
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (static_cast<long long>(i) * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string ans(n, '0');

    // For m=1, the subsegment [1] is always a permutation of {1}.
    // The segment is p[pos[1]...pos[1]].
    // min_idx = pos[1], max_idx = pos[1].
    // Current min_val = 1, current max_val = 1.
    ans[0] = '1';

    int min_idx = pos[1];
    int max_idx = pos[1];

    for (int m = 2; m <= n; ++m) {
        // To check if m is beautiful, we need to expand the current segment
        // [min_idx, max_idx] to include 'm'.
        // The number 'm' is at pos[m].

        // Update min_idx and max_idx to cover the range [1, ..., m]
        // This means the segment must span from min(pos[1], ..., pos[m])
        // to max(pos[1], ..., pos[m]).
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // If the current segment [min_idx, max_idx] has length m
        // (i.e., max_idx - min_idx + 1 == m),
        // then it contains all numbers from 1 to m (because we've expanded
        // it to include pos[1]...pos[m]) and no numbers greater than m
        // (because we only consider numbers up to m).
        // Thus, it forms a permutation of 1...m.
        if (max_idx - min_idx + 1 == m) {
            ans[m - 1] = '1';
        }
    }

    std::cout << ans << std::endl;
}

