    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        // The quadratic equation for 'a' is a^2 - d*a + d = 0.
        // The discriminant is D = (-d)^2 - 4*1*d = d^2 - 4d.
        // For real solutions, D must be non-negative.
        // d^2 - 4d >= 0
        // d(d - 4) >= 0
        // Since d >= 0, this implies d - 4 >= 0, so d >= 4.
        // Also, if d = 0, then 0(0-4) = 0 >= 0, so d=0 is a valid case.
        // If d = 0, a^2 - 0*a + 0 = 0 => a^2 = 0 => a = 0. Then b = d - a = 0 - 0 = 0.
        // So a=0, b=0 is a solution for d=0.

        if (d < 0) { // d is non-negative per problem statement, but good to be robust
            std::cout << "N\n";
        } else if (d == 0) {
            std::cout << std::fixed << std::setprecision(9) << "Y 0.000000000 0.000000000\n";
        } else if (d < 4) { // For d > 0 and d < 4, d^2 - 4d < 0, no real solutions.
            std::cout << "N\n";
        } else { // d >= 4
            double discriminant = d * d - 4 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            // Solutions for 'a' are (d +/- sqrt(d^2 - 4d)) / 2
            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = d - a1; // b = d - a

            // We need a, b to be non-negative.
            // Since d >= 4, d is positive.
            // sqrt_discriminant is real and non-negative.
            // So a1 = (d + sqrt_discriminant) / 2.0 will always be positive.
            // For b1 = d - a1 = d - (d + sqrt_discriminant) / 2.0 = (2d - d - sqrt_discriminant) / 2.0 = (d - sqrt_discriminant) / 2.0
            // We need b1 >= 0, which means d - sqrt_discriminant >= 0, or d >= sqrt_discriminant.
            // Squaring both sides (both are non-negative): d^2 >= discriminant
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // d >= 0.
            // This condition is already met by d >= 4.
            // So both a1 and b1 will always be non-negative when d >= 4.

            // The problem asks for "two non-negative real numbers a and b".
            // The order doesn't matter. We can print a1 and b1.
            std::cout << std::fixed << std::setprecision(9) << "Y " << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

