void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    long long total_toys = A + B + C + D;

    std::string ans1 = "Tidak"; // Box 1: (-inf, -1]
    std::string ans2 = "Tidak"; // Box 2: (-1, 0)
    std::string ans3 = "Tidak"; // Box 3: (0, 1)
    std::string ans4 = "Tidak"; // Box 4: [1, inf)

    if (total_toys == 0) { // Should not happen based on constraints A+B+C+D > 0
        std::cout << "Tidak Tidak Tidak Tidak\n";
        return;
    }

    if (total_toys == 1) {
        if (A == 1) ans1 = "Ya";
        if (B == 1) ans2 = "Ya";
        if (C == 1) ans3 = "Ya";
        if (D == 1) ans4 = "Ya";
        std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
        return;
    }

    // Case 1: Final product is positive
    // This happens if the total number of negative toys (A+B) is even.
    if ((A + B) % 2 == 0) {
        // Final product is positive.
        // Can it be in Box 3 (0, 1)?
        // Yes, if there's at least one toy in Box 2 or Box 3, and we can make the product < 1.
        // If all toys are in Box 4, product is >= 1.
        // If there's at least one toy in Box 2 or Box 3, we can make the product < 1.
        // Example: 0.5 * 0.5 = 0.25. Or 2 * 0.1 = 0.2.
        // The only way to guarantee product >= 1 is if all toys are from Box 1 or Box 4, AND A+B is even.
        // If A+B is even, all negative toys effectively become positive.
        // So if all toys are from Box 1 or Box 4, the product will be >= 1.
        // If there is at least one toy from Box 2 or Box 3, we can make the product < 1.
        if (C > 0 || B > 0) {
            ans3 = "Ya";
        }
        // Can it be in Box 4 [1, inf)?
        // Yes, if we can make the product >= 1.
        // This is always possible unless all toys are from Box 2 or Box 3.
        // If A+D > 0, we can always make the product >= 1.
        // If A+D == 0, then all toys are from B and C.
        // If all toys are from B and C, and A+B is even (meaning B is even), then the product is positive.
        // If B+C > 0 and A+D == 0, then the product is always < 1.
        // So, if A+D > 0, we can make it >= 1.
        // If A+D == 0, then all toys are from B and C. If B is even, product is positive.
        // In this case (A+D==0), the product is always < 1, so it cannot be in Box 4.
        // So, ans4 is "Ya" if A+D > 0.
        if (A > 0 || D > 0) {
            ans4 = "Ya";
        } else { // A=0, D=0, so all toys are from B and C.
            // If B is even, product is positive. All values are < 1, so product is < 1.
            // So ans4 remains "Tidak".
        }
    }

    // Case 2: Final product is negative
    // This happens if the total number of negative toys (A+B) is odd.
    if ((A + B) % 2 == 1) {
        // Final product is negative.
        // Can it be in Box 1 (-inf, -1]?
        // Yes, if we can make the magnitude >= 1.
        // This is possible if there's at least one toy from Box 1 or Box 4.
        // If A+D > 0, we can make the magnitude >= 1.
        // If A+D == 0, then all toys are from B and C.
        // If A+D == 0, then A=0, D=0. B must be odd for (A+B) to be odd.
        // All toys are from B and C. All values have magnitude < 1.
        // So the product will have magnitude < 1.
        // So ans1 is "Ya" if A+D > 0.
        if (A > 0 || D > 0) {
            ans1 = "Ya";
        }
        // Can it be in Box 2 (-1, 0)?
        // Yes, if there's at least one toy in Box 2 or Box 3, and we can make the magnitude < 1.
        // If all toys are from Box 1 or Box 4, and A+B is odd, the product will have magnitude >= 1.
        // If there is at least one toy from Box 2 or Box 3, we can make the magnitude < 1.
        if (B > 0 || C > 0) {
            ans2 = "Ya";
        } else { // B=0, C=0, so all toys are from A and D.
            // If A+B is odd, then A must be odd.
            // All toys are from A and D. Product will have magnitude >= 1.
            // So ans2 remains "Tidak".
        }
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
}

