    for (int i = 1; i < n; ++i) {
        prefix_min_ops[i] = std::max(prefix_min_ops[i-1] + 1, a[i] - (a[i] - i)); // a[i] must be at least i
        // Simplified: prefix_min_ops[i] = std::max(prefix_min_ops[i-1] + 1, (long long)i);
        // This is wrong. prefix_min_ops[i] should be the minimum value a[i] can take to satisfy the increasing condition.
        // To satisfy a_0 < a_1 < ... < a_i, we need a_j >= j for all j <= i.
        // So, a_i must be at least i.
        // The minimum value a[i] can take is i.
        // If a[i] < i, it's impossible.
        // If a[i] >= i, it's possible to make it i.
        // So, prefix_min_ops[i] = i if a[i] >= i, else impossible.
        // Let's re-evaluate.
        // We need a_0' < a_1' < ... < a_i'.
        // The smallest possible values are 0, 1, 2, ..., i.
        // So, we must be able to make a_j' = j for all j from 0 to i.
        // This requires a_j >= j for all j from 0 to i.
        // If a_j < j for any j, then it's impossible to make a_j' = j.
        // So, let's define `left_possible[i]` as true if `a_0, ..., a_i` can be made strictly increasing.
        // `left_possible[i]` is true if `a_j >= j` for all `0 <= j <= i`.
        // This is equivalent to `a_i >= i` AND `left_possible[i-1]` is true.
        // So, `left_possible[i] = (a[i] >= i) && left_possible[i-1]`.
        // Base case: `left_possible[0] = (a[0] >= 0)` which is always true.

        // Let's use a simpler approach:
        // `left[i]` stores the minimum value `a[i]` can take to satisfy `a_0 < ... < a_i`.
        // `left[0] = 0`.
        // `left[i] = left[i-1] + 1`.
        // If `a[i] < left[i]`, then it's impossible to make `a[i]` that large, so we can mark it as impossible.
        // We can use `left[i]` to store the minimum possible value for `a[i]` in an increasing sequence starting from 0.
        // If `a[i]` is less than `i`, then it's impossible to make `a[i]` equal to `i` (or greater) while keeping `a_0, ..., a_i` strictly increasing.
        // So, `left[i]` can be `i` if `a[i] >= i`, otherwise it's impossible.
        // Let's use `l_val[i]` to store the minimum value `a[i]` can take to satisfy `a_0 < ... < a_i`.
        // `l_val[0] = 0`.
        // For `i > 0`, `l_val[i] = l_val[i-1] + 1`.
        // If `a[i] < l_val[i]`, then it's impossible to make `a[i]` at least `l_val[i]`.
        // We can use a boolean array `can_reach_left[i]` to indicate if `a_0, ..., a_i` can be made strictly increasing.
    }

    std::vector<bool> can_reach_left(n);
    can_reach_left[0] = (a[0] >= 0); // Always true since a_i are non-negative
    for (int i = 1; i < n; ++i) {
        can_reach_left[i] = can_reach_left[i-1] && (a[i] >= i);
    }

    std::vector<bool> can_reach_right(n);
    can_reach_right[n-1] = (a[n-1] >= 0); // Always true
    for (int i = n - 2; i >= 0; --i) {
        can_reach_right[i] = can_reach_right[i+1] && (a[i] >= (n - 1 - i));
    }

    bool possible = false;
    for (int k = 0; k < n; ++k) {
        // k is the 0-indexed peak position.
        // Left part: a_0 < a_1 < ... < a_k
        // This requires a_j >= j for 0 <= j <= k.
        // This is checked by can_reach_left[k].

        // Right part: a_k > a_{k+1} > ... > a_{n-1}
        // This requires a_j >= (n-1-j) for k <= j <= n-1.
        // This is checked by can_reach_right[k].

        if (can_reach_left[k] && can_reach_right[k]) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

