int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int b_ptr = 0; // Pointer for the elements we are trying to place (the 'b' array)
    for (int i = 0; i < n; ++i) { // Iterate through elements of the sorted 'a' array (original positions)
        // We want to find an element a[b_ptr] from the available elements
        // such that a[b_ptr] > a[i].
        // Since both arrays are sorted, if a[b_ptr] > a[i], then a[b_ptr+1], a[b_ptr+2], ...
        // are also candidates. To maximize matches, we should use the smallest
        // possible element from the available pool that satisfies the condition.
        // This means we advance b_ptr until a[b_ptr] > a[i].
        while (b_ptr < n && a[b_ptr] <= a[i]) {
            b_ptr++;
        }
        // If we found such an element, we use it for position i.
        // This means a[i] is replaced by a[b_ptr], and a[b_ptr] is now "used".
        if (b_ptr < n) {
            count++;
            b_ptr++; // Move to the next available element for the next position
        } else {
            // No more elements in 'a' (from b_ptr onwards) are greater than a[i].
            // We cannot make any more matches for the remaining positions.
            break;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> prefix_max(n);
    std::vector<bool> prefix_is_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max = 0;
    bool distinct_prefix = true;
    for (int i = 0; i < n; ++i) {
        if (a[i] > n || seen_prefix[a[i]]) { // a[i] > n is an optimization, max element can't be > n
            distinct_prefix = false;
        }
        seen_prefix[a[i]] = true;
        current_max = std::max(current_max, a[i]);
        prefix_max[i] = current_max;
        if (distinct_prefix && current_max == i + 1) {
            prefix_is_perm[i + 1] = true;
        }
    }

    std::vector<int> suffix_max(n);
    std::vector<bool> suffix_is_perm(n + 1, false);
    std::fill(seen_prefix.begin(), seen_prefix.end(), false); // Reuse seen_prefix for suffix
    current_max = 0;
    bool distinct_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] > n || seen_prefix[a[i]]) { // a[i] > n is an optimization
            distinct_suffix = false;
        }
        seen_prefix[a[i]] = true;
        current_max = std::max(current_max, a[i]);
        suffix_max[i] = current_max;
        if (distinct_suffix && current_max == (n - i)) {
            suffix_is_perm[n - i] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (prefix_is_perm[l1] && suffix_is_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareA(const Element& a, const Element& b) {
    return a.value < b.value;
}

bool compareB(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareA);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareB);

    // The optimal strategy is to pair the largest A_i with the largest B_j,
    // the second largest A_i with the second largest B_j, and so on.
    // This means if A is sorted ascending, and B is sorted ascending,
    // we pair A[i] with B[i].
    // However, we need to output A' in the original order of B.
    // So, if B_sorted[i] was originally at index b_elements[i].original_index,
    // then A_sorted[i] should be placed at that index in the result array.

    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // a_elements[m - 1 - i].value is the i-th largest value from A
        // b_elements[i].original_index is the original index of the i-th smallest value from B
        // We want to pair the i-th largest A with the i-th largest B.
        // Since B is sorted ascending, b_elements[i] is the i-th smallest B value.
        // So, b_elements[m - 1 - i] is the i-th largest B value.
        // We assign the i-th largest A value to the original position of the i-th largest B value.
        result_a_prime[b_elements[m - 1 - i].original_index] = a_elements[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

