int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, long long> x_counts;
    std::map<int, long long> y_counts;
    std::map<std::pair<int, int>, long long> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Pairs with same x-coordinate
    for (auto const& [x_coord, count] : x_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Pairs with same y-coordinate
    for (auto const& [y_coord, count] : y_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs that have both same x and same y (i.e., identical points)
    // These pairs were counted twice: once for same x, once for same y.
    // They should only be counted once.
    for (auto const& [coords, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // that moves past this 'b' will contribute to the steps.
            // The number of 'a's currently accumulated (count_a)
            // represents the 'a's that are to the left of this 'b'
            // and have not yet been processed (i.e., moved past a 'b').
            // Each such 'a' will eventually move past this 'b'.
            // When an 'a' moves past a 'b' ("ab" -> "bba"), it costs 1 step.
            // The 'a' effectively moves past the 'b', and a new 'b' is created.
            // This new 'b' is to the left of the 'a'.
            // The crucial observation is that when an 'a' moves past a 'b',
            // it effectively doubles the number of 'a's that are "waiting"
            // to move past the *next* 'b' to its left.
            // This is because the original 'a' moves past, and the new 'b'
            // created might interact with 'a's further left.
            // However, the problem asks for minimum steps.
            // The strategy is to always pick the rightmost "ab".
            // When we process 'b' from right to left:
            // If we see 'b', it means all 'a's to its left will eventually
            // have to move past this 'b'.
            // The number of 'a's that are currently "active" (count_a)
            // will each perform an operation with this 'b'.
            // Each such operation adds 1 to total_steps.
            // After these operations, each 'a' has moved past this 'b',
            // and for each 'a', a new 'b' is created to its left.
            // These new 'b's effectively double the 'a's that are
            // waiting to move past the *next* 'b' to the left.
            // So, if we have `count_a` 'a's to the left of current 'b',
            // these `count_a` 'a's will each perform an operation.
            // `total_steps += count_a`.
            // After these operations, the `count_a` 'a's are now to the right
            // of this 'b'. But for each of them, a new 'b' was created
            // to its left. These new 'b's will interact with 'a's further left.
            // This means the effective number of 'a's that are "waiting"
            // to move past the *next* 'b' to the left doubles.
            // So, `count_a = (count_a * 2) % MOD`.
            // This logic is correct for the rightmost "ab" strategy.
            total_steps = (total_steps + count_a) % MOD;
            count_a = (count_a * 2) % MOD;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it simply adds to the count of 'a's
            // that are waiting to move past 'b's to their right.
            count_a = (count_a + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

