void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all 1s

    // Step 1: Determine necessary 0s in w based on s_i = '0'
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s_i is '0', then both w_{i-x} and w_{i+x} must be '0'
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if the constructed w can produce s
    // Construct a candidate s_prime from w and x
    std::string s_prime(n, '0');
    for (int i = 0; i < n; ++i) {
        bool is_one = false;
        // Check w_{i-x}
        if (i - x >= 0 && w[i - x] == '1') {
            is_one = true;
        }
        // Check w_{i+x}
        if (i + x < n && w[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            s_prime[i] = '1';
        }
    }

    // Compare s_prime with the given s
    if (s_prime == s) {
        std::cout << w << std::endl;
