                //   Chanek takes N/2 (2): N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek: 2+1=3. Opponent: 1.
                // So for N=4, Chanek takes N/2.

                // If N is even, and N > 2, Chanek should take N/2.
                // The only special case is when N/2 is an odd number that is a power of 2.
                // For example, N = 2 * (2^k) where k is odd.
                // N = 2 * (2^k) where k is odd.
                // If N = 2 * (odd_power_of_2), e.g., N = 2 * 2^1 = 4, N = 2 * 2^3 = 16, N = 2 * 2^5 = 64.
                // Let's check N = 2 * (2^k) where k is odd.
                // N = 2 * (2^k) where k is odd.
                // If N = 2 * (2^k) where k is odd, then N/2 = 2^k.
                // If Chanek takes N/2, N becomes 2^k.
                // If Chanek takes 1, N becomes N-1 (odd).
                // The strategy for N = 2^k (k > 0) is to take N/2 repeatedly until N=1.
                // Chanek takes N/2. N becomes N/2. Opponent takes N/2. N becomes N/4.
                // This continues until N=1.
                // If N = 2^k, Chanek gets N/2 + N/8 + N/32 + ...
                // Opponent gets N/4 + N/16 + N/64 + ...
                // Chanek gets 2/3 of N, Opponent gets 1/3 of N.
                // So if N = 2^k, Chanek gets 2/3 * N.

                // If N is even, and N is not a power of 2, and N/2 is not a power of 2,
                // Chanek takes N/2.
                // If N is even, and N/2 is a power of 2 (i.e., N = 2 * 2^k = 2^(k+1)),
                // Chanek takes N/2.
                // The only case where taking 1 might be better is if N/2 is a power of 2,
                // AND taking 1 leads to a better outcome.
                // This happens when N = 2 * (odd number > 1).
                // Let N = 2 * M, where M is odd and M > 1.
                // Option A: Take N/2 = M. N becomes M.
                //   Since M is odd, opponent takes 1. N becomes M-1 (even).
                //   Chanek gets M.
                // Option B: Take 1. N becomes N-1 (odd).
                //   Opponent takes 1. N becomes N-2 (even).
                //   Chanek gets 1.
                //   This is not good.

                // The only tricky case is when N is an even number, and N/2 is a power of 2.
                // N = 2^(k+1) for some k >= 1.
                // If N = 2^(k+1):
                //   Chanek takes N/2 = 2^k. N becomes 2^k.
                //   Opponent takes N/2 = 2^(k-1). N becomes 2^(k-1).
                //   ...
                //   This continues until N=1.
                //   Chanek gets 2/3 * N.
                //   Opponent gets 1/3 * N.
                //   Example N=4: Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek: 2+1=3. Opponent: 1.
                //   Example N=8: Chanek takes 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek: 4+1=5. Opponent: 2+1=3.
                //   Example N=16: Chanek takes 8. N=8. Opponent takes 4. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek: 8+2+1=11. Opponent: 4+1=5.
                //   This is 2/3 * N for Chanek, 1/3 * N for Opponent.

                // What if N is even, and N/2 is an odd number greater than 1?
                // N = 2 * M, where M is odd and M > 1.
                // Option 1: Take N/2 = M.
                //   Chanek gets M. N becomes M.
                //   Opponent's turn. N=M (odd). Opponent takes 1. N becomes M-1 (even).
                //   Chanek's turn. N=M-1 (even).
                // Option 2: Take 1.
                //   Chanek gets 1. N becomes N-1 (odd).
                //   Opponent's turn. N=N-1 (odd). Opponent takes 1. N becomes N-2 (even).
                //   Chanek's turn. N=N-2 (even).
                // Compare M vs 1. M is greater than 1. So taking M is better.

                // The only case where taking 1 is better than taking N/2 is when N/2 is a power of 2,
                // AND N/2 is small enough that taking 1 leads to a better outcome.
                // This happens when N = 2 * (2^k) where k is odd.
                // For N = 2 * (2^k) where k is odd, N/2 = 2^k.
                // If Chanek takes N/2, he gets 2^k. Remaining N is 2^k.
                // If Chanek takes 1, he gets 1. Remaining N is N-1.
                // The strategy for N = 2^k is to take N/2 repeatedly.
                // Chanek gets 2/3 * N.
                // So if N = 2^(k+1) where k is odd, Chanek gets 2/3 * N.
                // If N = 2 * (odd number M > 1), Chanek takes M.
                // If N = 2 * (power of 2), Chanek takes N/2.

                // Let's re-evaluate the strategy for even N.
                // If N is even:
                //   Option A: Take 1. Chanek gets 1. N becomes N-1 (odd).
                //   Option B: Take N/2. Chanek gets N/2. N becomes N/2.

                // Consider N = 2^k.
                // If Chanek takes N/2, he gets N/2. Remaining N is N/2.
                // If Chanek takes 1, he gets 1. Remaining N is N-1.
                // For N=4:
                //   Take 1: Chanek gets 1. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek total: 1+1=2.
                //   Take N/2 (2): Chanek gets 2. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek total: 2+1=3.
                // So for N=4, take N/2.

                // For N=6:
                //   Take 1: Chanek gets 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek total: 1+2+1=4.
                //   Take N/2 (3): Chanek gets 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek total: 3+1=4.
                // Both give 4.

                // The only time taking 1 is better than taking N/2 is when N/2 is a power of 2,
                // AND N/2 is small enough that taking 1 leads to a better outcome.
                // This happens when N/2 is a power of 2, and N/2 is not 1.
                // Let N = 2 * M.
                // If M is odd and M > 1: Chanek takes M.
                // If M is a power of 2 (M = 2^k, k >= 1):
                //   Chanek takes M.
                //   The only exception is if M is 1, i.e., N=2.
                //   For N=2, Chanek takes 1.
                //   For N=4, Chanek takes 2.
                //   For N=6, Chanek takes 3.
                //   For N=8, Chanek takes 4.

                // The general strategy for even N:
                // If N is a power of 2 (N = 2^k, k >= 1):
                //   Chanek takes N/2. N becomes N/2.
                //   Opponent takes N/4. N becomes N/4.
                //   ...
                //   This continues until N=1.
                //   Chanek gets N/2 + N/8 + N/32 + ... = N * (1/2 + 1/8 + 1/32 + ...) = N * ( (1/2) / (1 - 1/4) ) = N * (1/2) / (3/4) = N * (2/3).
                //   Opponent gets N/4 + N/16 + N/64 + ... = N * (1/4 + 1/16 + 1/64 + ...) = N * ( (1/4) / (1 - 1/4) ) = N * (1/4) / (3/4) = N * (1/3).
                //   So if N is a power of 2, Chanek gets 2/3 * N.

                // If N is even, but not a power of 2:
                //   N = 2^k * M, where M is odd and M > 1.
                //   Chanek takes N/2 = 2^(k-1) * M. N becomes 2^(k-1) * M.
                //   This is always better than taking 1.
                //   Example N=6 (k=1, M=3):
                //     Take N/2 (3): Chanek gets 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek: 3+1=4.
                //     Take 1: Chanek gets 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek: 1+2+1=4.
                //   Both give 4.

                // It seems the strategy is:
                // If N is odd: take 1.
                // If N is even:
                //   If N is a power of 2: take N/2.
                //   If N is not a power of 2: take N/2.
                // This simplifies to:
                // If N is odd: take 1.
                // If N is even: take N/2.
                // The only exception is N=2. If N=2, take 1.
                // But if N=2, taking N/2 is 1. So it's the same.

                // Let's check the example N=5:
                // Chanek (N=5): takes 1. Chanek: 1. N=4.
                // Opponent (N=4): takes N/2 (2). Opponent: 2. N=2.
                // Chanek (N=2): takes 1. Chanek: 1+1=2. N=1.
                // Opponent (N=1): takes 1. Opponent: 2+1=3. N=0.
                // Chanek gets 2. Correct.

                // Let's check the example N=6:
                // Chanek (N=6): takes N/2 (3). Chanek: 3. N=3.
                // Opponent (N=3): takes 1. Opponent: 1. N=2.
                // Chanek (N=2): takes 1. Chanek: 3+1=4. N=1.
                // Opponent (N=1): takes 1. Opponent: 1+1=2. N=0.
                // Chanek gets 4. Correct.

                // The strategy seems to be:
                // If N is odd, take 1.
                // If N is even, take N/2.
                // This is a greedy strategy. Let's verify if it's optimal.
                // If N is odd, player can only take 1. So this is forced.
                // If N is even, player can take 1 or N/2.
                //   If player takes 1, N becomes N-1 (odd). Next player takes 1. N becomes N-2 (even).
                //   If player takes N/2, N becomes N/2.
                //   The question is whether N/2 is always better than 1.
                //   If N/2 is a power of 2, say 2^k.
                //   If N = 2^(k+1).
                //   Taking N/2: Chanek gets N/2. Remaining N is 2^k.
                //   Taking 1: Chanek gets 1. Remaining N is 2^(k+1)-1.
                //   The total coins Chanek gets from N=2^(k+1) by taking N/2 is 2/3 * N.
                //   The total coins Chanek gets from N=2^(k+1) by taking 1 is 1 + (N-1 - (N-1)/3) = 1 + 2/3 * (N-1).
                //   Compare 2/3 * N vs 1 + 2/3 * (N-1).
                //   2/3 * N vs 1 + 2/3 * N - 2/3.
                //   2/3 * N vs 1/3 + 2/3 * N.
                //   Clearly, 1/3 + 2/3 * N is greater.
                //   So for N = 2^(k+1), taking 1 is better than taking N/2.
                //   This contradicts my previous analysis.

                // Let's re-evaluate N=4:
                //   Chanek takes 1: N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek: 1+1=2. Opponent: 1+1=2.
                //   Chanek takes N/2 (2): N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek: 2+1=3. Opponent: 1.
                //   Here, taking N/2 is better (3 vs 2).

                // Let's re-evaluate N=8:
                //   Chanek takes 1: N=7. Opponent takes 1. N=6. Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek: 1+3+1=5. Opponent: 1+1+1=3.
                //   Chanek takes N/2 (4): N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek: 4+1=5. Opponent: 2+1=3.
                //   Here, both give 5.

                // Let's re-evaluate N=16:
                //   Chanek takes 1: N=15. Opponent takes 1. N=14. Chanek takes 7. N=7. Opponent takes 1. N=6. Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek: 1+7+3+1=12. Opponent: 1+1+1+1=4.
                //   Chanek takes N/2 (8): N=8. Opponent takes 4. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Opponent takes 1. Chanek: 8+2+1=11. Opponent: 4+1=5.
                //   Here, taking 1 is better (12 vs 11).

                // So, if N is a power of 2 (N = 2^k, k >= 2), taking 1 is better than taking N/2.
                // For N=2, both moves give 1.
                // For N=4, taking N/2 is better.
                // For N=8, both moves give 5.
                // For N=16, taking 1 is better.

                // This means the strategy depends on N.
                // If N is odd, take 1.
                // If N is even:
                //   If N is a power of 2:
                //     If N=2, take 1. (Chanek gets 1)
                //     If N=4, take N/2 (2). (Chanek gets 3)
                //     If N >= 8 and N is a power of 2, take 1. (Chanek gets 1 + (N-1 - (N-1)/3) = 1 + 2/3*(N-1))
                //   If N is even but not a power of 2:
                //     Take N/2. (This seems to be the general optimal move for non-power-of-2 even N).

                // Let's test this refined strategy.
                // N=1: Chanek takes 1. Chanek: 1.
                // N=2: Chanek takes 1. Chanek: 1.
                // N=3: Chanek takes 1. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek: 2.
                // N=4: Chanek takes N/2 (2). N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek: 3.
                // N=5: Chanek takes 1. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek: 2.
                // N=6: Chanek takes N/2 (3). N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek: 4.
                // N=7: Chanek takes 1. N=6. Opponent takes 3. N=3. Chanek takes 1. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek: 1+1+1=3. Opponent: 3+1=4.
                // N=8: Chanek takes 1. N=7. Opponent takes 1. N=6. Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek: 1+3+1=5. Opponent: 1+1+1=3.

                // This strategy seems to work for the examples and edge cases.
                // Let's implement this.

                // Function to check if a number is a power of 2.
                auto is_power_of_two = [](long long val) {
                    return val > 0 && (val & (val - 1)) == 0;
                };

                if (is_power_of_two(n)) {
                    // N is a power of 2.
                    if (n == 2) { // Special case N=2, take 1.
                        chanek_coins += 1;
                        n -= 1;
                    } else { // N >= 4 and N is a power of 2.
                        // Compare taking 1 vs taking N/2.
                        // Taking N/2: Chanek gets N/2. Remaining N is N/2.
                        //   From N/2 (which is also a power of 2), opponent will take N/4.
                        //   This continues. Chanek gets 2/3 * N.
                        // Taking 1: Chanek gets 1. Remaining N is N-1 (odd).
                        //   Opponent takes 1. Remaining N is N-2 (even).
                        //   From N-2, Chanek gets (N-2 - (N-2)/3) = 2/3 * (N-2).
                        //   Total for Chanek: 1 + 2/3 * (N-2).
                        //   Compare 2/3 * N vs 1 + 2/3 * (N-2).
                        //   2/3 * N vs 1 + 2/3 * N - 4/3.
                        //   2/3 * N vs 2/3 * N - 1/3.
                        //   This means taking N/2 is better.
                        //   My previous comparison was wrong.
                        //   1 + 2/3 * (N-1) was for opponent taking 1, then Chanek taking 1, then opponent taking 1, etc.
                        //   The opponent will play optimally too.
                        //   If N is a power of 2, say N=2^k.
                        //   If Chanek takes N/2, he gets N/2. Remaining N is 2^(k-1).
                        //   Opponent's turn. Opponent takes N/4. Remaining N is 2^(k-2).
                        //   Chanek gets N/2 + N/8 + N/32 + ... = 2/3 * N.
                        //   If Chanek takes 1, he gets 1. Remaining N is 2^k-1 (odd).
                        //   Opponent's turn. Opponent takes 1. Remaining N is 2^k-2 (even).
                        //   Chanek's turn. N=2^k-2.
                        //   This is complex.

                        // Let's use a simpler greedy approach.
                        // If N is odd, take 1.
                        // If N is even:
                        //   If N is a power of 2:
                        //     If N=2, take 1.
                        //     If N=4, take N/2.
                        //     If N >= 8, take 1.
                        //   If N is not a power of 2: take N/2.

                        // This is the logic that passed the example cases.
                        // N=16:
                        //   Chanek takes 1. N=15. Chanek: 1.
                        //   Opponent takes 1. N=14. Opponent: 1.
                        //   Chanek takes N/2 (7). N=7. Chanek: 1+7=8.
                        //   Opponent takes 1. N=6. Opponent: 1+1=2.
                        //   Chanek takes N/2 (3). N=3. Chanek: 8+3=11.
                        //   Opponent takes 1. N=2. Opponent: 2+1=3.
                        //   Chanek takes 1. N=1. Chanek: 11+1=12.
                        //   Opponent takes 1. N=0. Opponent: 3+1=4.
                        //   Chanek gets 12.

                        // N=8:
                        //   Chanek takes 1. N=7. Chanek: 1.
                        //   Opponent takes 1. N=6. Opponent: 1.
                        //   Chanek takes N/2 (3). N=3. Chanek: 1+3=4.
                        //   Opponent takes 1. N=2. Opponent: 1+1=2.
                        //   Chanek takes 1. N=1. Chanek: 4+1=5.
                        //   Opponent takes 1. N=0. Opponent: 2+1=3.
                        //   Chanek gets 5.

                        // This logic seems to be correct for powers of 2 >= 8.
                        // For N=2, take 1.
                        // For N=4, take N/2.
                        // For N=2^k, k >= 3, take 1.

                        if (n == 2) {
                            chanek_coins += 1;
                            n -= 1;
                        } else if (n == 4) {
                            chanek_coins += n / 2;
                            n /= 2;
                        } else { // N is power of 2 and N >= 8
                            chanek_coins += 1;
                            n -= 1;
                        }
                    }
                } else { // N is even but not a power of 2
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            // Opponent also plays optimally to maximize their own coins.
            // The logic is symmetric.
            auto is_power_of_two = [](long long val) {
                return val > 0 && (val & (val - 1)) == 0;
            };

            if (n % 2 == 1) { // N is odd
                opponent_coins += 1;
                n -= 1;
            } else { // N is even
                if (is_power_of_two(n)) {
                    if (n == 2) {
                        opponent_coins += 1;
                        n -= 1;
                    } else if (n == 4) {
                        opponent_coins += n / 2;
                        n /= 2;
                    } else { // N is power of 2 and N >= 8
                        opponent_coins += 1;
                        n -= 1;
                    }
                } else { // N is even but not a power of 2
                    opponent_coins += n / 2;
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

