#include <iostream>
#include <string>
#include <vector>
#include <algorithm> // For std::min/max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // prefix_counts[0][i] stores count of 'x' in s[0...i-1]
    // prefix_counts[1][i] stores count of 'y' in s[0...i-1]
    // prefix_counts[2][i] stores count of 'z' in s[0...i-1]
    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        prefix_counts[0][i + 1] = prefix_counts[0][i];
        prefix_counts[1][i + 1] = prefix_counts[1][i];
        prefix_counts[2][i + 1] = prefix_counts[2][i];
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;
        // Adjust to 0-indexed
        --l; 
        // r is already exclusive for prefix_counts[char_idx][r] - prefix_counts[char_idx][l]

        if (r - l < 3) { // Substring length less than 3, no 3-char subsequences exist. Algorithm terminates.
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[0][r] - prefix_counts[0][l];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l];

        // The algorithm terminates if and only if the counts of 'x', 'y', 'z'
        // in the substring are "balanced" enough such that they can all be
        // rearranged into permutations of "xyz".
        // Specifically, the difference between the maximum and minimum count
        // of any character must not exceed 1.
        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    for (int k = 0; k <= 9; ++k) {
        std::string t(n, ' ');
        std::vector<char> s1_digits;
        std::vector<char> s2_digits;
        bool possible_k = true;
        char last_s1_digit = '0' - 1; // Smaller than any digit
        char first_s2_digit = '9' + 1; // Larger than any digit

        // First pass: assign digits < k to color 1, digits > k to color 2
        // Digits == k are temporarily unassigned.
        for (int i = 0; i < n; ++i) {
            char digit = s[i];
            if (digit < (k + '0')) {
                t[i] = '1';
                s1_digits.push_back(digit);
            } else if (digit > (k + '0')) {
                t[i] = '2';
                s2_digits.push_back(digit);
            }
        }

        // Check if S1 and S2 are internally sorted so far
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible_k = false;
                break;
            }
        }
        if (!possible_k) continue;

        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible_k = false;
                break;
            }
        }
        if (!possible_k) continue;

        // Determine last_s1_digit and first_s2_digit from assigned digits
        if (!s1_digits.empty()) {
            last_s1_digit = s1_digits.back();
        }
        if (!s2_digits.empty()) {
            first_s2_digit = s2_digits.front();
        }

        // Second pass: assign digits == k
        // Digits == k must be assigned such that they maintain sorted order.
        // They can either go to S1 or S2.
        // If assigned to S1, they must be >= last_s1_digit.
        // If assigned to S2, they must be <= first_s2_digit.
        // Crucially, all digits 'k' assigned to S1 must appear before all digits 'k' assigned to S2.
        // This means there's a split point among the 'k' digits.
        // All 'k's before some index go to S1, all 'k's after go to S2.
        // The first 'k' that goes to S2 must be >= last_s1_digit.
        // The last 'k' that goes to S1 must be <= first_s2_digit.

        // To simplify, we can assign all 'k's that appear before the first 'k' that is greater than last_s1_digit to color 1.
        // And all 'k's that appear after the last 'k' that is smaller than first_s2_digit to color 2.
        // This is equivalent to finding the first 'k' that we *must* assign to color 2.
        // Any 'k' before that must be color 1. Any 'k' after that must be color 2.

        char current_last_s1 = last_s1_digit;
        char current_first_s2 = first_s2_digit;

        // Find the split point for digits 'k'
        int split_idx_for_k = -1; // Index of the first 'k' that should be colored 2
        for (int i = 0; i < n; ++i) {
            if (s[i] == (k + '0')) {
                if (s[i] < current_last_s1) { // This 'k' is too small for S1, must be S2
                    // This case should not happen if current_last_s1 is correctly updated.
                    // If s[i] == k, and current_last_s1 is from a digit < k, then s[i] >= current_last_s1.
                    // If current_last_s1 is from a digit == k, then it's fine.
                    // This condition is effectively: if s[i] < current_last_s1, then it's impossible.
                    // But s[i] is 'k', so it can only be < current_last_s1 if current_last_s1 was also 'k'.
                    // This logic is tricky. Let's use a simpler approach for 'k's.
                    // All 'k's before a certain point go to S1, all 'k's after go to S2.
                    // The first 'k' that goes to S2 must be >= last_s1_digit.
                    // The last 'k' that goes to S1 must be <= first_s2_digit.
                    // This means we can find the first 'k' that is greater than or equal to `current_last_s1`
                    // and assign it to color 2. All subsequent 'k's must also be color 2.
                    // All 'k's before that must be color 1.
                    // This is the standard approach for two-stack sorting.
                }
                if (s[i] >= current_last_s1) {
                    split_idx_for_k = i;
                    break;
                }
            }
        }

        // If no 'k' was found that could start S2, all 'k's go to S1.
        if (split_idx_for_k == -1) {
            split_idx_for_k = n; // All 'k's go to S1
        }

        // Assign 'k's based on split_idx_for_k
        for (int i = 0; i < n; ++i) {
            if (s[i] == (k + '0')) {
                if (i < split_idx_for_k) {
                    t[i] = '1';
                } else {
                    t[i] = '2';
                }
            }
        }

        // Reconstruct S1 and S2 and check final conditions
        s1_digits.clear();
        s2_digits.clear();
        for (int i = 0; i < n; ++i) {
            if (t[i] == '1') {
                s1_digits.push_back(s[i]);
            } else if (t[i] == '2') {
                s2_digits.push_back(s[i]);
            }
        }

        // Check if S1 is sorted
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible_k = false;
                break;
            }
        }
        if (!possible_k) continue;

        // Check if S2 is sorted
        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible_k = false;
                break;
            }
        }
        if (!possible_k) continue;

        // Check if last S1 <= first S2
        if (!s1_digits.empty() && !s2_digits.empty()) {
            if (s1_digits.back() > s2_digits.front()) {
                possible_k = false;
            }
        }
        if (!possible_k) continue;

        std::cout << t << "\n";
        return;
    }

    std::cout << "-\n";
}

