    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < n; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_prob = 0.0;

    for (int k_actual = 0; k_actual < n; ++k_actual) {
        char char0_val = s[k_actual];

        std::vector<int> possible_k_initial;
        for (int idx : char_indices[char0_val - 'a']) {
            possible_k_initial.push_back(idx);
        }

        if (possible_k_initial.size() == 1) {
            total_prob += 1.0;
            continue;
        }

        double max_win_prob_for_k_actual = 0.0;

        for (int p = 1; p < n; ++p) { // Vasya chooses position p
            std::vector<int> counts(n, 0); // counts[k_val] = number of (char0, char_p) pairs that match k_val

            for (int k_val : possible_k_initial) {
                char char_p_val = s[(k_val + p) % n];
                int hash_val = (char0_val - 'a') * 26 + (char_p_val - 'a');
                counts[hash_val]++;
            }

            int num_unique_pairs = 0;
            for (int k_val : possible_k_initial) {
                char char_p_val = s[(k_val + p) % n];
                int hash_val = (char0_val - 'a') * 26 + (char_p_val - 'a');
                if (counts[hash_val] == 1) {
                    num_unique_pairs++;
                }
            }
            max_win_prob_for_k_actual = std::max(max_win_prob_for_k_actual, (double)num_unique_pairs / possible_k_initial.size());
        }
        total_prob += max_win_prob_for_k_actual;
    }

    std::cout << std::fixed << std::setprecision(15) << total_prob / n << std::endl;

    return 0;
}

