int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::ceil(std::sqrt(n)));

    for (int i = 0; i < n; ++i) {
        int block_idx = i / k;
        int start_of_block = block_idx * k;
        int end_of_block = std::min(n, (block_idx + 1) * k);

        // The element at index i in the output permutation
        // should be the (k - 1 - (i % k))th element from the end of its block
        // when blocks are considered in reverse order.
        // Or, more simply, it's the (k - 1 - (i % k))th element from the start of the block
        // if we consider blocks in reverse order.
        // The value is `start_of_block + (k - 1 - (i % k)) + 1`
        // which simplifies to `start_of_block + k - (i % k)`
        // This is the value `(block_idx + 1) * k - (i % k)`
        // But we need to ensure it doesn't exceed n.
        // The values in the current block are `start_of_block + 1, ..., end_of_block`.
        // We want to print them in reverse order.
        // The first element of the block (at index `block_idx * k`) should be `end_of_block`.
        // The second element of the block (at index `block_idx * k + 1`) should be `end_of_block - 1`.
        // The element at index `i` (which is `block_idx * k + (i % k)`) should be `end_of_block - (i % k)`.
        std::cout << end_of_block - (i % k) << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

