#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // balance[i] = (count of 1s) - (count of 2s) for jars 1 to i
    // We are interested in jars 1 to n-L.
    // The balance for jars 1 to k is prefix_balance_left[k].
    // The balance for jars 1 to 0 is 0.
    std::vector<int> prefix_balance_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_balance_left[i + 1] = prefix_balance_left[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right side (jars n+1 to 2n)
    // balance[i] = (count of 1s) - (count of 2s) for jars i to 2n
    // We are interested in jars n+R+1 to 2n.
    // The balance for jars k to 2n is suffix_balance_right[k].
    // The balance for jars 2n+1 to 2n is 0.
    std::vector<int> suffix_balance_right(2 * n + 1, 0);
    for (int i = 2 * n - 1; i >= n; --i) {
        suffix_balance_right[i + 1] = suffix_balance_right[i + 2] + (a[i] == 1 ? 1 : -1);
    }

    // Store the minimum number of jars removed from the right side (R)
    // for each possible balance value from the right side.
    // map: balance_value -> min_R
    std::map<int, int> right_balance_to_min_R;
    for (int R = 0; R <= n; ++R) {
        // The jars remaining on the right are from index n+R to 2n-1 (0-indexed)
        // which corresponds to jars n+R+1 to 2n (1-indexed).
        // The balance for these jars is suffix_balance_right[n+R+1].
        int current_right_balance = suffix_balance_right[n + R + 1];
        if (right_balance_to_min_R.find(current_right_balance) == right_balance_to_min_R.end()) {
            right_balance_to_min_R[current_right_balance] = R;
        } else {
            right_balance_to_min_R[current_right_balance] = std::min(right_balance_to_min_R[current_right_balance], R);
        }
    }

    int min_total_removed = 2 * n; // Initialize with maximum possible removals

    // Iterate through all possible numbers of jars removed from the left side (L)
    for (int L = 0; L <= n; ++L) {
        // The jars remaining on the left are from index 0 to n-L-1 (0-indexed)
        // which corresponds to jars 1 to n-L (1-indexed).
        // The balance for these jars is prefix_balance_left[n-L].
        int current_left_balance = prefix_balance_left[n - L];

        // We need the total balance to be 0.
        // So, current_left_balance + current_right_balance = 0
        // This means current_right_balance must be -current_left_balance.
        int target_right_balance = -current_left_balance;

        if (right_balance_to_min_R.count(target_right_balance)) {
            int R = right_balance_to_min_R[target_right_balance];
            min_total_removed = std::min(min_total_removed, L + R);
        }
    }

    std::cout << min_total_removed << std::endl;
}

