}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> L(n, 0), R(n, 0);

    // Calculate L[i]: minimum distance to a 0 to the left (inclusive)
    // L[i] = 0 if a[i] == 0
    // L[i] = L[i-1] + 1 if a[i] == 1 and i > 0
    // L[0] = 0 if a[0] == 0, infinity if a[0] == 1 (effectively, no 0 to the left)
    // For our purpose, we can just say L[0] = 0 if a[0] == 0, else a large value.
    // But since we only care about L[i] for i > 0, and L[i] is distance to a[i] itself if a[i]==0,
    // we can initialize L[0] based on a[0].

    if (a[0] == 0) {
        L[0] = 0;
    } else {
        L[0] = n + 1; // Represents infinity for practical purposes
    }
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            L[i] = 0;
        } else {
            L[i] = L[i - 1] + 1;
        }
    }

    // Calculate R[i]: minimum distance to a 0 to the right (inclusive)
    // R[i] = 0 if a[i] == 0
    // R[i] = R[i+1] + 1 if a[i] == 1 and i < n-1
    // R[n-1] = 0 if a[n-1] == 0, infinity if a[n-1] == 1
    if (a[n - 1] == 0) {
        R[n - 1] = 0;
    } else {
        R[n - 1] = n + 1; // Represents infinity
    }
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            R[i] = 0;
        } else {
            R[i] = R[i + 1] + 1;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            int dist_to_nearest_zero = std::min(L[i], R[i]);
            if (dist_to_nearest_zero == n + 1) { // No zeros in the sequence
                std::cout << 0 << std::endl;
                for (int j = 0; j < n; ++j) {
                    std::cout << a[j] << (j == n - 1 ? "" : " ");
                }
                std::cout << std::endl;
                return 0;
            }
            max_k = std::max(max_k, (dist_to_nearest_zero + 1) / 2);
        }
    }

    std::cout << max_k << std::endl;

    std::vector<int> b(n);
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            b[i] = 0;
        } else { // a[i] == 1
            int dist_to_nearest_zero = std::min(L[i], R[i]);
            if (dist_to_nearest_zero == n + 1) { // Should not happen if max_k > 0
                b[i] = 1;
            } else if (dist_to_nearest_zero <= max_k) {
                b[i] = 0;
            } else {
                b[i] = 1;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize two values: one where all bits are 0, and one where all bits are 1.
    // We only care about bits 0-9, so 0 and 1023 are sufficient.
    int val0 = 0;    // Represents the output for an input of 0
    int val1023 = 1023; // Represents the output for an input of 1023

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val0 &= x;
            val1023 &= x;
        } else if (op_char == '|') {
            val0 |= x;
            val1023 |= x;
        } else if (op_char == '^') {
            val0 ^= x;
            val1023 ^= x;
        }
    }

    // Now, val0 is the result if the input was 0.
    // And val1023 is the result if the input was 1023.
    // For each bit position j (0 to 9):
    // Let b_in be the j-th bit of the input.
    // Let b_out be the j-th bit of the final result.
    //
    // If b_in = 0, then b_out is (val0 >> j) & 1.
    // If b_in = 1, then b_out is (val1023 >> j) & 1.
    //
    // We need to find A, B, C such that:
    // (0 & A | B ^ C) == (val0 >> j) & 1
    // (1 & A | B ^ C) == (val1023 >> j) & 1
    //
    // This simplifies to:
    // (B ^ C) == (val0 >> j) & 1
    // (A | B ^ C) == (val1023 >> j) & 1
    //
    // Let K = (B ^ C). Then K is the j-th bit of the constant for the OR operation.
    // K = (val0 >> j) & 1
    // (A | K) == (val1023 >> j) & 1
    //
    // This means for each bit j:
    // 1. If (val0 >> j) & 1 == 0 and (val1023 >> j) & 1 == 0:
    //    Input 0 -> Output 0. Input 1 -> Output 0.
    //    This means the bit is always 0, regardless of input.
    //    This can be achieved by `& 0` for this bit.
    // 2. If (val0 >> j) & 1 == 0 and (val1023 >> j) & 1 == 1:
    //    Input 0 -> Output 0. Input 1 -> Output 1.
    //    This means the bit is unchanged.
    //    This can be achieved by `& 1` for this bit.
    // 3. If (val0 >> j) & 1 == 1 and (val1023 >> j) & 1 == 0:
    //    Input 0 -> Output 1. Input 1 -> Output 0.
    //    This means the bit is flipped.
    //    This can be achieved by `^ 1` for this bit.
    // 4. If (val0 >> j) & 1 == 1 and (val1023 >> j) & 1 == 1:
    //    Input 0 -> Output 1. Input 1 -> Output 1.
    //    This means the bit is always 1, regardless of input.
    //    This can be achieved by `| 1` for this bit.

    // We can combine these into three operations:
    // A final_AND_mask
    // A final_OR_mask
    // A final_XOR_mask
    //
    // Initial state: x
    // x & final_AND_mask | final_OR_mask ^ final_XOR_mask
    //
    // For each bit j:
    // Let b_in be the j-th bit of input.
    // Let b_out be the j-th bit of output.
    //
    // Case 1: b_out = 0 for b_in = 0, b_out = 0 for b_in = 1. (Always 0)
    //   This means (val0 >> j) & 1 == 0 and (val1023 >> j) & 1 == 0.
    //   We need (b_in & A_j | B_j ^ C_j) = 0.
    //   If A_j=0, B_j=0, C_j=0: (b_in & 0 | 0 ^ 0) = 0. Works.
    //   So, A_j=0, B_j=0, C_j=0.
    //
    // Case 2: b_out = 0 for b_in = 0, b_out = 1 for b_in = 1. (Unchanged)
    //   This means (val0 >> j) & 1 == 0 and (val1023 >> j) & 1 == 1.
    //   We need (b_in & A_j | B_j ^ C_j) = b_in.
    //   If A_j=1, B_j=0, C_j=0: (b_in & 1 | 0 ^ 0) = b_in. Works.
    //   So, A_j=1, B_j=0, C_j=0.
    //
    // Case 3: b_out = 1 for b_in = 0, b_out = 0 for b_in = 1. (Flipped)
    //   This means (val0 >> j) & 1 == 1 and (val1023 >> j) & 1 == 0.
    //   We need (b_in & A_j | B_j ^ C_j) = !b_in.
    //   If A_j=1, B_j=0, C_j=1: (b_in & 1 | 0 ^ 1) = b_in ^ 1 = !b_in. Works.
    //   So, A_j=1, B_j=0, C_j=1.
    //
    // Case 4: b_out = 1 for b_in = 0, b_out = 1 for b_in = 1. (Always 1)
    //   This means (val0 >> j) & 1 == 1 and (val1023 >> j) & 1 == 1.
    //   We need (b_in & A_j | B_j ^ C_j) = 1.
    //   If A_j=0, B_j=1, C_j=0: (b_in & 0 | 1 ^ 0) = 1. Works.
    //   So, A_j=0, B_j=1, C_j=0.

    // Let's define the masks for the three operations:
    // `&` mask: `and_val`
    // `|` mask: `or_val`
    // `^` mask: `xor_val`
    int and_val = 0; // Bits that should be 1 in the & mask
    int or_val = 0;  // Bits that should be 1 in the | mask
    int xor_val = 0; // Bits that should be 1 in the ^ mask

    // Initialize and_val to all 1s (1023) because we want to preserve bits by default
    // and then set specific bits to 0 if needed.
    and_val = 1023;

    for (int j = 0; j < 10; ++j) {
        int bit0 = (val0 >> j) & 1;
        int bit1 = (val1023 >> j) & 1;

        if (bit0 == 0 && bit1 == 0) { // Always 0
            // (b_in & 0 | 0 ^ 0) = 0
            // and_val's j-th bit should be 0
            and_val &= ~(1 << j);
            // or_val's j-th bit should be 0
            // xor_val's j-th bit should be 0
        } else if (bit0 == 0 && bit1 == 1) { // Unchanged
            // (b_in & 1 | 0 ^ 0) = b_in
            // and_val's j-th bit should be 1 (already is)
            // or_val's j-th bit should be 0
            // xor_val's j-th bit should be 0
        } else if (bit0 == 1 && bit1 == 0) { // Flipped
            // (b_in & 1 | 0 ^ 1) = b_in ^ 1
            // and_val's j-th bit should be 1 (already is)
            // or_val's j-th bit should be 0
            // xor_val's j-th bit should be 1
            xor_val |= (1 << j);
        } else { // bit0 == 1 && bit1 == 1 (Always 1)
            // (b_in & 0 | 1 ^ 0) = 1
            // and_val's j-th bit should be 0
            and_val &= ~(1 << j);
            // or_val's j-th bit should be 1
            or_val |= (1 << j);
            // xor_val's j-th bit should be 0
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (and_val != 1023) { // If the AND mask is not all 1s, we need an & operation
        result_ops.push_back({'&', and_val});
    }
    if (or_val != 0) { // If the OR mask is not all 0s, we need an | operation
        result_ops.push_back({'|', or_val});
    }
    if (xor_val != 0) { // If the XOR mask is not all 0s, we need a ^ operation
        result_ops.push_back({'^', xor_val});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    for (int i = 0; i < n; ++i) {
        // Case 1: Substrings starting with '0'
        // If s[i] is '0', then f(s[i...r]) can only be 0.
        // So, we need r - i + 1 = 0, which is impossible since length >= 1.
        // However, the problem statement example f(000) = 0.
        // If f(s_l...s_r) = 0, then all characters must be '0'.
        // In this case, r - l + 1 = 0, which is impossible.
        // This implies that a substring of all '0's cannot be good.
        // Example: s = "000", f("000") = 0. Length = 3. 3 != 0.
        // So, if s[i] is '0', we can skip it as a starting point for a good substring.
        // This is incorrect based on the example f(000) = 0.
        // The example "00001000" has 4 good substrings.
        // "0001000" has 3 good substrings.
        // Let's re-read: "f(000) = 0".
        // If s_l...s_r = "000", length is 3. f("000") = 0. 3 != 0. Not good.
        // This means a substring of all '0's can never be good.
        // So, if s[i] is '0', it cannot be the start of a good substring unless it's a leading zero
        // for a value > 0.
        // The condition is r - l + 1 = f(s_l...s_r).
        // If s[i] = '0', then f(s[i...r]) will be the value of s[i+1...r].
        // This is the key. The problem states "f(011) = 3", "f(00101) = 5".
        // This means leading zeros are part of the string whose value is computed.
        // So, f("011") means the binary string "011" has value 3. Length is 3. 3 == 3. Good.
        // f("00101") means the binary string "00101" has value 5. Length is 5. 5 == 5. Good.
        // f("000") means the binary string "000" has value 0. Length is 3. 3 != 0. Not good.
        // So, my initial interpretation was correct.
        // A substring $s_l \dots s_r$ is good if $r - l + 1 = \text{value}(s_l \dots s_r)$.

        // Iterate through all possible starting positions i
        // For each i, iterate through possible ending positions j
        // Calculate value and length.
        long long current_val = 0;
        for (int j = i; j < n; ++j) {
            int len = j - i + 1;

            // If current_val exceeds a certain threshold, it's impossible for len to catch up.
            // Max possible len is n (2e5).
            // If current_val > n, then it can't be equal to len.
            // Also, if current_val is already large, adding more bits will make it even larger.
            // The maximum value for len is N (2e5).
            // log2(2e5) is approx 17.6. So, a binary string of length 18 can already exceed 2e5.
            // If len > 18, and the first bit is '1', then current_val >= 2^(len-1).
            // If len = 18, current_val can be up to 2^18 - 1 = 262143.
            // If len = 19, current_val can be up to 2^19 - 1 = 524287.
            // So, if len > 18, current_val will be much larger than len.
            // We can cap the inner loop when len becomes too large or current_val becomes too large.
            // A safe upper bound for len to check is around 20.
            // If len > 20, and s[i] is '1', then current_val >= 2^(len-1) which is much larger than len.
            // If s[i] is '0', then current_val is calculated from s[i+1...j].
            // The maximum length of s is 2e5.
            // If len > 20, then current_val will be at least 2^(len-1) if s[i] is '1'.
            // If s[i] is '0', then current_val is calculated from s[i+1...j].
            // The maximum value of len is N.
            // If current_val > N, we can break.
            // If len > 20, and s[i] is '1', then current_val will be at least 2^19, which is > N.
            // So, we only need to check substrings of length up to ~20-21.
            // Let's use a slightly larger bound, say 22, to be safe.
            // 2^21 is about 2 million.
            // If len > 22, and s[i] is '1', then current_val >= 2^(len-1) >= 2^21, which is much larger than N.
            // So, we can break if len > 22.
            // This means the inner loop runs at most 22 times.
            // Total complexity: N * 22. This is efficient enough.

            if (s[j] == '1') {
                if (current_val > (2LL * n)) { // Optimization: if current_val is already too large, it won't match len
                    // This check is important. If current_val is already large, multiplying by 2
                    // and adding 1 might overflow long long if not careful, but more importantly,
                    // it will definitely be larger than any possible length N.
                    // Max N is 2e5. Max current_val can be 2^62.
                    // If current_val > N, it's impossible for current_val == len.
                    // We can break early.
                    break;
                }
                current_val = current_val * 2 + 1;
            } else { // s[j] == '0'
                if (current_val > (2LL * n)) { // Same optimization
                    break;
                }
                current_val = current_val * 2;
            }

            if (current_val == len) {
                good_substrings_count++;
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

