    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <algorithm>

int count_ones(const std::string& s) {
    int count = 0;
    for (char c : s) {
        if (c == '1') {
            count++;
        }
    }
    return count;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string a, b;
    std::cin >> a >> b;

    int ones_a = count_ones(a);
    int ones_b = count_ones(b);

    // If ones_a is odd, we can make it even by appending '1'.
    // If ones_a is even, we can make it odd by appending '1' (after appending '0' first, if needed).
    // The maximum number of '1's we can achieve in string 'a' is its current count + 1.
    // This is because we can always append parity. If parity is '0', count doesn't change.
    // If parity is '1', count increases by 1.
    // So, if we have an even number of '1's, we can append '0', then we still have an even number of '1's.
    // If we have an odd number of '1's, we can append '1', then we have an even number of '1's.
    // The maximum number of '1's we can effectively have is `ones_a` if `ones_a` is even,
    // or `ones_a + 1` if `ones_a` is odd.
    // This can be simplified to `ones_a + (ones_a % 2 == 0 ? 0 : 1)`.
    // Or even simpler, `ones_a` if `ones_a` is even, and `ones_a + 1` if `ones_a` is odd.
    // This is equivalent to `ones_a` if `ones_a` is even, and `ones_a` if `ones_a` is odd,
    // but we can always make it `ones_a + 1` if `ones_a` is odd.
    // The maximum number of '1's we can achieve is `ones_a` if `ones_a` is even,
    // and `ones_a + 1` if `ones_a` is odd.
    // This is `ones_a` if `ones_a % 2 == 0`, and `ones_a + 1` if `ones_a % 2 != 0`.
    // This can be written as `ones_a + (ones_a % 2)`.
    int max_ones_a_reachable = ones_a + (ones_a % 2);

    if (max_ones_a_reachable >= ones_b && a.length() <= b.length()) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9 and y can accumulate many such values.
// x can also go out of bounds quickly.

// Memoization table for results of (x, parity)
// dp[x][0] stores {final_y, final_x} if starting at x with parity 0 (add a_x)
// dp[x][1] stores {final_y, final_x} if starting at x with parity 1 (subtract a_x)
// The values stored are relative changes from the state (x, parity)
// dp[x][parity].first = change in y
// dp[x][parity].second = change in x
// A special value (e.g., -1 for change in y) can indicate non-termination.
std::vector<std::vector<std::pair<long long, long long>>> dp;
std::vector<std::vector<bool>> visited; // To detect cycles (non-termination)

// The actual array 'a' (0-indexed)
std::vector<long long> a_arr;
int N;

// Recursive function to calculate the outcome from a given state (current_x, current_parity)
// current_x is 1-indexed
// current_parity: 0 for adding a_x, 1 for subtracting a_x
std::pair<long long, long long> solve(long long current_x, int current_parity) {
    // Check termination conditions
    if (current_x <= 0 || current_x > N) {
        return {0, current_x}; // Base case: terminated, no further y change, x is the final x
    }

    // Check if already computed
    if (dp[current_x][current_parity].first != -2) { // -2 indicates not computed
        return dp[current_x][current_parity];
    }

    // Detect cycles (non-termination)
    if (visited[current_x][current_parity]) {
        return {-1, -1}; // Indicate non-termination
    }

    visited[current_x][current_parity] = true;

    long long val = a_arr[current_x - 1]; // Get a_x (0-indexed array)
    long long next_x;
    long long y_change_from_step = val;

    if (current_parity == 0) { // Step 2: x = x + val, y = y + val
        next_x = current_x + val;
        // Next step will be step 3 (parity 1)
        std::pair<long long, long long> res = solve(next_x, 1);

        visited[current_x][current_parity] = false; // Backtrack visited state

        if (res.first == -1) { // If next state leads to non-termination
            return dp[current_x][current_parity] = {-1, -1};
        } else {
            return dp[current_x][current_parity] = {y_change_from_step + res.first, res.second};
        }
    } else { // current_parity == 1 (Step 3: x = x - val, y = y + val)
        next_x = current_x - val;
        // Next step will be step 2 (parity 0)
        std::pair<long long, long long> res = solve(next_x, 0);

        visited[current_x][current_parity] = false; // Backtrack visited state

        if (res.first == -1) { // If next state leads to non-termination
            return dp[current_x][current_parity] = {-1, -1};
        } else {
            return dp[current_x][current_parity] = {y_change_from_step + res.first, res.second};
        }
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    a_arr.resize(N);
    // a_1 is set for each query, a_2 to a_N are given
    for (int i = 1; i < N; ++i) {
        std::cin >> a_arr[i];
    }

    // Initialize DP table. Size N+1 for 1-indexed x, and 2 for parity.
    // Use -2 as a sentinel value for uncomputed states.
    dp.resize(N + 1, std::vector<std::pair<long long, long long>>(2, {-2, -2}));
    visited.resize(N + 1, std::vector<bool>(2, false));

    for (int i = 1; i < N; ++i) {
        a_arr[0] = i; // Set a_1 for the current query

        // Reset DP table and visited states for each new a_1.
        // Only states reachable from (1,0) with current a_1 need to be cleared.
        // However, clearing the whole table is simpler and N is small enough.
        // A more optimized approach would be to only clear relevant entries,
        // but this requires tracking which entries were modified.
        // For N=2e5, clearing N*2 entries is 4e5 operations, which is fine.
        for(int j=1; j<=N; ++j) {
            dp[j][0] = {-2, -2};
            dp[j][1] = {-2, -2};
            visited[j][0] = false;
            visited[j][1] = false;
        }

        // Initial state: x=1, y=0. First operation is step 2 (add a_x).
        // So we call solve(1, 0)
        std::pair<long long, long long> result = solve(1, 0);

        if (result.first == -1) {
            std::cout << -1 << "\n";
        } else {
            std::cout << i + result.first << "\n"; // Initial y is 0, first a_x is a_1=i
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, std::numeric_limits<long long>::max());

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 2) {
            // For a type 2 query (l, r, m_i), we know that for all j in [l, r],
            // the current value a_j must be <= m_i.
            // The current value a_j is initial_a_j + sum_of_deltas_applied_to_j.
            // So, initial_a_j + sum_of_deltas_applied_to_j <= m_i.
            // This implies initial_a_j <= m_i - sum_of_deltas_applied_to_j.
            // We want to find the largest possible initial_a_j that satisfies all constraints.
            // So, initial_a_j <= min(m_i - sum_of_deltas_applied_to_j for all type 2 ops).
            // Here, b[j] stores this upper bound for initial_a_j.
            // We iterate through operations in reverse to calculate sum_of_deltas_applied_to_j.
            // However, the problem is simpler: we can just set b[j] = min(b[j], m_i) for j in [l, r]
            // and then later subtract the accumulated deltas.
            // This is because if we define initial_a_j = b[j] - accumulated_delta_j,
            // then b[j] is effectively the value a_j would have if no deltas were applied.
            // So, for a type 2 query (l, r, m_i), the value of a_j *before* any deltas
            // are applied to it *after* this query, must be <= m_i.
            // This means b[j] (which represents the value of a_j if no deltas were applied)
            // must be <= m_i.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], ops[i].val);
            }
        }
    }

    // Now, b[j] contains the maximum possible value for a_j if no deltas were applied.
    // We need to adjust b[j] by subtracting the deltas that would have been applied
    // to it *before* the type 2 query.
    // Let's define initial_a[j] = b[j].
    // Then, we simulate the operations to find the actual values.
    // For type 1 (l, r, d), we apply d to initial_a[j] for j in [l, r].
    // For type 2 (l, r, m_i), we check if max(initial_a[j]) == m_i.

    // The initial array elements are a_i.
    // Let's define a_i = b_i.
    // When a type 1 operation (l, r, d) occurs, it means a_j = a_j + d.
    // This means the initial value a_j must be such that after all operations,
    // the conditions are met.
    // The values b[j] we computed are the upper bounds for the *final* value of a_j
    // if no deltas were applied.
    // Let's define `initial_a[j]` as the value of `a_j` in the original array.
    // We want to find `initial_a[j]`.
    // For each `j`, `initial_a[j]` must be `b[j]` minus the sum of all `d` values
    // that would have been applied to `a_j` *before* any type 2 query that set `b[j]`.
    // This is complicated.

    // A simpler approach:
    // Let `initial_a[j]` be the value we are trying to find.
    // For each type 2 query `(l, r, m_i)`, we know that for all `k` in `[l, r]`,
    // `initial_a[k] + sum_of_deltas_applied_to_k_before_this_query <= m_i`.
    // This means `initial_a[k] <= m_i - sum_of_deltas_applied_to_k_before_this_query`.
    // To maximize `initial_a[k]`, we want to set `initial_a[k]` to the minimum of these upper bounds.
    // Let `current_deltas[j]` be the sum of `d` values applied to `a[j]` up to the current point.
    // When we process a type 2 query `(l, r, m_i)`:
    // For each `j` in `[l, r]`, we have `initial_a[j] + current_deltas[j] <= m_i`.
    // So, `initial_a[j] <= m_i - current_deltas[j]`.
    // We can initialize `initial_a[j]` to a very large value (e.g., 10^9).
    // Then, for each type 2 query, update `initial_a[j] = min(initial_a[j], m_i - current_deltas[j])`.
    // This requires `current_deltas[j]` to be known *at the time of the query*.
    // This means we need to iterate through operations in order.

    std::vector<long long> initial_a(n, std::numeric_limits<long long>::max());
    std::vector<long long> current_deltas(n, 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_deltas[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_deltas[j]);
            }
        }
    }

    // If initial_a[j] is still max_long_long, it means it was never constrained by a type 2 query.
    // We can set it to 0, as per problem statement |a_i| <= 10^9.
    // Or, more generally, any value within bounds. 0 is simplest.
    for (int j = 0; j < n; ++j) {
        if (initial_a[j] == std::numeric_limits<long long>::max()) {
            initial_a[j] = 0;
        }
    }

    // Now, verify the solution.
    // Re-simulate all operations with the constructed initial_a.
    std::vector<long long> a_current = initial_a;
    current_deltas.assign(n, 0); // Reset current_deltas for verification

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_deltas[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, initial_a[j] + current_deltas[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v, d, p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].id = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false; // Child i goes to the doctor

        long long current_v_cry = children[i].v;
        long long accumulated_d_cry = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_cry from previous children who left
            children[j].p -= accumulated_d_cry;

            // Apply current_v_cry from child i
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--; // Volume decreases for subsequent children
            }

            // Check if child j's confidence drops below zero
            if (children[j].p < 0) {
                if (children[j].in_line) { // Ensure we only process a child leaving once
                    children[j].in_line = false;
                    accumulated_d_cry += children[j].d;
                }
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_val = 0; // The previous element in the non-decreasing array
    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];

        // Case 1: a[i] can be kept as is (or incremented to be >= prev_val)
        // This means a[i] >= prev_val.
        // If a[i] < prev_val, then we must increment a[i].
        // The minimum value a[i] can take is a[i].
        // The maximum value a[i] can take is (a[i] + x) % m.
        // If a[i] >= prev_val, we can potentially keep it as a[i].
        // We need to check if (a[i] + x) % m is also >= prev_val.
        // If a[i] >= prev_val, we can just use a[i] as the current value.
        // The condition for this is that a[i] + x >= prev_val.
        // More precisely, if a[i] >= prev_val, we can set current_val = a[i].
        // This is valid if a[i] is reachable, i.e., 0 operations on a[i] is allowed.
        // This is always true if x >= 0.

        // Case 2: a[i] must be incremented.
        // This happens if a[i] < prev_val.
        // In this case, we must increment a[i] such that its new value is >= prev_val.
        // The smallest possible value for a[i] after incrementing is (a[i] + k) % m.
        // We need to find if there exists a k (0 <= k <= x) such that (a[i] + k) % m >= prev_val.
        // The values a[i] can take are in the range [a[i], (a[i]+x)%m] if a[i]+x < m,
        // or [a[i], m-1] U [0, (a[i]+x)%m] if a[i]+x >= m.

        // Let's simplify. We want to find a value `v` such that `prev_val <= v < m`
        // and `v` can be obtained from `a[i]` by adding `k` operations, where `0 <= k <= x`.
        // This means `v = (a[i] + k) % m`.

        // If a[i] >= prev_val:
        // We can potentially use a[i] itself. This requires 0 operations on a[i].
        // This is valid if 0 <= x.
        // So, if a[i] >= prev_val, we can set current_val = a[i].
        // This is the greedy choice to keep values as small as possible.
        // However, we must ensure that a[i] is reachable with at most x operations.
        // If a[i] >= prev_val, we can use a[i] as the current value.
        // This is always possible with 0 operations on a[i], which is <= x.
        // So, if a[i] >= prev_val, we set prev_val = a[i].

        // What if a[i] < prev_val?
        // We must increment a[i].
        // The value a[i] can become is (a[i] + k) % m for 0 <= k <= x.
        // We need to find if there is a k such that (a[i] + k) % m >= prev_val.
        // The smallest value a[i] can become that is >= prev_val is prev_val itself.
        // Can we make a[i] become prev_val?
        // This requires (a[i] + k) % m = prev_val.
        // If a[i] <= prev_val, then k = prev_val - a[i] is one option.
        // If this k <= x, then we can make a[i] become prev_val.
        // What if prev_val - a[i] > x?
        // Then we cannot reach prev_val by just adding.
        // We might need to wrap around.
        // The value we are trying to achieve is `v`.
        // `v` must be `prev_val <= v < m`.
        // `v` must be reachable from `a[i]` with `k <= x` operations.
        // This means `(a[i] + k) % m = v`.
        // The number of operations `k` to change `a[i]` to `v` is:
        // If `v >= a[i]`, then `k = v - a[i]`.
        // If `v < a[i]`, then `k = v - a[i] + m`.

        // Let's consider the two possible values for the current element:
        // 1. Keep it as `a[i]`. This is possible if `a[i] >= prev_val`.
        //    The cost for this is 0 operations on `a[i]`.
        // 2. Increment it to `a[i]'` such that `a[i]' >= prev_val`.
        //    The smallest such `a[i]'` is `prev_val`.
        //    The cost for this is `k = (prev_val - a[i] + m) % m`.
        //    This `k` must be `<= x`.

        // If `a[i] >= prev_val`:
        // We have two choices for the current element's value:
        //   a) `a[i]`: This requires 0 operations on `a[i]`. This is valid since `0 <= x`.
        //   b) `prev_val`: This requires `k = (prev_val - a[i] + m) % m` operations.
        //      If `prev_val <= a[i]`, then `k = prev_val - a[i]`.
        //      If `prev_val > a[i]`, then `k = prev_val - a[i] + m`.
        //      Wait, this is wrong. If `a[i] >= prev_val`, then `prev_val - a[i]` is negative or zero.
        //      The number of operations to change `a[i]` to `prev_val` is `(prev_val - a[i] + m) % m`.
        //      If `prev_val <= a[i]`, then `k = prev_val - a[i] + m` if `prev_val < a[i]`, or `0` if `prev_val == a[i]`.
        //      This is `(prev_val - a[i] + m) % m`.
        //      Example: a[i]=5, prev_val=3, m=7. k = (3-5+7)%7 = 5.
        //      Example: a[i]=5, prev_val=5, m=7. k = (5-5+7)%7 = 0.
        //      Example: a[i]=5, prev_val=6, m=7. k = (6-5+7)%7 = 1.
        //      This `k` must be `<= x`.

        // We want to keep `prev_val` as small as possible.
        // If `a[i] >= prev_val`:
        //   We can choose `a[i]` as the current value. This requires 0 operations on `a[i]`.
        //   This is always valid since `0 <= x`.
        //   So, we can set `prev_val = a[i]`.
        //   However, we could also choose to increment `a[i]` to `prev_val` if `prev_val` is reachable.
        //   The cost to change `a[i]` to `prev_val` is `k = (prev_val - a[i] + m) % m`.
        //   If `k <= x`, then we can choose `prev_val` as the current value.
        //   Since we want to keep `prev_val` as small as possible, if `k <= x`, we should choose `prev_val`.
        //   Otherwise, we must choose `a[i]`.
        //   So, if `a[i] >= prev_val`:
        //     If `(prev_val - a[i] + m) % m <= x`, then `prev_val` remains `prev_val`.
        //     Else (`(prev_val - a[i] + m) % m > x`), then `prev_val` becomes `a[i]`.
        // This logic is correct.

        // If `a[i] < prev_val`:
        //   We *must* increment `a[i]` to be at least `prev_val`.
        //   The smallest value `a[i]` can become that is `>= prev_val` is `prev_val` itself.
        //   The cost to change `a[i]` to `prev_val` is `k = (prev_val - a[i] + m) % m`.
        //   If `k <= x`, then we can make `a[i]` become `prev_val`. So `prev_val` remains `prev_val`.
        //   If `k > x`, then we cannot make `a[i]` become `prev_val` (or any value `>= prev_val` by wrapping around).
        //   In this case, it's impossible to satisfy the condition for this `x`.
        //   So, return `false`.

        // Combining these:
        // If `a[i] >= prev_val`:
        //   `diff = a[i] - prev_val`.
        //   If `diff` is small enough such that `a[i]` can be "wrapped around" to `prev_val`
        //   (i.e., `a[i]` becomes `prev_val` by adding `m - diff` operations, which is `(prev_val - a[i] + m) % m` operations),
        //   and this number of operations is `<= x`, then we can keep `prev_val` as `prev_val`.
        //   This happens if `(prev_val - a[i] + m) % m <= x`.
        //   Otherwise, we must use `a[i]` as the current value, so `prev_val = a[i]`.
        //   This is equivalent to: if `a[i] + x >= prev_val + m` (meaning `a[i]` can wrap around and still be >= `prev_val`),
        //   or if `a[i] + x < m` and `a[i] + x < prev_val` (meaning `a[i]` cannot reach `prev_val` even without wrap-around),
        //   then we must use `a[i]`.
        //   This is getting complicated. Let's use the `k` definition.

        // Let `k_to_prev = (prev_val - current_a + m) % m`. This is the minimum operations to make `current_a` equal to `prev_val`.
        // If `current_a >= prev_val`:
        //   We have two options for the new `prev_val`:
        //   1. Keep `prev_val` as `prev_val`. This requires `k_to_prev` operations on `current_a`.
        //      This is valid if `k_to_prev <= x`.
        //   2. Set `prev_val` to `current_a`. This requires 0 operations on `current_a`.
        //      This is always valid since `0 <= x`.
        //   We want to keep `prev_val` as small as possible. So if option 1 is valid, we take it.
        //   Otherwise, we take option 2.
        //   So, if `k_to_prev <= x`, `prev_val` remains `prev_val`.
        //   Else, `prev_val` becomes `current_a`.
        // Else (`current_a < prev_val`):
        //   We *must* increment `current_a` to be at least `prev_val`.
        //   The smallest value we can make it is `prev_val`. This requires `k_to_prev` operations.
        //   If `k_to_prev <= x`, then we can achieve `prev_val`. So `prev_val` remains `prev_val`.
        //   Else, it's impossible. Return `false`.

        // This logic seems sound and covers all cases.

        if (current_a >= prev_val) {
            // Option 1: Keep prev_val as prev_val. This means current_a becomes prev_val.
            // Operations needed: (prev_val - current_a + m) % m.
