        } else { // current_a < prev_val
            // We must increment current_a to be at least prev_val.
            // The smallest value it can become is prev_val.
            // Operations needed: (prev_val - current_a + m) % m.
            // If this is <= x, we can do it.
            if ((prev_val - current_a + m) % m <= x) {
                // prev_val remains prev_val
            } else {
