#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All tracks covered
            return true;
        }

        long long current_h = h[h_idx];

        // If current head can cover p[p_idx]
        if (std::abs(current_h - p[p_idx]) <= T) {
            // This head can cover p[p_idx] and potentially more tracks to its right.
            // The rightmost track this head can cover is current_h + T.
            long long cover_limit = current_h + T;

            // Advance p_idx past all tracks covered by this head.
            while (p_idx < m && p[p_idx] <= cover_limit) {
                p_idx++;
            }
        }
    }
    return p_idx == m; // True if all tracks are covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance is 10^10, so 2*10^10 is a safe upper bound for T.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

